-- Poems batch 278
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f2f8235a-f777-48a1-84d5-f90a2e7827eb','憶暢慶玉如四上人','仇遠','宋','宋诗','song-poetry','','[]','臘中晴色久，霜月冷森森。',48,'全唐诗/poet.song.246000.json','["臘中晴色久，霜月冷森森。", "可但思元度，惟應憶道林。", "三更難得曉，一片欲歸心。", "有約分苔石，南山蒼樹陰。"]'),
('c89f85f4-b0d8-4c9b-962b-92390f0f0100','曉霜','仇遠','宋','宋诗','song-poetry','','[]','重衾驚驟冷，萬瓦見濃霜。',48,'全唐诗/poet.song.246000.json','["重衾驚驟冷，萬瓦見濃霜。", "夾岸蒹葭白，空庭橘柚黄。", "宦情真淡泊，歲晚轉荒凉。", "野寺鐘聲早，何人僕馬忙。"]'),
('ae4c732f-0b92-4272-9145-24824fa8f282','中元','仇遠','宋','宋诗','song-poetry','','[]','初秋當望夜，平楚带斜曛。',48,'全唐诗/poet.song.246000.json','["初秋當望夜，平楚带斜曛。", "暑氣能昏月，砧聲不隔雲。", "華燈浮白水，老衲誦冥文。", "漫說中元節，儒書惜未聞。"]'),
('05b3f910-3555-467d-9dbe-74deb666c141','和子野四首  其一','仇遠','宋','宋诗','song-poetry','','[]','旅食無生計，卑棲奈若何。',48,'全唐诗/poet.song.246000.json','["旅食無生計，卑棲奈若何。", "飯惟供脫粟，衣未補香莎。", "戶外履常滿，床頭金不多。", "老爲文學掾，一似舊恩科。"]'),
('67d8b474-9e59-4aa4-8482-445a9e611440','和子野四首  其二','仇遠','宋','宋诗','song-poetry','','[]','窮冬霜霰集，行路古今難。',48,'全唐诗/poet.song.246000.json','["窮冬霜霰集，行路古今難。", "舉眼看浮世，何人耐歲寒。", "棄瓢將止酒，脫冕擬休官。", "一室能容膝，吾生亦易安。"]'),
('3600d3d4-16ea-4fd7-9840-7b4046206118','和子野四首  其三','仇遠','宋','宋诗','song-poetry','','[]','亨塗即畏塗，暮境欲何如。',48,'全唐诗/poet.song.246000.json','["亨塗即畏塗，暮境欲何如。", "索米多貧士，鈔詩欠小胥。", "自緣鄉夢熟，頓與世情疏。", "會約逃名者，山間倒跨馿。"]'),
('4c43204f-a487-4729-af73-bf4f851f80d1','和子野四首  其四','仇遠','宋','宋诗','song-poetry','','[]','詭遇非吾事，支離笑我身。',48,'全唐诗/poet.song.246000.json','["詭遇非吾事，支離笑我身。", "文章寧可拙，仕宦豈宜貧。", "鄉故多新鬼，年荒少佚民。", "休嗟華黍廢，陽谷易回春。"]'),
('36043e91-6328-416b-97bc-77db4dd3fcac','再疊  其一','仇遠','宋','宋诗','song-poetry','','[]','醉眠春一榻，不記夢伊何。',48,'全唐诗/poet.song.246000.json','["醉眠春一榻，不記夢伊何。", "落月明紅葉，寒廳暗綠莎。", "敝袍爲客久，高枕閲人多。", "未有匡時策，無心中甲科。"]'),
('67b42135-1299-448c-9903-bc5a6e22dd2b','再疊  其二','仇遠','宋','宋诗','song-poetry','','[]','世態年年改，窮居事事難。',48,'全唐诗/poet.song.246000.json','["世態年年改，窮居事事難。", "予懷雖浩蕩，此地本酸寒。", "古瀨浮貞女，空齋貯冷官。", "枯腸與藜莧，歲久頗相安。"]'),
('1d7ec16e-58d1-4823-83cc-74e65e3adf7c','再疊  其三','仇遠','宋','宋诗','song-poetry','','[]','老景存三樂，浮生付六如。',48,'全唐诗/poet.song.246000.json','["老景存三樂，浮生付六如。", "是非忘馬指，憎愛任烏胥。", "故里仍饑饉，清流例闊疏。", "有人風雪外，詩在斷橋馿。"]'),
('43b2c0cd-90a8-4fc6-951b-107dda898ee3','再疊  其四','仇遠','宋','宋诗','song-poetry','','[]','雪溪漁隠者，郊島是前身。',48,'全唐诗/poet.song.246000.json','["雪溪漁隠者，郊島是前身。", "乍見猶疑傲，相逢不說貧。", "鶴招窮處士，梅伴老詩人。", "時共論文酒，衰顔少借春。"]'),
('4f88c21f-74eb-424d-a46c-c3909a905485','三疊  其一','仇遠','宋','宋诗','song-poetry','','[]','禁酤限十日，亡何能幾何。',48,'全唐诗/poet.song.246000.json','["禁酤限十日，亡何能幾何。", "流光徒荏苒，老眼自挼莎。", "江浙歸心切，山林醒眼多。", "富家憂勸率，役後欲重科。"]'),
('81d07b93-fd33-4292-9ca1-80712b6e93f2','三疊  其二','仇遠','宋','宋诗','song-poetry','','[]','爲貧干寸祿，匏繫欲歸難。',48,'全唐诗/poet.song.246000.json','["爲貧干寸祿，匏繫欲歸難。", "雁字誰能寄，鷗盟久已寒。", "自憐秦博士，何似衛伶官。", "終覺家居樂，高眠一枕安。"]'),
('2a5409a6-d70a-4d87-8111-6027d3a2c1a9','三疊  其三','仇遠','宋','宋诗','song-poetry','','[]','在昔金淵地，煙花錦不如。',48,'全唐诗/poet.song.246000.json','["在昔金淵地，煙花錦不如。", "衣冠尊史祖，山水識靈胥。", "富歲人多頼，前修日以疏。", "洪崖仙可問，願乞雪精馿。"]'),
('93f94624-9894-464a-9c1b-88a30d47f451','三疊  其四','仇遠','宋','宋诗','song-poetry','','[]','飽喫芹宮飯，饑寒未迫身。',48,'全唐诗/poet.song.246000.json','["飽喫芹宮飯，饑寒未迫身。", "公侯方重老，妻子莫憂貧。", "蹤跡新豐客，心期畫邑人。", "皇荂歌一曲，聊以和陽春。"]'),
('6e2608cb-3ed2-44c7-bdb4-8b655e7b0c53','黄渚舟中  其一','仇遠','宋','宋诗','song-poetry','','[]','夕晴殊可喜，小作川原遊。',48,'全唐诗/poet.song.246000.json','["夕晴殊可喜，小作川原遊。", "水岸菰蔣合，野田鴻雁留。", "雲煙易得晚，城市那知秋。", "落葉塞破屋，逃亡令我愁。"]'),
('426fae3f-5f5e-425f-8ad7-e01918b02dee','黄渚舟中  其二','仇遠','宋','宋诗','song-poetry','','[]','酌彼溪店酒，醉向舟中眠。',48,'全唐诗/poet.song.246000.json','["酌彼溪店酒，醉向舟中眠。", "舟人待月出，急急乘晚牽。", "前山見瓦屋，小彴橫沙田。", "回首六百載，我思唐謫仙。"]'),
('954a2682-10ce-48d2-9de7-385c26abeecb','棕莊','仇遠','宋','宋诗','song-poetry','','[]','幽徑秋陰合，青渠草色深。',48,'全唐诗/poet.song.246000.json','["幽徑秋陰合，青渠草色深。", "肯教木葉落，直見夕陽沉。", "獨客逢來雁，新寒集遠砧。", "芙蓉花似錦，有意媚高林。"]'),
('0ae83437-7111-4338-b76c-9289d4d7e0e4','寄鄂渚王子文教授','仇遠','宋','宋诗','song-poetry','','[]','笑把青藜杖，遠遊黄鶴城。',48,'全唐诗/poet.song.246000.json','["笑把青藜杖，遠遊黄鶴城。", "雨消戰伐氣，春生絃誦聲。", "相從未有約，久別難爲情。", "東望思渺渺，江長秋月明。"]'),
('fbdfeb07-adc1-48f0-89ca-3b28c70eff67','送楊剛中赴淮安教授','仇遠','宋','宋诗','song-poetry','','[]','西蜀楊君子，才爲博士優。',48,'全唐诗/poet.song.246000.json','["西蜀楊君子，才爲博士優。", "儒官清似水，學舍小於舟。", "吳地仍多潦，淮田薄有收。", "雖非溫飽計，足解友朋憂。"]'),
('e8aa489d-e6cc-4aa0-837f-35ef93ce593d','風起','仇遠','宋','宋诗','song-poetry','','[]','朔風連夕起，浩蕩厲嚴寒。',48,'全唐诗/poet.song.246000.json','["朔風連夕起，浩蕩厲嚴寒。", "遠勢驚春夢，微權屬冷官。", "雲行和月暗，木落打窗乾。", "因憶吳船客，波濤寢不安。"]'),
('5555fc7f-b232-49c7-9c57-ff966fd5efb4','廣教寺','仇遠','宋','宋诗','song-poetry','','[]','三門當驛道，四壁啟僧房。',48,'全唐诗/poet.song.246000.json','["三門當驛道，四壁啟僧房。", "頗有千竿竹，能令六月凉。", "撞鐘山鸛起，煮茗石罌香。", "岸曲盤渦急，人言古瀨陽。"]'),
('caa9f8be-206a-4de4-a0ee-2aa751694a41','次彥功韻','仇遠','宋','宋诗','song-poetry','','[]','春早風驅雪，天寒竹映門。',48,'全唐诗/poet.song.246000.json','["春早風驅雪，天寒竹映門。", "燈前終夜讀，笈內故書存。", "尚覺文章貴，那矜齒爵尊。", "向平愁未了，女嫁與兒昏。"]'),
('763cb949-133f-4886-af68-7abb2c0d3fa4','雨止','仇遠','宋','宋诗','song-poetry','','[]','夜半雨忽止，老夫心頓寬。',48,'全唐诗/poet.song.246000.json','["夜半雨忽止，老夫心頓寬。", "最憐兒女弱，難受雪霜寒。", "澤國無來棹，臺城有去鞍。", "西村歸未卜，此日敢求安。"]'),
('d4b45eec-35b0-4dd8-9656-9277abce65fa','薄遊','仇遠','宋','宋诗','song-poetry','','[]','未草閒居賦，聊從薄宦遊。',48,'全唐诗/poet.song.246000.json','["未草閒居賦，聊從薄宦遊。", "江湖明老眼，風雨暗孤舟。", "客况何曾好，吾生本自浮。", "終然愧農圃，將有事西疇。"]'),
('5449f96c-95b9-4a2c-a8e5-6c85fa93227b','形影','仇遠','宋','宋诗','song-poetry','','[]','形影自相問，追隨六十年。',48,'全唐诗/poet.song.246000.json','["形影自相問，追隨六十年。", "冷官真漫爾，歸夢亦蘧然。", "但覺寒風暖，難令素髪玄。", "可能學陶令，家去有園田。"]'),
('e59f189f-e8a2-4079-8af2-e9f5ac2ee7fd','曉出西城','仇遠','宋','宋诗','song-poetry','','[]','閒官閒不盡，曉出古城陰。',48,'全唐诗/poet.song.246000.json','["閒官閒不盡，曉出古城陰。", "斗柄已插地，秋聲將滿林。", "故園三畝宅，落月幾家砧。", "爲報柴桑令，予今亦委心。"]'),
('ad1a0417-9d13-4d8b-879d-4cecc44f754a','三更汎舟謝達剨  其一','仇遠','宋','宋诗','song-poetry','','[]','渰水不盈尺，大舟行水中。',48,'全唐诗/poet.song.246000.json','["渰水不盈尺，大舟行水中。", "朦朧微有月，瀲灧寂無風。", "時序三秋半，陰晴萬里同。", "山歌與村笛，醉卧聽漁童。"]'),
('fe525f2d-e48e-434a-a1e9-f7ea30f64d3e','三更汎舟謝達剨  其二','仇遠','宋','宋诗','song-poetry','','[]','一望四十里，瀰漫白浸天。',48,'全唐诗/poet.song.246000.json','["一望四十里，瀰漫白浸天。", "何年圍此水，爲我墾成田。", "風使帆船疾，雲和竹葦連。", "末流溪轉狹，浮沫带蛟涎。"]'),
('356c38dd-c4da-4cc5-bb44-194f33d6b339','代步','仇遠','宋','宋诗','song-poetry','','[]','羸驂聊代步，按轡且徐行。',48,'全唐诗/poet.song.246000.json','["羸驂聊代步，按轡且徐行。", "凹凸驚前路，驅馳羨後生。", "曉回天尚闇，路滑雨初晴。", "得似肩輿穩，歸來醉不驚。"]'),
('b98ea469-ef62-4365-b826-29a4685ee8a2','舍北野步','仇遠','宋','宋诗','song-poetry','','[]','野步上西門，寬平又一村。',48,'全唐诗/poet.song.246000.json','["野步上西門，寬平又一村。", "疏籬圍古井，密樹擁高墳。", "家有田園樂，氓知守令尊。", "因思興廢事，變滅似秋雲。"]'),
('67d60778-71a0-4e9e-8a7a-4c5a898f8641','次蕭饒州韻  其一','仇遠','宋','宋诗','song-poetry','','[]','愛山如愛士，交友竟忘年。',48,'全唐诗/poet.song.246000.json','["愛山如愛士，交友竟忘年。", "未老先辭祿，能閒始是仙。", "清談真藥石，雅志樂林泉。", "笑看衡門外，隨風柳絮顛。"]'),
('30253fcd-72f0-4aaa-89a7-d72c0f7bafbe','次蕭饒州韻  其二','仇遠','宋','宋诗','song-poetry','','[]','謙謙賢太守，止止樂閒居。',48,'全唐诗/poet.song.246000.json','["謙謙賢太守，止止樂閒居。", "健筆凌三謝，高風繼二疏。", "家猶傳故笏，夢不到安車。", "何處溪山好，相從結草廬。"]'),
('9f5e0a7d-0fea-47ef-a846-850e8317dd62','次蕭饒州韻  其三','仇遠','宋','宋诗','song-poetry','','[]','寓舍已三遷，閑官又一年。',48,'全唐诗/poet.song.246000.json','["寓舍已三遷，閑官又一年。", "酒杯時樂聖，茶椀欲通仙。", "愛笋從穿壁，澆花自汲泉。", "誰能問前代，劉蹶與秦顛。"]'),
('b2fe91f0-7201-416d-9642-6ba24bfd252a','次蕭饒州韻  其四','仇遠','宋','宋诗','song-poetry','','[]','數椽西郭外，元不異村居。',48,'全唐诗/poet.song.246000.json','["數椽西郭外，元不異村居。", "官冷謀升斗，頭童怯比疏。", "莫愁書費紙，肯嘆出無車。", "也勝焦徵士，蝸牛卧雪廬。"]'),
('5847e9c0-8df3-4616-85bf-c85a67256644','同室','仇遠','宋','宋诗','song-poetry','','[]','同室過百指，一官寖四年。',48,'全唐诗/poet.song.246000.json','["同室過百指，一官寖四年。", "幸無乞米帖，何取買山錢。", "止酒陶元亮，思歸孟浩然。", "乾魚兼菜把，頗勝酌貪泉。"]'),
('b06600d6-9418-44b7-9f22-e38bba9a23a2','朋酒','仇遠','宋','宋诗','song-poetry','','[]','朋酒朝朝樂，鄉心夜夜愁。',48,'全唐诗/poet.song.246000.json','["朋酒朝朝樂，鄉心夜夜愁。", "朱雲難作吏，宋玉易悲秋。", "陵谷何曾改，田園未可求。", "南來幾鴻雁，亦爲稻粱謀。"]'),
('cf377372-2af6-4f0a-a8d4-11e21b16beef','之金陵','仇遠','宋','宋诗','song-poetry','','[]','文學本閒官，長年愧素餐。',48,'全唐诗/poet.song.246000.json','["文學本閒官，長年愧素餐。", "出門還自笑，行路有何難。", "風日幽懷暢，江山望眼寬。", "六朝遺迹在，隨喜一遊觀。"]'),
('9507b7d6-3f8f-4361-a9bf-00f3a4ee225c','方萬里史敬輿陳孝先龔聖予胡穆仲相繼淪沒令人感愴','仇遠','宋','宋诗','song-poetry','','[]','諸老俱塵土，令予雙淚流。',48,'全唐诗/poet.song.246000.json','["諸老俱塵土，令予雙淚流。", "幾年能再見，一氣故應休。", "江左衣冠盡，人間翰墨留。", "空山茅屋底，野史屬誰修。"]'),
('de5e5bc0-fa30-4afb-8062-9d22810cf883','寄陳南翔張伯成主賓','仇遠','宋','宋诗','song-poetry','','[]','山水未遊徧，其如歸夢何。',48,'全唐诗/poet.song.246000.json','["山水未遊徧，其如歸夢何。", "獨憐黄渚月，相隔白漚波。", "秋盡那無雁，霜遲尚有荷。", "終期共燈火，插架異書多。"]'),
('af709246-fcbb-4098-b1ac-7fda100ba7bf','遣意  其一','仇遠','宋','宋诗','song-poetry','','[]','衮衮歲年晚，冥冥車馬塵。',48,'全唐诗/poet.song.246000.json','["衮衮歲年晚，冥冥車馬塵。", "饑烏方畏雪，凍草已矜春。", "鄉老知誰健，儒官自古貧。", "明朝除夜近，市井悄無人。"]'),
('c445ec9e-4892-4022-9a49-307af5db1f44','遣意  其二','仇遠','宋','宋诗','song-poetry','','[]','抖擻老精神，飄蓬又一春。',48,'全唐诗/poet.song.246000.json','["抖擻老精神，飄蓬又一春。", "敢言惟有我，每恨不如人。", "文字須稱韻，功名莫認真。", "青銅杖頭在，留與買烏薪。"]'),
('cfe6e9fc-9fa1-4bb7-b964-71fbd1b94b8d','遣意  其三','仇遠','宋','宋诗','song-poetry','','[]','宦遊今倦矣，歲晚意何如。',48,'全唐诗/poet.song.246000.json','["宦遊今倦矣，歲晚意何如。", "臘雪不到地，春風先滿閭。", "鄰翁寒乞炭，溪女曉供魚。", "多有梅花處，吾將卜隠居。"]'),
('0159db83-719a-42b8-a24e-9a6741b167ae','利交','仇遠','宋','宋诗','song-poetry','','[]','一自儀秦去，從衡直到今。',48,'全唐诗/poet.song.246000.json','["一自儀秦去，從衡直到今。", "士緣貧失節，交以利知心。", "乍可昏求火，何堪晝見金。", "狂瀾回已倒，猶幸有山林。"]'),
('286d0498-1a9e-4f81-b447-50601a733e34','聞雞','仇遠','宋','宋诗','song-poetry','','[]','今夕知何夕，此聲非惡聲。',48,'全唐诗/poet.song.246000.json','["今夕知何夕，此聲非惡聲。", "窗前疑月色，枕上誤天明。", "未必皆三唱，惟應只四更。", "姑蘇城外寺，此際已鐘鳴。"]'),
('a142264c-f053-4ab8-95ea-3693d78169e5','題水軒','仇遠','宋','宋诗','song-poetry','','[]','水軒寒最早，偏稱冷官居。',48,'全唐诗/poet.song.246000.json','["水軒寒最早，偏稱冷官居。", "老態重衾薄，秋聲四壁虛。", "霜前蛩漸少，雨後葉全疏。", "漁叟頑如鐵，鶉衣曉捕魚。"]'),
('3cb07798-3a08-4828-9f4d-8f749d15190d','有感','仇遠','宋','宋诗','song-poetry','','[]','腐儒乖世用，作事例迂疏。',48,'全唐诗/poet.song.246000.json','["腐儒乖世用，作事例迂疏。", "浪走長安道，欲投光範書。", "懸知成漫爾，可笑賦歸與。", "寄語陳言者，毋輕出草廬。"]'),
('9759bea8-12cb-4e08-940b-d67225bb3707','潦雨排悶二首  其一','仇遠','宋','宋诗','song-poetry','','[]','淫雨喧中夜，羈人積隠憂。',48,'全唐诗/poet.song.246000.json','["淫雨喧中夜，羈人積隠憂。", "葵傾那有日，麥腐欲無秋。", "小市渾如洗，前溪漫不流。", "林鳩兼垤鸛，聒聒幾時休。"]'),
('57497e7e-4192-4fd2-a075-53035d600347','潦雨排悶二首  其二','仇遠','宋','宋诗','song-poetry','','[]','宿雨漲溪流，江南四月秋。',48,'全唐诗/poet.song.246000.json','["宿雨漲溪流，江南四月秋。", "市無糧得糶，田有麥難收。", "官况全然冷，民饑絕可憂。", "沙鷗應笑我，何日放歸舟。"]'),
('47716640-5b6c-448e-9478-931478d1ccaa','跨馬','仇遠','宋','宋诗','song-poetry','','[]','跨馬入城去，驅鷄上屋飛。',48,'全唐诗/poet.song.246000.json','["跨馬入城去，驅鷄上屋飛。", "閒官差可樂，徒步未爲非。", "杜老平明出，山公倒載歸。", "晚汀沙水闊，野鶩得相依。"]'),
('5ed19cb1-1859-4a72-b4f5-f01fa4f62ae5','醉歌三首  其一','仇遠','宋','宋诗','song-poetry','','[]','金淵醇酒賤，足可醉亡何。',48,'全唐诗/poet.song.246000.json','["金淵醇酒賤，足可醉亡何。", "日覺醒時少，其如飲不多。", "人生間調笑，俗事暗消磨。", "此意神仙會，山童亦解歌。"]'),
('99348f46-dcef-460b-9922-2b73ce7c878c','醉歌三首  其二','仇遠','宋','宋诗','song-poetry','','[]','客居真易過，凡事不如儀。',48,'全唐诗/poet.song.246000.json','["客居真易過，凡事不如儀。", "惟有閒尋睡，渾無趣作詩。", "晚晴行數步，日午酌三巵。", "繫馬庭階下，人多借去騎。"]'),
('5ac91cfd-5d96-4c02-a69c-74e0a0c6035d','醉歌三首  其三','仇遠','宋','宋诗','song-poetry','','[]','清狂歌窈窕，微醉困瞢騰。',48,'全唐诗/poet.song.246000.json','["清狂歌窈窕，微醉困瞢騰。", "酒薄多疑水，官閒一似僧。", "已知燈即火，不願谷爲陵。", "百事俱能了，惟餘飲未能。"]'),
('c0727e2f-1106-4f0f-8db3-64bd9f9011c1','自愛','仇遠','宋','宋诗','song-poetry','','[]','金淵豈愛我，我自愛金淵。',48,'全唐诗/poet.song.246000.json','["金淵豈愛我，我自愛金淵。", "似蜜醪尤美，如珠米更圓。", "携家踰八口，竊祿又三年。", "書冊盈歸篋，毋嫌載月船。"]'),
('63a806ad-d514-4dea-ba86-b11809f7cdc0','和友人韻','仇遠','宋','宋诗','song-poetry','','[]','山林空入夢，詩酒未忘懷。',48,'全唐诗/poet.song.246000.json','["山林空入夢，詩酒未忘懷。", "老興自不淺，卿言亦大佳。", "封侯無骨相，學道有心齋。", "安樂行窩在，棲棲且避乖。"]'),
('ede89443-a6c3-4ddd-9dc1-3e18c2712f13','呈王達之御史','仇遠','宋','宋诗','song-poetry','','[]','西晉文章伯，南臺法令師。',48,'全唐诗/poet.song.246000.json','["西晉文章伯，南臺法令師。", "常因行部日，記得從遊時。", "敏手除三害，貞心畏四知。", "何由侍王導，揮麈話襟期。"]'),
('e4baf5ee-a4b0-483d-9ce7-6bd7bd9dbd54','贈別葉子啟郭祥卿','仇遠','宋','宋诗','song-poetry','','[]','萍水偶相逢，金淵客路中。',48,'全唐诗/poet.song.246000.json','["萍水偶相逢，金淵客路中。", "帆船明日發，尊酒幾時同。", "窮達無先後，交遊貴始終。", "湖堤梅柳外，有約艤疏篷。"]'),
('868ed453-c1ce-4b9c-ab47-c10e1fd316cc','敝車','仇遠','宋','宋诗','song-poetry','','[]','汝自騎高馬，予寧坐敝車。',48,'全唐诗/poet.song.246000.json','["汝自騎高馬，予寧坐敝車。", "功名輸俊茂，天地著迂疏。", "漫說癡人夢，仍看後世書。", "謫仙酒樓在，不醉欲何如。"]'),
('5d9d9823-a5c7-4f37-abd4-474af080bd75','張氏隠居','仇遠','宋','宋诗','song-poetry','','[]','杜老曾題品，依稀舊隠居。',48,'全唐诗/poet.song.246000.json','["杜老曾題品，依稀舊隠居。", "頗知書有味，肯教子爲儒。", "築屋先通燕，開池剩養魚。", "相邀須飲醉，酒熟不煩沽。"]'),
('20054db4-a865-4d89-b18d-677e41c26828','過鄭氏幽居','仇遠','宋','宋诗','song-poetry','','[]','趁雨過雲關，東風尚峭寒。',48,'全唐诗/poet.song.246000.json','["趁雨過雲關，東風尚峭寒。", "野花渾未放，石路卒難乾。", "薄酒無多酌，窮途信少歡。", "歸來借蓑笠，莫作老坡看。"]'),
('00cfb4f3-3aea-468a-897e-be00bd8c0866','懷方嚴州  其一','仇遠','宋','宋诗','song-poetry','','[]','八十一年前，科名已褎然。',48,'全唐诗/poet.song.246000.json','["八十一年前，科名已褎然。", "依劉王粲檄，入洛賀循船。", "受禪碑誰上，閒情賦自傳。", "江山英氣歇，堪恨亦堪憐。"]'),
('1bef3377-6925-44c2-8ca9-af751bdfb014','懷方嚴州  其二','仇遠','宋','宋诗','song-poetry','','[]','八十一年終，堪嗟旅襯窮。',48,'全唐诗/poet.song.246000.json','["八十一年終，堪嗟旅襯窮。", "胸中元耿耿，身外竟空空。", "白首太玄草，紫陽虛谷翁。", "平生有遺恨，五馬未乘驄。"]'),
('80839092-58ff-45d1-a73c-1f134c2df9d5','懷方嚴州  其三','仇遠','宋','宋诗','song-poetry','','[]','八十一年亡，哀哉老紫陽。',48,'全唐诗/poet.song.246000.json','["八十一年亡，哀哉老紫陽。", "佳兒方戒道，小妾漫專房。", "每憶先生被，常懷太守章。", "桐江詩萬首，端可及龜堂。"]'),
('578830ce-c5a4-490c-9989-a9a1aea8287f','懷方嚴州  其四','仇遠','宋','宋诗','song-poetry','','[]','八十一年身，棲遲客館貧。',48,'全唐诗/poet.song.246000.json','["八十一年身，棲遲客館貧。", "登門曾有我，銘墓竟何人。", "醉夢高樓月，悲歌故國春。", "可能函玉骨，歸葬練溪濱。"]'),
('92cacf84-761f-4b95-95ee-bc8017099973','懷方嚴州  其五','仇遠','宋','宋诗','song-poetry','','[]','八十一年休，云何不首丘。',48,'全唐诗/poet.song.246000.json','["八十一年休，云何不首丘。", "豈無商女恨，肯作賈胡留。", "書籍從人賣，田園有子收。", "烏聊山在望，風雪去悠悠。"]'),
('bda05502-4ddf-4705-920b-b9d76cc47a2c','懷張似之','仇遠','宋','宋诗','song-poetry','','[]','少日登山屐，中年上水船。',48,'全唐诗/poet.song.246000.json','["少日登山屐，中年上水船。", "黄花猶自綠，白髪若爲玄。", "但覺杯行速，那知帽影偏。", "南峰深秀處，回首重潸然。"]'),
('591381fb-203b-4018-839d-a9ddedbfce71','釣鰲亭','仇遠','宋','宋诗','song-poetry','','[]','俯瞰秦淮水，前瞻魯泮宮。',48,'全唐诗/poet.song.246000.json','["俯瞰秦淮水，前瞻魯泮宮。", "明知倚闌者，不是釣魚翁。", "古石稜稜長，春潮脈脈通。", "狀元真宰相，千古一吳公。"]'),
('3a901b78-5250-47bb-a66f-7537f3711772','除夜新居  其一','仇遠','宋','宋诗','song-poetry','','[]','避喧遷出郭，歲晚尚擔簦。',48,'全唐诗/poet.song.246000.json','["避喧遷出郭，歲晚尚擔簦。", "陋室大於斗，長途滑似冰。", "豈無問字酒，共守讀書燈。", "老病須微祿，歸田恨未能。"]'),
('b47537bc-068f-4657-9aad-76a1434203fb','除夜新居  其二','仇遠','宋','宋诗','song-poetry','','[]','籸盆夾道明，爆竹小兒驚。',48,'全唐诗/poet.song.246000.json','["籸盆夾道明，爆竹小兒驚。", "但聽窗前雪，不知樓上更。", "流年雙羽急，深夜一鷄鳴。", "淺醉和衣睡，明朝要賀正。"]'),
('6b63eda2-f317-4036-a16b-2f30de22b24d','除夜新居  其三','仇遠','宋','宋诗','song-poetry','','[]','茅簷盈尺雪，真是冷官居。',48,'全唐诗/poet.song.246000.json','["茅簷盈尺雪，真是冷官居。", "窮巷稀人跡，今朝是歲除。", "聒廳無鼓吹，消夜足琴書。", "曉凍冰橋滑，鄰家借板輿。"]'),
('6e539f62-e34b-4250-93e5-ab6d1734a562','元夕放夜','仇遠','宋','宋诗','song-poetry','','[]','繡衣玉節駐江城，放得元宵兩夜晴。',64,'全唐诗/poet.song.246000.json','["繡衣玉節駐江城，放得元宵兩夜晴。", "陸地金蓮方灧灧，一天明月故盈盈。", "邏兵酣卧忘鐘韻，遊子歡呼趁鼓聲。", "兒女看燈歸較晚，老夫自剔讀書檠。"]'),
('9ea47643-14ff-458e-b3d0-4b930871259d','憶西坡梅','仇遠','宋','宋诗','song-poetry','','[]','杖藜久不到西坡，苔上梅花積漸多。',64,'全唐诗/poet.song.246000.json','["杖藜久不到西坡，苔上梅花積漸多。", "野屋荒凉誰管領，酒尊期會竟蹉跎。", "韶光二月已强半，樂事一生能幾何。", "頼有鄰園春可折，洗瓶斜插在行窩。"]'),
('413257b9-861e-47c3-8019-b1ed8995a498','三月二十六日書所聞','仇遠','宋','宋诗','song-poetry','','[]','從來賽社說金淵，鼓笛鉦旗隘市廛。',64,'全唐诗/poet.song.246000.json','["從來賽社說金淵，鼓笛鉦旗隘市廛。", "地上鬼神行白晝，夜中風雨洗青天。", "妖氛旱魃驅無跡，和氣歡聲兆有年。", "車馬縱觀兒女事，老夫閉戶讀韋編。"]'),
('77e0b3ad-f1f1-426c-8b7d-df4dbb569eed','寄陳仲麟','仇遠','宋','宋诗','song-poetry','','[]','檇李城邊送客船，梅花一別又三年。',64,'全唐诗/poet.song.246000.json','["檇李城邊送客船，梅花一別又三年。", "清風朗月思元度，駿馬名姬羨謫仙。", "湖海倦遊予白髪，園林真樂子青氈。", "楚生卜宅平生志，歸日相從學力田。"]'),
('c317d0a4-1cb5-4a17-8e5e-8a75cb6dbfc4','予自存博解印歸鄉心日夜相趣古人有名山川處輒忘歸然歸未易忘也夢得一聯續之','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','業風宦海足波瀾，常憶西湖南北山。',64,'全唐诗/poet.song.246000.json','["業風宦海足波瀾，常憶西湖南北山。", "熟處肯忘生處樂，別時雖易見時難。", "奉親還舍君先得，投檄歸田我未閒。", "漫說桃源人迹絕，故園松菊半荒殘。"]'),
('45b843c5-a800-4b98-ab2d-5acc65bd8618','送張叔夏游金陵','仇遠','宋','宋诗','song-poetry','','[]','肯向金淵暫泊舟，相逢衮衮別方休。',64,'全唐诗/poet.song.246000.json','["肯向金淵暫泊舟，相逢衮衮別方休。", "移宮換羽周郎顧，詠月吟風太白遊。", "床上無金猶好客，尊中有酒可消愁。", "明朝又作臺城客，細看青山似洛州。"]'),
('c27c5d16-db0b-4336-b6d3-2a5993344c2b','送陳壯甫稅使歸金陵','仇遠','宋','宋诗','song-poetry','','[]','征商廉幹不言錢，異事同寮又一年。',64,'全唐诗/poet.song.246000.json','["征商廉幹不言錢，異事同寮又一年。", "美譽正香金瀨曲，歸心已在冶城邊。", "家傳簪笏青溪譜，風送旌旗上水船。", "小草相依行有日，莫須摻別重凄然。"]'),
('48d15294-a1a8-498f-a2e8-ad67c2936783','蕭饒州見寄次韻','仇遠','宋','宋诗','song-poetry','','[]','夜來聽雨夢仇溪，夢覺招邀客賦詩。',64,'全唐诗/poet.song.246000.json','["夜來聽雨夢仇溪，夢覺招邀客賦詩。", "我自不分官冷熱，子須能別酒淳漓。", "江頭風順鱸魚到，天外春歸杜宇知。", "十日菊花元不減，恰如六月見蒲葵。"]'),
('f3cbf752-582f-4efe-a801-d2b103df74c3','喜晴','仇遠','宋','宋诗','song-poetry','','[]','新歲連朝喜遇晴，宜人宜穀最關情。',64,'全唐诗/poet.song.246000.json','["新歲連朝喜遇晴，宜人宜穀最關情。", "郊原尚覺春光薄，市井先傳米價平。", "趁暖飛蟲生滅易，向陽征雁去留輕。", "北門冷掾無公事，閒看官梅野柳爭。"]'),
('559c9805-5b5d-40a4-9644-89408d9f65b2','題趙千里溪山春遊圖','仇遠','宋','宋诗','song-poetry','','[]','一溪流水數家村，短櫟長松映蓽門。',64,'全唐诗/poet.song.246000.json','["一溪流水數家村，短櫟長松映蓽門。", "不是花通輞川口，祇疑路隔武陵源。", "小橋瘦馬行春色，遠浦青山带雨痕。", "樓觀玲瓏雲縹緲，須知畫裏別乾坤。"]'),
('567f92d4-c861-40a3-bcde-3794a54a7ca7','寄武康王居正','仇遠','宋','宋诗','song-poetry','','[]','曾向清溪采白蘋，江東日暮別經春。',64,'全唐诗/poet.song.246000.json','["曾向清溪采白蘋，江東日暮別經春。", "投金瀨上思歸客，浮玉山前憶故人。", "千里雲萍應念我，一庭風樹敢忘親。", "挂蓑石暖苔衣厚，擬買漁舠作近鄰。"]'),
('891a6dce-c560-4942-ae77-028441f8cebd','寄梁中砥','仇遠','宋','宋诗','song-poetry','','[]','句曲峰巒翠倚天，琳宮瓊館宴神仙。',64,'全唐诗/poet.song.246000.json','["句曲峰巒翠倚天，琳宮瓊館宴神仙。", "水程纔隔一百里，脚債未償三十年。", "幾擬看山携酒去，相期聽雨對床眠。", "何當撥遣塵間事，一試松根喜客泉。"]'),
('27b51712-f555-4c03-95c4-5f2fbb4ad8da','寄子野','仇遠','宋','宋诗','song-poetry','','[]','西窗隠几讀南華，頗悟亡羊與戰蝸。',64,'全唐诗/poet.song.246000.json','["西窗隠几讀南華，頗悟亡羊與戰蝸。", "住久不知身是客，歸休誰謂女無家。", "向陽野竹先抽筍，待雪官梅欲試花。", "我愛睡鄉真樂地，底須頻喫玉川茶。"]'),
('643de3e7-07f1-440e-bb40-fd6dbea7aa57','黑兔','仇遠','宋','宋诗','song-poetry','','[]','何年偷舐玄霜鼎，變却蟾宮玉雪姿。',64,'全唐诗/poet.song.246000.json','["何年偷舐玄霜鼎，變却蟾宮玉雪姿。", "毛穎未封先試墨，褐衣乍著便披緇。", "移來暘谷烏相對，躍入陰山鬼不知。", "蹤跡分明予甚愛，正當秋曉月明時。"]'),
('eaaa0dff-dd08-46d2-8917-681fd7f63b65','和劉君佐韻寄董靜傳高士','仇遠','宋','宋诗','song-poetry','','[]','雪暗江湖入暮年，何人葦外小延緣。',64,'全唐诗/poet.song.246000.json','["雪暗江湖入暮年，何人葦外小延緣。", "水痕不動玉平岸，春意欲回花滿天。", "懶出恐消桐屐蠟，醉吟忘上苧袍船。", "行當歸學林和靖，結屋梅根伴鶴眠。"]'),
('18fe9bbc-a3a5-45e8-87e6-da15251a4eee','驚蟄日雷','仇遠','宋','宋诗','song-poetry','','[]','坤宮半夜一聲雷，蟄戶花房曉已開。',64,'全唐诗/poet.song.246000.json','["坤宮半夜一聲雷，蟄戶花房曉已開。", "野闊風高吹燭滅，電明雨急打窗來。", "頓然草木精神別，自是寒暄氣候催。", "惟有石龜并木雁，守株不動任春回。"]'),
('d71d7e93-b8b6-42af-8c53-9da874dbac18','雁去','仇遠','宋','宋诗','song-poetry','','[]','離羣野雁在中庭，馴養經年羽翼成。',64,'全唐诗/poet.song.246000.json','["離羣野雁在中庭，馴養經年羽翼成。", "因爲哀鳴殊可念，豈知飛去太無情。", "天陰月黑多機穽，歲晚山空少弟兄。", "願爾水田常飽煖，春風早問北歸程。"]'),
('b274f98b-6396-42a9-a021-309d2e3e448a','寄屠存博','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三年塵土白鬚眉，擬向西湖濯客衣。',64,'全唐诗/poet.song.246000.json','["三年塵土白鬚眉，擬向西湖濯客衣。", "林下杜鵑猶勸去，海邊鷗鳥亦知幾。", "及瓜將得葵丘代，存菊須尋栗里歸。", "見說中山屠博士，鄉心也趁白雲飛。"]'),
('912d036b-e4e0-4fa3-a587-64a49f1f6b7e','再寄子野','仇遠','宋','宋诗','song-poetry','','[]','霜力風威各逞强，老夫絮被不離床。',64,'全唐诗/poet.song.246000.json','["霜力風威各逞强，老夫絮被不離床。", "一貧已幸官將滿，百計無如歸最長。", "別後交朋難得信，夢中文字不成章。", "從來心似梅花白，莫入東風桃李場。"]'),
('54992877-f28d-4399-8860-f206491cfc86','寄鄧善之','仇遠','宋','宋诗','song-poetry','','[]','幾年不寄子公書，忽向燕南遺鯉魚。',64,'全唐诗/poet.song.246000.json','["幾年不寄子公書，忽向燕南遺鯉魚。", "天遠地遥歸未得，男婚女嫁事何如。", "壯遊自致青雲上，漫仕誰憐白髪餘。", "西浙林泉俱可隠，毋忘舊約共閒居。"]'),
('751b2928-958a-43e9-8c0b-f2d762483b10','醉聞杜宇','仇遠','宋','宋诗','song-poetry','','[]','幾日冥迷醉夢中，醒來衣袖裹春風。',64,'全唐诗/poet.song.246000.json','["幾日冥迷醉夢中，醒來衣袖裹春風。", "杜鵑未歇鳥聲碎，芍藥已開花信空。", "差勝跨馿愁杜老，儘教騎馬笑山公。", "卑官安得金貂換，尚有杖頭三百銅。"]'),
('6f8b6137-3e09-4d3b-aa21-a1ba7d697134','北村吳園雨中賞牡丹主人留飲','仇遠','宋','宋诗','song-poetry','','[]','不謂村園見此花，嬌紅數朵眩晴霞。',64,'全唐诗/poet.song.246000.json','["不謂村園見此花，嬌紅數朵眩晴霞。", "可憐國色天香種，竟落田夫野老家。", "略具杯盤供筍蕨，已拚杖屨污泥沙。", "莫愁乳鹿銜春去，自有蓬蒿盡力遮。"]'),
('3db43408-b60b-4716-933a-bfb10bd5de75','官冷','仇遠','宋','宋诗','song-poetry','','[]','不負平生下澤車，宦游卜宅亦村墟。',64,'全唐诗/poet.song.246000.json','["不負平生下澤車，宦游卜宅亦村墟。", "家貧累重須干祿，官冷身閒可讀書。", "高柳每聞鶑婭姹，破籬時度竹蕭疏。", "西南林壑堪娛晚，靜看飛雲自卷舒。"]'),
('2e186bd8-efd3-44b5-a8a2-6a08ad4130bf','喜晴復雨','仇遠','宋','宋诗','song-poetry','','[]','早起方誇甲子晴，夜分忽又似盆傾。',64,'全唐诗/poet.song.246000.json','["早起方誇甲子晴，夜分忽又似盆傾。", "黑雲冉冉連燈暗，白浪滔滔與岸平。", "芹未出泥先有燕，花都委地尚無鶑。", "東橋沙觜多舟楫，直下荆溪不待撐。"]'),
('5947e4df-957e-4369-ab0a-065b436e9f2f','五日','仇遠','宋','宋诗','song-poetry','','[]','湘魄能傳楚澤芳，何如倒載醉襄陽。',64,'全唐诗/poet.song.246000.json','["湘魄能傳楚澤芳，何如倒載醉襄陽。", "夕陰空照栽葵圃，宿雨難乾打麥場。", "龍去涎留丹井濕，燕歸泥落墨池香。", "枉將黍粽沉蛟窟，移與江村餉水荒。"]'),
('e9bfd8bf-46be-4a69-8ba8-4b456dd496fd','雨','仇遠','宋','宋诗','song-poetry','','[]','才放庚申一日晴，天明一日雨如傾。',64,'全唐诗/poet.song.246000.json','["才放庚申一日晴，天明一日雨如傾。", "烏雲覆地陰陰合，白浪侵田灧灧平。", "屋漏未乾連礎潤，橋低欲壓礙舟行。", "桔橰不是閒家具，會聽溪邊鵝鸛鳴。"]'),
('7be490fc-fa00-4b83-8b83-408170e66808','雨坐  其一','仇遠','宋','宋诗','song-poetry','','[]','梅霖寒似麥秋天，風葛凄凄未脫綿。',64,'全唐诗/poet.song.246000.json','["梅霖寒似麥秋天，風葛凄凄未脫綿。", "金彈落池盧橘熟，紅裙委地石榴鮮。", "汨羅遺恨空千載，瀨水閒居尚一年。", "蒲酒相邀須徑醉，歸尋枕席付高眠。"]'),
('7a51a9ac-6613-4a6c-a0a0-96fcba10b9d3','雨坐  其二','仇遠','宋','宋诗','song-poetry','','[]','兩年蒲節雨霏微，誤我中山采藥期。',64,'全唐诗/poet.song.246000.json','["兩年蒲節雨霏微，誤我中山采藥期。", "騎馬出門隨所寓，看花酌酒復奚疑。", "量慳未易勝金盞，臂弱猶堪繫綵絲。", "追憶侯家陪宴賜，素紈紅葛翠交枝。"]'),
('ecf7b3e9-51b0-42af-9b72-8ca2f78b8ff7','與子野過永仙觀循西城以歸邂逅李戒甫夕山西爽詩料滿目子野明發詩來予次韻  其一','仇遠','宋','宋诗','song-poetry','','[]','壞垣荒逕入蒿萊，不惹康衢半點埃。',64,'全唐诗/poet.song.246000.json','["壞垣荒逕入蒿萊，不惹康衢半點埃。", "賞靜偏憐雛笋長，趁凉自引瘦筇來。", "盃餘潄齒呼新茗，石上題詩剝古苔。", "試問依簷雙老檜，何如列柏在烏臺。"]'),
('cd600861-c802-4ba7-9750-c90e3d87a60a','與子野過永仙觀循西城以歸邂逅李戒甫夕山西爽詩料滿目子野明發詩來予次韻  其二','仇遠','宋','宋诗','song-poetry','','[]','一笑相逢李伯時，樹陰匝地綠雲低。',64,'全唐诗/poet.song.246000.json','["一笑相逢李伯時，樹陰匝地綠雲低。", "林梢落日猶餘丈，天下好山多在西。", "我醉欲歸須客送，君裝已趣尚鵑啼。", "明朝定有新詩句，且讓溪翁向上題。"]'),
('31e5b02f-a163-4e79-a324-5b2849cc78a9','寓舍在青安門外由是出郊不數里羣山獻狀如游龍如奔馬如踞虎豹深秀坡陀不一而足似有招引賦詩之意遂約子野再用韻  其一','仇遠','宋','宋诗','song-poetry','','[]','西望寬平倦眼開，風收雲翳掃烟埃。',64,'全唐诗/poet.song.246000.json','["西望寬平倦眼開，風收雲翳掃烟埃。", "誰能白日捲簾坐，盡看青山排闥來。", "合沓斷岡如引蔓，盤陀大石不生苔。", "此中林壑多仙迹，何必吹簫更楚臺。"]'),
('4ab822bd-0f2d-4c49-ad41-26824b0d2cba','寓舍在青安門外由是出郊不數里羣山獻狀如游龍如奔馬如踞虎豹深秀坡陀不一而足似有招引賦詩之意遂約子野再用韻  其二','仇遠','宋','宋诗','song-poetry','','[]','山列瑶簪束不齊，過雲舒卷樹高低。',64,'全唐诗/poet.song.246000.json','["山列瑶簪束不齊，過雲舒卷樹高低。", "孟郊李白曾行處，泰華瑯琊盡向西。", "瘦馬自穿幽徑去，老鶑猶戀落花啼。", "豈無崖壁平如削，留與詩人醉墨題。"]'),
('095d6d33-c4b1-4664-a038-74eda0ab8d8f','和仲祥大風韻  其一','仇遠','宋','宋诗','song-poetry','','[]','正憂藴藴與隆隆，怪得連朝起大風。',64,'全唐诗/poet.song.246000.json','["正憂藴藴與隆隆，怪得連朝起大風。", "酷日從今宜斂暑，大王自古解稱雄。", "中庭老樹吹將折，破屋重茅卷已空。", "可是南溟茝欲化，爰居先避魯門東。"]'),
('d56bb8ed-4c80-4e7d-a5cd-22f6b7dd1038','和仲祥大風韻  其二','仇遠','宋','宋诗','song-poetry','','[]','非雨非雷勢可乘，柔枝弱葉力難勝。',64,'全唐诗/poet.song.246000.json','["非雨非雷勢可乘，柔枝弱葉力難勝。", "疾於健將追奔馬，豪似吟仙賦大鵬。", "柱砥潜移黄螘穴，山屏盡啟白雲縢。", "直須少霽飛廉怒，水落圩田穀再登。"]'),
('64debe5a-07f3-473e-9761-39483a36f332','巫雲九峰','仇遠','宋','宋诗','song-poetry','','[]','誰割巫山一片雲，峰巒羅列比兒孫。',64,'全唐诗/poet.song.246000.json','["誰割巫山一片雲，峰巒羅列比兒孫。", "嵌空自是天生穴，剝蝕無非水渲痕。", "霜削秋清連竹色，露腴曉翠及蒲根。", "九峰九鎖參差似，永鎮仇溪第一村。"]'),
('e0dd18bf-cd50-4df4-9694-f644f538a915','觀雨','仇遠','宋','宋诗','song-poetry','','[]','雨師殿後疾雷先，風捲浮雲似擘綿。',64,'全唐诗/poet.song.246000.json','["雨師殿後疾雷先，風捲浮雲似擘綿。", "大點成漚添黑潦，濃陰匝地暗青天。", "崦中暴長彌漫水，圩上平沉沮洳田。", "米直頓增車戽急，早推紅日麗金淵。"]'),
('808bab62-3ec0-40a7-9c67-42be7345c78c','宦海','仇遠','宋','宋诗','song-poetry','','[]','黄帽棕鞋隠者便，青衫槐笏我家傳。',64,'全唐诗/poet.song.246000.json','["黄帽棕鞋隠者便，青衫槐笏我家傳。", "一生碌碌空多事，六袠駸駸欠二年。", "安樂窩中閒有味，溫柔鄉裏老無緣。", "浮沉宦海終非願，早葺山南屋數椽。"]'),
('c7721366-d0a0-4137-9183-e1054da76a16','屠存博教授赴溧水任留飲寓舍','仇遠','宋','宋诗','song-poetry','','[]','只隔山中一日程，書船暫泊溧陽城。',64,'全唐诗/poet.song.246000.json','["只隔山中一日程，書船暫泊溧陽城。", "儒冠喜見賢翁季，道眼相看老弟兄。", "酒量吞江凉更闊，蟬聲送客晚爭鳴。", "青衫肯爲琵琶濕，笑向天涯看月明。"]'),
('b41ba7cc-81d3-45b8-91f1-618870be64d0','寄戚子雲','仇遠','宋','宋诗','song-poetry','','[]','七不能堪一不成，閒雲自恨出山輕。',64,'全唐诗/poet.song.246000.json','["七不能堪一不成，閒雲自恨出山輕。", "柳枝駱馬愛心斷，蓴菜鱸魚歸興生。", "薄宦棲棲留泮水，故人渺渺隔臺城。", "對床風雨何時卜，共翦青燈話到明。"]'),
('43a8319b-1f03-4154-8c88-6643cbefd6e0','送張巨川歸崇德','仇遠','宋','宋诗','song-poetry','','[]','三載金淵入幙賓，轉當繁劇轉精神。',64,'全唐诗/poet.song.246000.json','["三載金淵入幙賓，轉當繁劇轉精神。", "高堂多有承顔樂，巨室都無切齒人。", "此日吏民爭卧轍，他時事業繼埋輪。", "語兒溪上滄浪水，有約征衣共浣塵。"]'),
('0ac42517-a9b7-49b4-a392-d2189cbb06bb','二十五日東風少定辛丑夜西風再作','仇遠','宋','宋诗','song-poetry','','[]','東風已掃九衢埃，何事飈輪去復回。',64,'全唐诗/poet.song.246000.json','["東風已掃九衢埃，何事飈輪去復回。", "秋信蘋洲凉漸迫，人家蓬戶晝難開。", "低田受水祥禾偃，亂石飛空巨木摧。", "見說長淮旱無雨，蜚蝗幾欲渡江來。"]'),
('6b0da149-fc55-4403-a886-2ed2ad648e4f','五月六日晴芮君節卞西仲諸友來泛蒲和韻','仇遠','宋','宋诗','song-poetry','','[]','端午凄凉雨壓城，忽然端六報新晴。',64,'全唐诗/poet.song.246000.json','["端午凄凉雨壓城，忽然端六報新晴。", "素衣塵暗行人老，綠樹陰濃曙日明。", "倦眼冥冥渾似霧，憂心悄悄只如酲。", "枇杷薦酒猶堪醉，杏子微酸尚带生。"]'),
('84e5c7b1-63b4-44a5-83a1-d30e0202940f','用韻答蕭濟翁','仇遠','宋','宋诗','song-poetry','','[]','想君不欠買山錢，要學騎馿孟浩然。',64,'全唐诗/poet.song.246000.json','["想君不欠買山錢，要學騎馿孟浩然。", "拂袖徑行輕萬里，著書直待後千年。", "林泉短褐凄將老，齋館孤燈耿不眠。", "明旦履霜何所向，大茅峰頂看芝田。"]'),
('70ebeabf-b59f-4e41-9ed1-55f7b0fbc81e','答徐恕宣城寄別','仇遠','宋','宋诗','song-poetry','','[]','懷古潸然老淚流，依稀見月喘吳牛。',64,'全唐诗/poet.song.246000.json','["懷古潸然老淚流，依稀見月喘吳牛。", "客鄉時序留如燕，學舍風波小似舟。", "已恨浮雲無巧夕，未知後月可中秋。", "徐卿忽寄新詩札，正倚雙溪疊嶂樓。"]'),
('c5acdf45-a754-46aa-b98d-0301174e49fa','江陰何仲禮相訪和答','仇遠','宋','宋诗','song-poetry','','[]','月照空梁幾夢中，翩然環佩下天風。',64,'全唐诗/poet.song.246000.json','["月照空梁幾夢中，翩然環佩下天風。", "十年不到澄江上，一櫂能來瀨水東。", "湖海交遊今漸少，英豪見識略相同。", "舊時東野吟詩處，何日携壺酹此翁。"]'),
('70ead792-09a3-4d3a-b235-5581829fe144','答趙源仲','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人到中年萬事慵，我今况是六旬翁。',64,'全唐诗/poet.song.246000.json','["人到中年萬事慵，我今况是六旬翁。", "歸心已薄西湖水，餘力重修古泮宮。", "官裏簡書尤可畏，案頭筆硯豈無功。", "邇來士習殊輕陗，願與醇儒振義風。"]'),
('f8bec453-7026-43c7-b298-f220405552a8','交山龍祠禱雨','仇遠','宋','宋诗','song-poetry','','[]','曉入荒蹊陟斷岡，多年廟食白龍王。',64,'全唐诗/poet.song.246000.json','["曉入荒蹊陟斷岡，多年廟食白龍王。", "要添溪上半篙水，不遠山中一瓣香。", "灌木雲昏旌斾出，高田土渴桔橰忙。", "莫疑栖隠無深洞，且得隨車雨送凉。"]'),
('b1468bf4-19a9-4d47-97a3-c94ea3e69990','題王師尹宜晚樓','仇遠','宋','宋诗','song-poetry','','[]','高捲書簾雨氣寒，螺屏擁髻赴滄灣。',64,'全唐诗/poet.song.246000.json','["高捲書簾雨氣寒，螺屏擁髻赴滄灣。", "去天一握屋上屋，斜日幾重山外山。", "地展畫圖增暮景，風吹笑語落人間。", "棲鴉已寂歸雲急，却怪雲猶未得閒。"]'),
('ac359f04-4055-44b7-b4b2-b3fada4a0021','慶孝僧自金陵回虎林','仇遠','宋','宋诗','song-poetry','','[]','白下長干住幾年，西風入夢即飄然。',64,'全唐诗/poet.song.246000.json','["白下長干住幾年，西風入夢即飄然。", "斷橋梅柳全非舊，古剎鐘魚大勝前。", "萬里豈宜常作客，一簞且可穩栖禪。", "滄江東去風波惡，亦欲湖山結數椽。"]'),
('09cf851a-29be-4b71-b118-1aebebf9f8f3','如上人歸問浙中友信','仇遠','宋','宋诗','song-poetry','','[]','何年駐錫下山中，既見匆匆又欲東。',64,'全唐诗/poet.song.246000.json','["何年駐錫下山中，既見匆匆又欲東。", "燕去鴻來俱是客，雲生月落不離空。", "冷泉亭上參吟暢，飛雪岩前哭老同。", "方外友朋詢近况，爲言已作木鷄翁。"]'),
('9fa84315-7960-491b-902c-701e4ceb9211','過介卿溪南隠居','仇遠','宋','宋诗','song-poetry','','[]','卜宅溪南遠市喧，一經教子守田園。',64,'全唐诗/poet.song.246000.json','["卜宅溪南遠市喧，一經教子守田園。", "邵平未老瓜先熟，靖節能閒菊自存。", "無白丁來多釀酒，放青山入別開門。", "朝衣曾侍天香滿，得似荷衣带露痕。"]'),
('ab8015e1-dda2-4187-9315-3932d982f9ac','悟上人同過史氏隠居','仇遠','宋','宋诗','song-poetry','','[]','經時少暇出郊游，野曠山遥易見秋。',64,'全唐诗/poet.song.246000.json','["經時少暇出郊游，野曠山遥易見秋。", "祗怪朝來多爽氣，似緣我輩是清流。", "荒臺古井平蕪濕，斜日西風亂葉愁。", "莫笑田翁無款待，綠菱新摘酒新篘。"]'),
('1377551b-6bf8-4e04-8831-db01a84a6e15','懷盛元仁','仇遠','宋','宋诗','song-poetry','','[]','年過耳順欲何如，臂膝酸寒齒髪疏。',64,'全唐诗/poet.song.246000.json','["年過耳順欲何如，臂膝酸寒齒髪疏。", "千里驅馳還倦矣，數椽卜築合歸與。", "山銜落日誰能繫，海漲平田自可鋤。", "寄語虎林諸道伴，江湖處處有鱸魚。"]'),
('eb9dd647-ae60-457d-8aef-cec193939274','秋日懷吾子行','仇遠','宋','宋诗','song-poetry','','[]','秋高天闊雁南翔，游子愀然思故鄉。',64,'全唐诗/poet.song.246000.json','["秋高天闊雁南翔，游子愀然思故鄉。", "重陽正當風雨近，三徑故應松菊荒。", "酒酣耳熱狂無益，江空目短愁何長。", "青山在望有晴日，我欲振衣千仞岡。"]'),
('4a6776b6-62bd-4e28-b950-3ddf87e2c3d0','七夕  其一','仇遠','宋','宋诗','song-poetry','','[]','河鼓天孫各老成，無愁可解任秋聲。',64,'全唐诗/poet.song.246000.json','["河鼓天孫各老成，無愁可解任秋聲。", "癡兒笑月羞眉曲，稚女穿針鬬眼明。", "夜半且分瓜果供，天中豈識別離情。", "未能免俗消光景，醉卧西風夢亦清。"]'),
('bd11df28-f139-4c3c-b7a1-c8f741dc2735','七夕  其二','仇遠','宋','宋诗','song-poetry','','[]','歲歲今宵乞巧樓，疏星如弈月如鈎。',64,'全唐诗/poet.song.246000.json','["歲歲今宵乞巧樓，疏星如弈月如鈎。", "莫將寒信侵房屋，肯把閒情問女牛。", "兒笑無書空曬腹，婦言有酒可澆愁。", "鵲慵竟失河橋約，盡日喳喳古樹頭。"]'),
('d00257f7-0cc4-4daf-858d-dc994e1ad5c2','題羣仙圖','仇遠','宋','宋诗','song-poetry','','[]','世代雖殊道不殊，衣冠氣貌列仙儒。',64,'全唐诗/poet.song.246000.json','["世代雖殊道不殊，衣冠氣貌列仙儒。", "自憐無計攀靈轡，豈意相從入畫圖。", "把袂拍肩歸福地，抗塵走俗笑泥塗。", "苔痕還繞榴皮相，風雨東林壁半蕪。"]'),
('4a1069fd-e16f-4b2e-8aa9-f11c8dc6b08c','永逈觀賞桂劉君佐黄景巖治酒','仇遠','宋','宋诗','song-poetry','','[]','雙桂崢嶸萬竹間，雲枝露粟綴高寒。',64,'全唐诗/poet.song.246000.json','["雙桂崢嶸萬竹間，雲枝露粟綴高寒。", "軒窗日日吹香過，冠蓋時時載酒看。", "月裏曾舂金杵臼，雨餘亂點石棋盤。", "乘槎仙子清如鶴，一曲霓裳舞素鸞。"]'),
('46e41156-922b-4fcd-aeb5-a1d9fdd3099c','中秋月出復雨有懷葉子文湯明叔','仇遠','宋','宋诗','song-poetry','','[]','溧濱三度見中秋，感歎光陰逐水流。',64,'全唐诗/poet.song.246000.json','["溧濱三度見中秋，感歎光陰逐水流。", "常是浮雲妬佳月，不容老子醉高樓。", "鱸香易動張翰興，鯨背難追李白游。", "遥憶詩人豪氣在，湖天空闊放扁舟。"]'),
('584e8bc4-5ae7-4d51-9db9-1c834dc3b1bf','中秋待月不見  其一','仇遠','宋','宋诗','song-poetry','','[]','期修翫事在杭州，月夕那知常滯留。',64,'全唐诗/poet.song.246000.json','["期修翫事在杭州，月夕那知常滯留。", "縱有侯芭常載酒，惜無李白共登樓。", "蛩催織婦貧非懶，雲掩霜娥老似羞。", "應笑山翁癡守待，滿身風露冷貂裘。"]'),
('8de826fe-da65-4c82-92df-01afa3be21f2','中秋待月不見  其二','仇遠','宋','宋诗','song-poetry','','[]','年年待月引壺觴，坐對中庭玉一方。',64,'全唐诗/poet.song.246000.json','["年年待月引壺觴，坐對中庭玉一方。", "靜夜忽驚雲作雨，索居空使客思鄉。", "荒鷄聲續簷花滴，蝴蝶夢回巖桂香。", "何處高樓見山闊，快予吹笛據胡床。"]'),
('b6578443-1ef4-4c81-aba5-21aa73621d2f','賞桂','仇遠','宋','宋诗','song-poetry','','[]','秋來常爲桂花忙，葉葉西風粟粟凉。',64,'全唐诗/poet.song.246000.json','["秋來常爲桂花忙，葉葉西風粟粟凉。", "奎甫宅中開四樹，儒珍園後粲孤芳。", "小山招隠人空老，朗月當庭影亦香。", "可必明年能賞得，一觴且醉此花旁。"]'),
('a8d3653f-8391-45b6-9c07-ff9eeb639d2c','夜聞秋聲','仇遠','宋','宋诗','song-poetry','','[]','西南振響使人驚，未必秋聲作此聲。',64,'全唐诗/poet.song.246000.json','["西南振響使人驚，未必秋聲作此聲。", "萬騎奔馳鼙鼓動，千夫翻踏桔橰鳴。", "初疑潮汐還疑雨，只在山林不在城。", "人道今年豐稔兆，燈前起舞待天明。"]'),
('2df368fd-27fb-4881-ae68-a81572936a7c','送許君起赴餘干教授  其一','仇遠','宋','宋诗','song-poetry','','[]','當年而父同吾父，各罄籯金共教兒。',64,'全唐诗/poet.song.246000.json','["當年而父同吾父，各罄籯金共教兒。", "可惜兩翁黄壤下，不知二子綠衣時。", "著鞭雖已撞樓破，列鼎寧無負米思。", "千里送君何以贈，長歌泮水蓼莪詩。"]'),
('ea09626d-4773-4a83-a629-d6232b041a2b','送許君起赴餘干教授  其二','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蘭佩蓉裳似倦遊，東隅雖失尚堪收。',64,'全唐诗/poet.song.246000.json','["蘭佩蓉裳似倦遊，東隅雖失尚堪收。", "君騎潄玉亭前馬，我艤投金瀨上舟。", "八品一官俱獨冷，兩州千里隔三秋。", "南溟鯤化君能事，甘分西湖侶白鷗。"]'),
('c520d3b8-abbf-43e9-9bd8-3ab6fa173123','聞金之一鄧牧心葉去文皆羽化山中','仇遠','宋','宋诗','song-poetry','','[]','獨居學道坐枯禪，鹿豕交遊七十年。',64,'全唐诗/poet.song.246000.json','["獨居學道坐枯禪，鹿豕交遊七十年。", "能以幻軀當雨雪，終無虛腹坐神仙。", "平生文字知誰愛，老死山林絕可憐。", "他日錢塘耆舊傳，三高宜入畫圖傳。"]'),
('f6164910-11f3-48be-b03c-a242431f1378','吳成季尊師與其弟元初會于維揚即還金陵成季寄詩因和','仇遠','宋','宋诗','song-poetry','','[]','初平兄弟總神仙，化石爲羊入上天。',64,'全唐诗/poet.song.246000.json','["初平兄弟總神仙，化石爲羊入上天。", "萬里相期雲上下，一江不隔水淵潫。", "對床夜雨吟詩燭，歸櫂春風載酒船。", "此是人生真樂事，岸花汀草意無邊。"]'),
('a26df86e-e8e4-4c1c-ba18-13c8ef302d3f','寄吳元初道錄','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','桃花兩度見青春，夢裏玄都隔幾塵。',64,'全唐诗/poet.song.246000.json','["桃花兩度見青春，夢裏玄都隔幾塵。", "升斗自憐爲客久，舟車每惜寄書頻。", "君如當日陶弘景，我亦他時賀季真。", "東望冶城空戀戀，西湖非晚作歸人。"]'),
('4e92a19d-21e1-48d7-b6e9-dc09325f7224','中秋月出復雨有懷葉子文湯明叔','仇遠','宋','宋诗','song-poetry','','[]','三秋此夕恰平分，城市人家半閉門。',64,'全唐诗/poet.song.246000.json','["三秋此夕恰平分，城市人家半閉門。", "正憶紫雲吹玉笛，忽驚皓月照金樽。", "宦情素薄鴻初到，詩興方濃雨又昏。", "不是桂花香自慰，倚欄無語易銷魂。"]'),
('bf18c756-6a21-4f3d-9793-5be3f5694893','明朝','仇遠','宋','宋诗','song-poetry','','[]','秋風嫋嫋雨瀟瀟，兀兀郊居出市遥。',64,'全唐诗/poet.song.246000.json','["秋風嫋嫋雨瀟瀟，兀兀郊居出市遥。", "未欠三盃通大道，且欣九日是明朝。", "籬邊舊菊猶堪摘，天末新鴻不可招。", "莫恨登高無脚力，强搘湘竹造山椒。"]'),
('ae08c3a4-fa7c-4c91-b535-189e9d77c551','和西仲秋日聞鶑詩','仇遠','宋','宋诗','song-poetry','','[]','不待風霜剪碧林，柳陰忽見一梭金。',64,'全唐诗/poet.song.246000.json','["不待風霜剪碧林，柳陰忽見一梭金。", "似傳西帝宸遊信，空惹東窗夢覺心。", "暫輟笙歌聊試聽，既無桃杏莫須吟。", "舊交燕子歸何處，好倩賓鴻爲嗣音。"]'),
('9e4c1ceb-8167-4c45-af13-8fcf7dfcf7fa','中秋同陳奎甫放舟','仇遠','宋','宋诗','song-poetry','','[]','尋荷訪桂遠相過，載雨仙舟泛綠波。',64,'全唐诗/poet.song.246000.json','["尋荷訪桂遠相過，載雨仙舟泛綠波。", "老眼已經秋若此，賞心莫問夜如何。", "金樽檀板逢歡伯，玉宇瓊樓鎖素娥。", "爭得西風卷雲幕，與君弄月扣舷歌。"]'),
('2c69f291-dd90-4582-92bc-5f376d94af3d','次日歸舟和南仲','仇遠','宋','宋诗','song-poetry','','[]','𠙶山渺渺點青螺，古瀨澄澄似絳河。',64,'全唐诗/poet.song.246000.json','["𠙶山渺渺點青螺，古瀨澄澄似絳河。", "塵世不知秋過半，水鄉但覺月明多。", "輕舟傲兀魚龍窟，夾岸橫陳早晚禾。", "一笑躍身煙霧表，醉歸何恤夜行訶。"]'),
('868098c8-2fcd-47eb-a743-36cbef0d4999','九月八日持螯','仇遠','宋','宋诗','song-poetry','','[]','趁晴明日擬登高，十里龍山肯憚勞。',64,'全唐诗/poet.song.246000.json','["趁晴明日擬登高，十里龍山肯憚勞。", "但願有錢堪對菊，莫愁無手可持螯。", "蝨官只合辭歸去，鼠腹安能賦老饕。", "行見白衣人送酒，已拚痛飲讀離騷。"]'),
('5eeef67d-711b-4ea9-aa53-21b766cc19f4','九日諸友屏峰上方登高得登字','仇遠','宋','宋诗','song-poetry','','[]','天借重陽一日晴，因過竹院遠尋僧。',64,'全唐诗/poet.song.246000.json','["天借重陽一日晴，因過竹院遠尋僧。", "翠屏晚對無人共，畫棟朝飛與客登。", "旋摘菊花浮臘醖，待分貝葉讀秋燈。", "餘生有暇須行樂，漫向松岡嘆廢陵。"]'),
('42ce2ba4-31e0-4896-8727-a28dd95be4a7','九日次程公明韻','仇遠','宋','宋诗','song-poetry','','[]','風帘獵獵傍簷斜，問酒來投野老家。',64,'全唐诗/poet.song.246000.json','["風帘獵獵傍簷斜，問酒來投野老家。", "佳節已逢重九日，東籬未見兩三花。", "科頭坐石從吹帽，拭眼看山似隔紗。", "七里岡前歸路闇，月懸破鏡憶秦嘉。"]'),
('475c21af-1a85-4553-aaec-946af57a6791','追和陳去非宣和甲辰重九韻','仇遠','宋','宋诗','song-poetry','','[]','世態炎凉不足憂，吾生贏得日優游。',64,'全唐诗/poet.song.246000.json','["世態炎凉不足憂，吾生贏得日優游。", "九日忽驚楓葉落，百年幾見菊花秋。", "忘形詩酒新豐客，滿目溪山古溧州。", "聞道市橋騎馬滑，山公歸醉得無愁。"]'),
('1b683be8-09ba-4f5e-b58c-54b4d6e27574','重陽見菊占冬晴上熟','仇遠','宋','宋诗','song-poetry','','[]','滿城風日釀輕霜，昨夜東籬菊盡黄。',64,'全唐诗/poet.song.246000.json','["滿城風日釀輕霜，昨夜東籬菊盡黄。", "正月自非添一閏，此花安得及重陽。", "新鴻遠到愁無信，螃蟹中虛怕有芒。", "濁酒醒來聞吉語，晴過冬至兆豐穰。"]'),
('638d7817-3e63-4808-a90c-abc67e9248c0','南仲以潘老句約賦','仇遠','宋','宋诗','song-poetry','','[]','秋聲浩蕩夜凄凉，却喜田家熟稻糧。',64,'全唐诗/poet.song.246000.json','["秋聲浩蕩夜凄凉，却喜田家熟稻糧。", "千里江湖隨薄宦，滿城風雨近重陽。", "菊花漸拆青青蘂，桂樹獨飄粟粟香。", "幸是催租人未至，尊前聊爲足成章。"]'),
('5face96b-b5cc-4f86-aba5-9a687386d6b3','十日與侯伯用謝元燾諸友汎菊得頭字','仇遠','宋','宋诗','song-poetry','','[]','西風吹髪冷颼颼，頼有多情帽裹頭。',64,'全唐诗/poet.song.246000.json','["西風吹髪冷颼颼，頼有多情帽裹頭。", "九日已知成昨夜，綠樽聊復集清流。", "山房霜菊偏能耐，客路雲萍故自浮。", "欲識歲寒心皎潔，一方月色十分秋。"]'),
('61f5efc5-36cd-4b1f-baad-ffa91395596e','和胡定甫  其一','仇遠','宋','宋诗','song-poetry','','[]','幾年野水倚扁舟，風雪塵埃暗綺裘。',64,'全唐诗/poet.song.246000.json','["幾年野水倚扁舟，風雪塵埃暗綺裘。", "齊魯青山恒北望，江湖白鳥共東流。", "杜陵騎馬尋征路，李白題詩遍酒樓。", "文學卑官何足說，直須攬轡覓封侯。"]'),
('5b0683a8-01aa-44ae-af20-187f36e43c13','和胡定甫  其二','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淡泊相逢古溧州，世情客况兩悠悠。',64,'全唐诗/poet.song.246000.json','["淡泊相逢古溧州，世情客况兩悠悠。", "腐儒都不通人事，冷掾何曾似宦游。", "輕薄成風雖可畏，廉勤律己每無愁。", "他時重會西湖上，把酒聯詩日自由。"]'),
('e0681254-7908-47a4-a211-f42d63aced82','和費廷玉  其一','仇遠','宋','宋诗','song-poetry','','[]','我昔南徐講席分，知君肥遯白雲村。',64,'全唐诗/poet.song.246000.json','["我昔南徐講席分，知君肥遯白雲村。", "草深能使芝蘭沒，木落方推竹柏尊。", "試問上書投魏闕，何如解組守衡門。", "西風吹醒槐安夢，斜日悠悠半隠垣。"]'),
('0f86ccd1-5652-4911-9c04-9c77445fe392','和費廷玉  其二','仇遠','宋','宋诗','song-poetry','','[]','笑人狗走鹿斯奔，父子瓜畦手自耘。',64,'全唐诗/poet.song.246000.json','["笑人狗走鹿斯奔，父子瓜畦手自耘。", "不願青黄施斷木，且將蒼白看浮雲。", "山巾聊友華陽鶴，野飯時羹古澗芹。", "顯宦何如廉賈好，茜巵千石鮆千斤。"]'),
('4c88736f-ae8f-4227-bec8-26135c359790','和南仲見寄  其一','仇遠','宋','宋诗','song-poetry','','[]','儒冠誤我欲投簪，抱膝聊爲隴上吟。',64,'全唐诗/poet.song.246000.json','["儒冠誤我欲投簪，抱膝聊爲隴上吟。", "故里未歸先入夢，新交雖好少知心。", "清光湛湛溪中月，遺迹沉沉瀨底金。", "聞道雪晴豐薺麥，行看放犢滿桃林。"]'),
('05f65754-5f46-4353-9b75-502db52c2d12','和南仲見寄  其二','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我本西湖一散人，偶來溪上濯烏巾。',64,'全唐诗/poet.song.246000.json','["我本西湖一散人，偶來溪上濯烏巾。", "波光綠映臺城柳，山色青回句曲春。", "客舍相親那忍別，交情到老願如新。", "江南天氣偏宜暖，滿目東風起麴塵。"]'),
('cc18fd50-7a13-4770-915f-a58849bef6ed','送程子方歸蜀  其一','仇遠','宋','宋诗','song-poetry','','[]','薄葺田園溧澤邊，鄉心常夢蜀山川。',64,'全唐诗/poet.song.246000.json','["薄葺田園溧澤邊，鄉心常夢蜀山川。", "梨花知幾逢寒食，麥飯誰能灑墓田。", "矍鑠老翁輕客路，扶携稚子上江船。", "東還莫爲親朋戀，自古雲安有杜鵑。"]'),
('dc0fe5d9-b972-413d-acbc-32e3929f150c','送程子方歸蜀  其二','仇遠','宋','宋诗','song-poetry','','[]','風雪飄蕭季子裘，大江西泝過荆州。',64,'全唐诗/poet.song.246000.json','["風雪飄蕭季子裘，大江西泝過荆州。", "渾家無計歸葱肆，歲晚何人付麥舟。", "長子應門寬後慮，輕帆入峽及春遊。", "明年歸趁梅花發，共醉䲔僊舊酒樓。"]'),
('9ea3e0cf-4789-433a-a906-87963ee51398','又送程公禮侍父歸蜀用方萬里韻','仇遠','宋','宋诗','song-poetry','','[]','遠從溧里上潼川，渚宿岩棲約半年。',64,'全唐诗/poet.song.246000.json','["遠從溧里上潼川，渚宿岩棲約半年。", "老子情懷原不淺，扁舟風景浩無邊。", "故鄉兵後幾人在，明月秋中何處圓。", "母氏懸懸兄弟望，順流及早理歸船。"]'),
('21ab490e-413e-499f-a75a-a1f8aa970772','和友人洮湖韻','仇遠','宋','宋诗','song-poetry','','[]','落日洮湖自放舟，詩筒特爲寄交遊。',64,'全唐诗/poet.song.246000.json','["落日洮湖自放舟，詩筒特爲寄交遊。", "征夫獨寐難爲夜，老我多愁不但秋。", "清興何人聯石鼎，虛名無夢到金甌。", "黄雞白酒田家樂，止有躬耕願未酬。"]'),
('b511675d-f40b-4238-a02d-d28dbc10c5da','呈王元亨僉事','仇遠','宋','宋诗','song-poetry','','[]','三槐鬰鬰德之符，喜向金淵識大儒。',64,'全唐诗/poet.song.246000.json','["三槐鬰鬰德之符，喜向金淵識大儒。", "早讀父書明體用，夙將使指厲廉隅。", "動摇山嶽威猶在，收斂風霜寂似無。", "人道魯公來辨獄，行看霖雨澤焦枯。"]'),
('36d0b317-c848-4f8b-b210-2c5d43b624c4','白海青','仇遠','宋','宋诗','song-poetry','','[]','素禽敏疾出扶餘，六翮雙拳膽氣麄。',64,'全唐诗/poet.song.246000.json','["素禽敏疾出扶餘，六翮雙拳膽氣麄。", "海外天鵝能獨擊，雲間俊鶻敢齊驅。", "㩳身直上非無見，戀主歸來不待呼。", "渭水鷹揚亦如此，好將粉墨寫成圖。"]'),
('131059f3-36a3-44eb-bde3-59289d0e33ce','秋晚齋居  其一','仇遠','宋','宋诗','song-poetry','','[]','君子堂西屋數間，但能容膝敢求安。',64,'全唐诗/poet.song.246000.json','["君子堂西屋數間，但能容膝敢求安。", "悄無人迹如深井，慣聽秋聲是冷官。", "繫馬階前慵夜秣，種蔬牆下助朝餐。", "携來書卷猶堪讀，好共青燈了歲寒。"]'),
('8a87aa60-2fb3-4488-a445-fc3059217cd3','秋晚齋居  其二','仇遠','宋','宋诗','song-poetry','','[]','校官既與廟官同，胡不移家在泮宮。',64,'全唐诗/poet.song.246000.json','["校官既與廟官同，胡不移家在泮宮。", "暮四朝三嫌有累，歲糜月費愧無功。", "致身館閣須公等，曝背庭除任老翁。", "却喜北窗新植竹，行看玉立向南風。"]'),
('58a16262-89f2-4037-bfdb-c7c96aca1931','秋晚齋居  其三','仇遠','宋','宋诗','song-poetry','','[]','乾坤身世一蘧廬，南北東西總可居。',64,'全唐诗/poet.song.246000.json','["乾坤身世一蘧廬，南北東西總可居。", "此去三年韓博士，向來四壁馬相如。", "移文早遣僕徵米，欹枕夜聽兒讀書。", "駕駟乘驄非我事，不如醉兀小肩輿。"]'),
('8eaee022-a536-463f-8fc7-ef8a0a8e5c51','秋晚齋居  其四','仇遠','宋','宋诗','song-poetry','','[]','奇字生來識不多，莫煩載酒日相過。',64,'全唐诗/poet.song.246000.json','["奇字生來識不多，莫煩載酒日相過。", "廊空儘有葉堪掃，門冷渾無雀可羅。", "肯爲功名虧道義，常因課講費吟哦。", "苔荒茅屋歸期遠，細雨簷花且醉歌。"]'),
('8fdaa4ac-1b17-49ff-a8af-7384bdf5dc6d','和姜景星  其一','仇遠','宋','宋诗','song-poetry','','[]','瓦霜磚日合寒晴，最愛幽窗遠市聲。',64,'全唐诗/poet.song.246000.json','["瓦霜磚日合寒晴，最愛幽窗遠市聲。", "懶去著書追管葛，閑來讀易玩周程。", "勞心未必能齊物，寡欲才堪論養生。", "蓍久不神何用卜，了知身世遯而亨。"]'),
('d1521316-f73e-4b5c-8868-67f89b4c0c1e','和姜景星  其二','仇遠','宋','宋诗','song-poetry','','[]','開遍梅花臘漸殘，又傳新曆歲更端。',64,'全唐诗/poet.song.246000.json','["開遍梅花臘漸殘，又傳新曆歲更端。", "書生愛日惟愁晚，稚子敲冰不怕寒。", "酒壓蟻篘醅可撥，詩題蠟紙墨難乾。", "宦遊得似家居樂，一枕三竿夢寐安。"]'),
('a6f4dd60-51ac-4c31-90ed-36f42fc0b099','和張輔之贈別','仇遠','宋','宋诗','song-poetry','','[]','夜雨溪頭泊客船，簷花溝溜亦涓涓。',64,'全唐诗/poet.song.246000.json','["夜雨溪頭泊客船，簷花溝溜亦涓涓。", "燈前詩酒留三宿，紙上功名付百年。", "寒雁叫霜投木末，晴雲扶日出山巔。", "欲歸苦被微官縛，不得相從酌冷泉。"]'),
('e26b0240-0ffd-4d4f-ab4e-918e7179ec1d','方竹杖','仇遠','宋','宋诗','song-poetry','','[]','勁節稜稜瘦且堅，形模界尺出天然。',64,'全唐诗/poet.song.246000.json','["勁節稜稜瘦且堅，形模界尺出天然。", "山翁甚愛資扶老，村衲無知誤削圓。", "偏稱深衣同此矩，漫誇長笛大如椽。", "有時閒爲吟詩出，徙倚中庭月一磚。"]'),
('f7f8a3b2-1a2e-44fc-a5cc-50dbba8aed7e','授時曆以丁未爲一歲  其一','仇遠','宋','宋诗','song-poetry','','[]','仇山村叟始生辰，六袠平頭又見春。',64,'全唐诗/poet.song.246000.json','["仇山村叟始生辰，六袠平頭又見春。", "檢曆今年交一歲，乘槎有日到三神。", "文章翰墨聊從好，富貴功名莫認真。", "且醉市橋新熟酒，紅梅花插白綸巾。"]'),
('b53e2601-551b-45f5-a693-7cd1cfddcada','授時曆以丁未爲一歲  其二','仇遠','宋','宋诗','song-poetry','','[]','一從妻子累心身，役役勞勞春復春。',64,'全唐诗/poet.song.246000.json','["一從妻子累心身，役役勞勞春復春。", "苦被長貧難擇祿，寧甘漸老不如人。", "廣文冷坐非無飯，張翰思歸豈爲蓴。", "莫問當初弧矢事，祗今筆硯亦生塵。"]'),
('b289b6cc-4f99-4561-887b-917dcdcf4e4d','秋懷和子野  其一','仇遠','宋','宋诗','song-poetry','','[]','霜紈如月勝吳紗，彷彿蟾宮路未賒。',64,'全唐诗/poet.song.246000.json','["霜紈如月勝吳紗，彷彿蟾宮路未賒。", "滌暑自宜斟瑞露，憑虛誰肯乞飛霞。", "荒城蔓草生螢火，古瀨西風起浪花。", "夢裏仇山歸未得，竹籬茅屋趁溪斜。"]'),
('d8772008-c808-4542-8b35-2bac33baedbd','秋懷和子野  其二','仇遠','宋','宋诗','song-poetry','','[]','自笑酸寒老孟郊，厭看俗事聚牛毛。',64,'全唐诗/poet.song.246000.json','["自笑酸寒老孟郊，厭看俗事聚牛毛。", "故鄉甚愛鱸魚美，冷掾何嫌馬骨高。", "少日宦情原淡泊，凉風客鬢轉刁騷。", "荷衣槐笏徒拘束，不似芒鞋白紵袍。"]'),
('7911fc06-e992-492a-8ea1-1895e08bf501','陳明遠書塾與蔣平仲張伯成清話','仇遠','宋','宋诗','song-poetry','','[]','霜晴泛渚狎輕鷗，人物欣逢古太丘。',64,'全唐诗/poet.song.246000.json','["霜晴泛渚狎輕鷗，人物欣逢古太丘。", "喬木故家猶昨日，寒花老圃正清秋。", "尊開北海心先醉，燭盡西窗話不休。", "笑我一身閒未得，又隨新雨上歸舟。"]'),
('9072feea-8055-473b-8353-37f338de8104','送郭君賢使君赴建德任  其一','仇遠','宋','宋诗','song-poetry','','[]','天邊久下紫泥書，日日東津望使車。',64,'全唐诗/poet.song.246000.json','["天邊久下紫泥書，日日東津望使車。", "最愛小兒騎竹馬，也隨迓吏過桐廬。", "良民吐氣心方快，宿弊盤根力爲鋤。", "祗恐聲名滿朝著，春坊賓客又新除。"]'),
('2923d8e7-58fe-41ae-b9aa-98fbf3f569a1','送郭君賢使君赴建德任  其二','仇遠','宋','宋诗','song-poetry','','[]','先朝日近侍明光，步武駸駸政事堂。',64,'全唐诗/poet.song.246000.json','["先朝日近侍明光，步武駸駸政事堂。", "玉宇承恩沾湛露，金淵遺愛托甘棠。", "江山此去分風月，門戶從來凜雪霜。", "虎兕梟狐宜斂迹，丈夫原不畏豪强。"]'),
('28147642-c564-438e-bab2-49335f998722','和吳東升','仇遠','宋','宋诗','song-poetry','','[]','知君豹隠白雲村，杖履春風忽過門。',64,'全唐诗/poet.song.246000.json','["知君豹隠白雲村，杖履春風忽過門。", "獨立幸無妻子累，老成喜有典型存。", "冰懸古樹花尤雋，雪漲寒江水不渾。", "冷落十年燈火讀，何時窗下約重溫。"]'),
('f366f73c-5d2d-4d32-be31-5260fb9273d4','和子野郊居見寄  其一','仇遠','宋','宋诗','song-poetry','','[]','知君標格眼前稀，暫別令人入夢思。',64,'全唐诗/poet.song.246000.json','["知君標格眼前稀，暫別令人入夢思。", "鋏有可彈何必嘆，書如肯借本非癡。", "且看平子歸田賦，更和淵明述酒詩。", "我勸山中多種漆，收功莫恨十年遲。"]'),
('8fb459b6-07cb-428b-910e-31f3f5b0a664','和子野郊居見寄  其二','仇遠','宋','宋诗','song-poetry','','[]','論心握手到忘形，性癖耽詩各瘦生。',64,'全唐诗/poet.song.246000.json','["論心握手到忘形，性癖耽詩各瘦生。", "美酒三升差可戀，良田二頃不如耕。", "溪晴正熟眠鷗夢，門靜那驚吠犬聲。", "泉石煙霞能自樂，棄予高舉得無情。"]'),
('266f6406-5d30-4ae2-ad93-cf7e5c30a311','和子野郊居見寄  其三','仇遠','宋','宋诗','song-poetry','','[]','歸去來兮意趣長，幽居遠隔水雲鄉。',64,'全唐诗/poet.song.246000.json','["歸去來兮意趣長，幽居遠隔水雲鄉。", "花粘石几吟詩筆，風度溪房煮藥香。", "把酒有時思太白，下車何日見元方。", "雲萍暫聚還分散，可是先生鐵石腸。"]'),
('04d5818d-f90c-41ec-9f91-a5675e3d41b2','和子野郊居見寄  其四','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','因子洮湖歸釣魚，西湖我亦念吾廬。',64,'全唐诗/poet.song.246000.json','["因子洮湖歸釣魚，西湖我亦念吾廬。", "途窮但覺知心少，性直由來料事疏。", "愛把琴彈招隠操，忍拈筆寫絕交書。", "人間喜怒須臾事，暮四朝三任衆狙。"]'),
('14f6ad10-d246-4e0f-a19f-9cf0c878e2c8','生日和洪山甫見贈韻','仇遠','宋','宋诗','song-poetry','','[]','雪雲無罅霽無期，勾引春光入泮池。',64,'全唐诗/poet.song.246000.json','["雪雲無罅霽無期，勾引春光入泮池。", "師道幸爲文學掾，堯夫喜見太平時。", "典衣沽酒從兒笑，閉戶吟詩只子知。", "甚欲相隨强歌舞，却憐多病覺衰遲。"]'),
('508b1dad-9936-4ebe-aed8-c4e075634bcd','初冬郊行  其一','仇遠','宋','宋诗','song-poetry','','[]','喜聞潁弟與坡兄，趁小春晴野外行。',64,'全唐诗/poet.song.246000.json','["喜聞潁弟與坡兄，趁小春晴野外行。", "獨樹荒村生處僻，落霞孤鶩去邊明。", "豳風酒食歸田樂，韶部塤箎打稻聲。", "從此廣文差飯足，素餐祇愧老農耕。"]'),
('6eb3c1d0-edef-4291-a7e3-903a3af2cedd','初冬郊行  其二','仇遠','宋','宋诗','song-poetry','','[]','懶向南園拜石兄，肯尋村叟傍溪行。',64,'全唐诗/poet.song.246000.json','["懶向南園拜石兄，肯尋村叟傍溪行。", "黄雲覆畝金穰熟，白露橫江紅葉明。", "彭澤歸來辭內景，康衢擊壤曲中聲。", "一丁不識多牛者，應笑書田事筆耕。"]'),
('20f1d4f2-7755-4147-8431-1f4e32597b26','公退曝日','仇遠','宋','宋诗','song-poetry','','[]','公退無營懶讀書，出門佳客費招呼。',64,'全唐诗/poet.song.246000.json','["公退無營懶讀書，出門佳客費招呼。", "閒搔短髪身將老，獨坐長簷日未晡。", "溪女賣魚隨市價，村夫騎馬納官租。", "勞生役役知何益，却笑今吾即故吾。"]'),
('6975341f-a404-4641-a645-0db44841b126','雪晴','仇遠','宋','宋诗','song-poetry','','[]','臘尾春頭半月期，寒欺人日雪銷遲。',64,'全唐诗/poet.song.246000.json','["臘尾春頭半月期，寒欺人日雪銷遲。", "纔升晴旭扶桑樹，便拂東風細柳枝。", "和氣滿城真可掬，豐年擊壤已先知。", "侏儒溫飽皇天賜，行續中和樂職詩。"]'),
('79ff586e-70c4-4e90-a115-055cd96b8ac7','至日用張伯舉韻','仇遠','宋','宋诗','song-poetry','','[]','博士無氈卧冷齋，有朋喜自遠方來。',64,'全唐诗/poet.song.246000.json','["博士無氈卧冷齋，有朋喜自遠方來。", "臘前一信春先到，隴首數枝梅已開。", "少忍年荒須辟穀，尚遲酒禁且銜盃。", "山中茅屋不歸去，空想秋風暗綠苔。"]'),
('72c542eb-403d-4789-be6d-7f91f3ef87f7','至日懷羅國賓  其一','仇遠','宋','宋诗','song-poetry','','[]','官冷誰能送酒錢，江鄉節物倍蕭然。',64,'全唐诗/poet.song.246000.json','["官冷誰能送酒錢，江鄉節物倍蕭然。", "容顔一日老一日，人事一年經一年。", "野僕竹輿侵曉出，病妻布被抱愁眠。", "甘心歸隠青巖下，閒共殘農理廢田。"]'),
('126789ab-514f-4923-ba4f-8a94f1a2ffcd','至日懷羅國賓  其二','仇遠','宋','宋诗','song-poetry','','[]','羣陰剝盡一陽回，霜日烘晴宿霧開。',64,'全唐诗/poet.song.246000.json','["羣陰剝盡一陽回，霜日烘晴宿霧開。", "閉戶讀書差自樂，載肴問字莫須來。", "榮枯易了觀芸草，冷暖相忘付酒盃。", "得似山居酬應少，晝長閒坐看寒梅。"]'),
('0a2cd08a-1980-459d-8fe6-535e6a4aadbd','潤州許使君寄餉新釀以流金牋爲贄且供詩藁','仇遠','宋','宋诗','song-poetry','','[]','浮玉乘壺香似桂，流金方絮滑如苔。',64,'全唐诗/poet.song.246000.json','["浮玉乘壺香似桂，流金方絮滑如苔。", "報投且致相思意，酬唱須尋應猝才。", "君喜旌幢開使府，我貪花竹作春臺。", "明年準擬游招隠，莫放遮山繡幕來。"]'),
('6e19d9fb-68ac-4d0b-8fb8-dd7fcbc5f347','冬日小齋即事','仇遠','宋','宋诗','song-poetry','','[]','蘆葦周遭舊楮糊，就中穴地砌磚爐。',64,'全唐诗/poet.song.246000.json','["蘆葦周遭舊楮糊，就中穴地砌磚爐。", "儒酸官冷渾相稱，草卧氈眠本不拘。", "窗外十分西日照，簾間半點北風無。", "一瓶雪水煎茶熟，清氣真能壓武夫。"]'),
('7b2441b8-7839-40aa-916c-b3ef8115840c','君子堂小集','仇遠','宋','宋诗','song-poetry','','[]','樂歲欣逢節序新，公堂稱兕集嘉賓。',64,'全唐诗/poet.song.246000.json','["樂歲欣逢節序新，公堂稱兕集嘉賓。", "衣冠尚想江東舊，芹藻初回泮水春。", "無事聊爲文字飲，相看總是老成人。", "且須飽喫圭田飯，朝市山林各致身。"]'),
('81037edb-3824-474b-b3c3-ab97463229b3','歲晏遷居','仇遠','宋','宋诗','song-poetry','','[]','借榻青安恰一年，年窮何事復謀遷。',64,'全唐诗/poet.song.246000.json','["借榻青安恰一年，年窮何事復謀遷。", "官閒空綰文章印，水淺難移書畫船。", "稚子歡呼新入屋，老夫嘆息早歸田。", "人生聚散如鳬雁，極目江湖萬里天。"]'),
('ff3af576-0f6e-44f3-a35d-1da83c8f2453','子野雪後寄和却寄廷玉  其一','仇遠','宋','宋诗','song-poetry','','[]','淵明白髪滿頭生，肯賦閒情未老成。',64,'全唐诗/poet.song.246000.json','["淵明白髪滿頭生，肯賦閒情未老成。", "自笑冷官租屋住，每因來使出郊迎。", "橫經空忝先生號，解印仍呼處士名。", "惟有溪干隠君子，知予的的願歸耕。"]'),
('a512c2fd-74a4-4d78-ab47-7aa9ebd712bc','子野雪後寄和却寄廷玉  其二','仇遠','宋','宋诗','song-poetry','','[]','琴書筆硯伴閒身，斗室依然不覺貧。',64,'全唐诗/poet.song.246000.json','["琴書筆硯伴閒身，斗室依然不覺貧。", "野犬自來能吠雪，土牛此去且迎春。", "一氈輾轉衾無絮，四壁凄凉甑有塵。", "昨夜東風先破凍，江梅冷眼笑何人。"]'),
('200f468d-a285-46de-b2fe-9bbed563eee1','子野雪後寄和却寄廷玉  其三','仇遠','宋','宋诗','song-poetry','','[]','平明跨馬晚方歸，偃仰行窩早見幾。',64,'全唐诗/poet.song.246000.json','["平明跨馬晚方歸，偃仰行窩早見幾。", "餘子祗宜床下卧，詩人頓覺眼中稀。", "堂堂白璧埋黄壤，冉冉緇塵染素衣。", "得酒便須開口笑，雪畦紫芋勝秋肥。"]'),
('a8858b2d-1546-45bb-8ddd-1aebce6474d8','子野雪後寄和却寄廷玉  其四','仇遠','宋','宋诗','song-poetry','','[]','素琴掛壁已多時，政爾難逢鍾子期。',64,'全唐诗/poet.song.246000.json','["素琴掛壁已多時，政爾難逢鍾子期。", "腹有精神方學道，面無塵土始言詩。", "山童隔壁沽村醖，田叟登門送墓碑。", "小市饑氓爭糴米，青州太守可能知。"]'),
('13fa2c8b-d4ad-409e-a0b5-505c97743c4d','至後  其一','仇遠','宋','宋诗','song-poetry','','[]','憑高欲驗曉雲黄，東際紅光見太陽。',64,'全唐诗/poet.song.246000.json','["憑高欲驗曉雲黄，東際紅光見太陽。", "便覺池芹春灧灧，俄驚簷竹晝琅琅。", "君師百拜恩難報，文史三冬志未償。", "吾道千鈞懸一縷，願同繡綫日添長。"]'),
('e92beb7d-c67d-4960-a794-ceaad61916b4','至後  其二','仇遠','宋','宋诗','song-poetry','','[]','陽和昨夜到梅邊，喜得春風一信傳。',64,'全唐诗/poet.song.246000.json','["陽和昨夜到梅邊，喜得春風一信傳。", "同舍團欒齊賀歲，異鄉飄泊又經年。", "夢中歸路忘舟楫，客裏生涯倚俸錢。", "紙帳布衾差穩睡，不愁獨冷坐無氈。"]'),
('546d576c-3edc-46f1-adba-8edcdefcb726','至後  其三','仇遠','宋','宋诗','song-poetry','','[]','霜華如雪著烏巾，染鬢粘鬚白未勻。',64,'全唐诗/poet.song.246000.json','["霜華如雪著烏巾，染鬢粘鬚白未勻。", "人羨久生趨老境，日隨長至到新春。", "投金瀨上能容我，貢玉堂中自有人。", "溧酒清醇魚菜美，不妨頻日宴嘉賓。"]'),
('7c5ca015-af00-4f09-b2df-09545f6fd620','至後  其四','仇遠','宋','宋诗','song-poetry','','[]','了知五十九年非，景薄崦嵫合見幾。',64,'全唐诗/poet.song.246000.json','["了知五十九年非，景薄崦嵫合見幾。", "夜半雖當泉脈動，臘前未見雪花飛。", "客程鴻雁駸駸老，家養雞豚處處肥。", "千日及瓜今過半，未知何日定言歸。"]'),
('91c8a20d-ecfe-4551-833e-8b9020a255db','歲窮早睡','仇遠','宋','宋诗','song-poetry','','[]','驥尾流光不可追，山中小草合知非。',64,'全唐诗/poet.song.246000.json','["驥尾流光不可追，山中小草合知非。", "臘餘四日春先到，官滿三年客早歸。", "暗雨隨風茅屋漏，荒城爭米燎盆稀。", "明朝又赴公筵賀，燈下醒眠懶解衣。"]'),
('f9208387-98b7-496c-b750-fa02036162ce','十一月十六日學宮對酒','仇遠','宋','宋诗','song-poetry','','[]','客况冬晴足自寬，招邀春意入毫端。',64,'全唐诗/poet.song.246000.json','["客况冬晴足自寬，招邀春意入毫端。", "浮雲蔽日俄生暝，急雨隨風故作寒。", "詩酒相尋忘爾汝，古今難必是悲歡。", "茫茫山嶽蘧蘧夢，不了梅花冷眼看。"]'),
('bc175f93-274d-41e3-8b28-edeb67be953c','衰年','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','衰年六十喜平頭，微祿虛名老可羞。',64,'全唐诗/poet.song.246000.json','["衰年六十喜平頭，微祿虛名老可羞。", "自笑一生同蝜蝂，了知萬事等蜉蝣。", "寡懽元亮須歸去，老病相如已倦遊。", "只憶西湖春漲綠，柳邊雪外艤蘭舟。"]'),
('b561995e-453c-4d35-8aa4-0e629c13d8e3','送湯希賢晦庵書院山長','仇遠','宋','宋诗','song-poetry','','[]','文公闕里女星源，手澤遺書尚有傳。',64,'全唐诗/poet.song.246000.json','["文公闕里女星源，手澤遺書尚有傳。", "精舍三年常作主，修程千里若登仙。", "青衫槐笏存家譜，練带花屏擁客船。", "故老或詢予出處，爲言索米向金淵。"]'),
('ce8ad348-2a35-42c0-b370-a8c7100ac0c4','與李孔言上舍談星命','仇遠','宋','宋诗','song-poetry','','[]','辟雍人物已無多，奈此江湖落拓何。',64,'全唐诗/poet.song.246000.json','["辟雍人物已無多，奈此江湖落拓何。", "鶴表只宜歸井邑，雁程不必度關河。", "詩書志氣存司馬，言語功名付祝鮀。", "炙輠談天非我事，雨燈聊和醉時歌。"]'),
('ba1cf24e-619c-479d-9ee9-1495b7d0bcef','游士','仇遠','宋','宋诗','song-poetry','','[]','游士登門索裹糧，塵埃冉冉化衣裳。',64,'全唐诗/poet.song.246000.json','["游士登門索裹糧，塵埃冉冉化衣裳。", "老夫也自飯不飽，童子聊沽酒共嘗。", "彼此身謀寧枉道，古今樂事是歸鄉。", "家徒四壁侯千戶，夢裏誰能較短長。"]'),
('6cdd571e-b28a-4eb7-be60-26e6f7ba3f84','歲除志喜','仇遠','宋','宋诗','song-poetry','','[]','郊居守歲若爲情，一歲中間百事經。',64,'全唐诗/poet.song.246000.json','["郊居守歲若爲情，一歲中間百事經。", "建業長男方入拜，桐江小女又歸寧。", "蒙頭被暖先高卧，婪尾盃空且獨醒。", "席上梅花開勝雪，寒香儘足慰飄零。"]'),
('dcee7856-40fd-4b6a-a93f-85c9cf2fbe31','除夕前一日雪','仇遠','宋','宋诗','song-poetry','','[]','江城臘盡漸春來，三白呈祥不待催。',64,'全唐诗/poet.song.246000.json','["江城臘盡漸春來，三白呈祥不待催。", "和氣已知隨處滿，梅花正用此時開。", "寒香冷艷相吞吐，月斧風斤巧剪裁。", "布絮寢衣烘未透，爐邊酒熟且銜盃。"]'),
('6b221790-93b4-44a1-a971-f66fea946e7f','呈王直卿御史','仇遠','宋','宋诗','song-poetry','','[]','金淵寶地閲金經，朝夕追隨驄馬行。',64,'全唐诗/poet.song.246000.json','["金淵寶地閲金經，朝夕追隨驄馬行。", "激濁揚清真御史，即溫聽厲老先生。", "衣冠文物今無幾，車笠交遊最有情。", "早願明時相司馬，他年洛社會耆英。"]'),
('a2edeb77-ca18-4459-bff9-1c33fe841f1b','小齋四花 梅','仇遠','宋','宋诗','song-poetry','','[]','艾納護春香，橫枝偃霜月。',24,'全唐诗/poet.song.246000.json','["艾納護春香，橫枝偃霜月。", "絕憐玉妃面，化作鐵漢骨。"]'),
('e14c0038-c001-4333-aff6-0328a77af763','小齋四花 水仙','仇遠','宋','宋诗','song-poetry','','[]','翠翹玉搔頭，湘妃赴蓬島。',24,'全唐诗/poet.song.246000.json','["翠翹玉搔頭，湘妃赴蓬島。", "如何譜騷人，不收此香草。"]'),
('d0483e68-5bf6-41ca-9fd8-23a11c26bf2e','小齋四花 菊','仇遠','宋','宋诗','song-poetry','','[]','晶晶雪前黄，矯矯霜下傑。',24,'全唐诗/poet.song.246000.json','["晶晶雪前黄，矯矯霜下傑。", "秋香寧可衰，相與全晚節。"]'),
('d171d0f7-0fea-4db6-9d84-8b853059cd7c','小齋四花 蠟梅','仇遠','宋','宋诗','song-poetry','','[]','別作一家春，故畹已禾黍。',24,'全唐诗/poet.song.246000.json','["別作一家春，故畹已禾黍。", "黄香從何來，誰爲東風主。"]'),
('ff304027-7d37-4865-92ee-a2abb86d963d','題扇  其一','仇遠','宋','宋诗','song-poetry','','[]','溪山隔岸好，風雨過橋危。',24,'全唐诗/poet.song.246000.json','["溪山隔岸好，風雨過橋危。", "何似高樓上，停雲且賦詩。"]'),
('e889b6c0-56cc-44c9-9655-f1847fdaff5d','題扇  其二','仇遠','宋','宋诗','song-poetry','','[]','茂樹坐終日，水流心不競。',24,'全唐诗/poet.song.246000.json','["茂樹坐終日，水流心不競。", "誰識山中居，萬動歸一靜。"]'),
('4006959b-f40e-4c60-aa9e-c38958100b86','題扇  其三','仇遠','宋','宋诗','song-poetry','','[]','泉急喧溪碓，山深怯瘦馿。',24,'全唐诗/poet.song.246000.json','["泉急喧溪碓，山深怯瘦馿。", "翟湯如肯隠，來此卜幽居。"]'),
('3fd74326-b391-4768-83ba-e3848817e76a','題扇  其四','仇遠','宋','宋诗','song-poetry','','[]','紅紫委塵土，綠窗清晝長。',24,'全唐诗/poet.song.246000.json','["紅紫委塵土，綠窗清晝長。", "安知兩三竹，風已作秋凉。"]'),
('5809cf38-f8f5-423b-a142-2ce4c854196f','題扇  其五','仇遠','宋','宋诗','song-poetry','','[]','欹枕聞春雨，閉門見綠陰。',24,'全唐诗/poet.song.246000.json','["欹枕聞春雨，閉門見綠陰。", "可人歌扇底，猶有惜春心。"]'),
('707c2909-55de-4ee2-99d5-18889d5201a7','題趙希賢所藏墨竹  其一','仇遠','宋','宋诗','song-poetry','','[]','一竿千百葉，鳳尾翠交加。',24,'全唐诗/poet.song.246000.json','["一竿千百葉，鳳尾翠交加。", "曾向僊壇種，和風掃落花。"]'),
('95d4a645-7073-4a43-af73-89fa2b4040d9','題趙希賢所藏墨竹  其二','仇遠','宋','宋诗','song-poetry','','[]','新梢霧如沐，斷節霜不枯。',24,'全唐诗/poet.song.246000.json','["新梢霧如沐，斷節霜不枯。", "西窗夕陽下，此君何可無。"]'),
('cccfc9c2-49f4-41b2-bbff-106b801fa8c3','題趙希賢所藏墨竹  其三','仇遠','宋','宋诗','song-poetry','','[]','謝家庭下玉，化此青琅玕。',24,'全唐诗/poet.song.246000.json','["謝家庭下玉，化此青琅玕。", "風標敻不俗，誰謂骨相寒。"]'),
('9a03ab1c-8cec-4bdc-bfab-e1383a681902','題趙希賢所藏墨竹  其四','仇遠','宋','宋诗','song-poetry','','[]','直節豸獻角，低枝鸞振羽。',24,'全唐诗/poet.song.246000.json','["直節豸獻角，低枝鸞振羽。", "古色鎮蒼然，非煙亦非雨。"]'),
('97d17774-fc61-438a-80ee-5471c41c230d','題畫竹  其一','仇遠','宋','宋诗','song-poetry','','[]','誰謂籊籊竿，乃不如勁草。',24,'全唐诗/poet.song.246000.json','["誰謂籊籊竿，乃不如勁草。", "北風動地來，直節未易倒。"]'),
('42110d94-4fe9-45ec-a4bb-bc9807cdf298','題畫竹  其二','仇遠','宋','宋诗','song-poetry','','[]','凈洗碧娟娟，顔色如少年。',24,'全唐诗/poet.song.246000.json','["凈洗碧娟娟，顔色如少年。", "窗前風收雨，階下笋行鞭。"]'),
('90d45008-8b84-4c29-b40e-30d4e34993ef','題畫竹  其三','仇遠','宋','宋诗','song-poetry','','[]','直節老欲枯，初篁瘦而勁。',24,'全唐诗/poet.song.246000.json','["直節老欲枯，初篁瘦而勁。", "祖孫知幾傳，不改君子性。"]'),
('a8b41593-9358-4f8c-91ac-d876922a22aa','題畫竹  其四','仇遠','宋','宋诗','song-poetry','','[]','新笋籜半含，節下粉猶綠。',24,'全唐诗/poet.song.246000.json','["新笋籜半含，節下粉猶綠。", "指日南風來，吹作階庭玉。"]'),
('c9312715-6f48-4da3-9437-bc6e932cb3a3','五更  其一','仇遠','宋','宋诗','song-poetry','','[]','僕云月未落，或謂夜過半。',24,'全唐诗/poet.song.246000.json','["僕云月未落，或謂夜過半。", "曉眠我正濃，漫漫何時旦。"]'),
('cde090bc-7f40-4cd5-9798-69a2e25c51b6','五更  其二','仇遠','宋','宋诗','song-poetry','','[]','一雞一雞鳴，夢覺天未曉。',24,'全唐诗/poet.song.246000.json','["一雞一雞鳴，夢覺天未曉。", "誰較夜短長，我睡不可少。"]'),
('7d164d5c-d9f6-421e-a0b6-a5221cd29bb8','五更  其三','仇遠','宋','宋诗','song-poetry','','[]','山寺鐘未鳴，城樓角已奏。',24,'全唐诗/poet.song.246000.json','["山寺鐘未鳴，城樓角已奏。", "角聲正可聽，欹枕續殘漏。"]'),
('41947965-ee0b-4aab-89be-548b5d2afd00','五更  其四','仇遠','宋','宋诗','song-poetry','','[]','月轉參旗橫，梅花夢方熟。',24,'全唐诗/poet.song.246000.json','["月轉參旗橫，梅花夢方熟。", "羅浮山忽來，毋乃地脈縮。"]'),
('2fde0696-18aa-4f04-841a-d17ef3c5a31b','五更  其五','仇遠','宋','宋诗','song-poetry','','[]','杭城打六更，市樓已攢點。',24,'全唐诗/poet.song.246000.json','["杭城打六更，市樓已攢點。", "流年莫催人，老色將冉冉。"]'),
('adf2b2f5-154a-4b34-b18d-55708c357c6e','五更  其六','仇遠','宋','宋诗','song-poetry','','[]','丑夜方向寅，被衾冷如鐵。',24,'全唐诗/poet.song.246000.json','["丑夜方向寅，被衾冷如鐵。", "江南貧者多，奈此霜加雪。"]'),
('68841f27-aeb7-49f5-ac94-6ab60a90c8e1','五更  其七','仇遠','宋','宋诗','song-poetry','','[]','愁多怯長夜，况乃衆病歸。',24,'全唐诗/poet.song.246000.json','["愁多怯長夜，况乃衆病歸。", "何待六十年，老矣當知非。"]'),
('7cdf0ca8-2dbc-4dc8-ab0b-92c3534aa62e','五更  其八','仇遠','宋','宋诗','song-poetry','','[]','雁鳴鶴亦鳴，不待雞戒旦。',24,'全唐诗/poet.song.246000.json','["雁鳴鶴亦鳴，不待雞戒旦。", "平生善利心，一鳴思過半。"]'),
('3895540a-3cba-40e3-befa-c7adfefb67d7','五更  其九','仇遠','宋','宋诗','song-poetry','','[]','宰相當此時，已入待漏院。',24,'全唐诗/poet.song.246000.json','["宰相當此時，已入待漏院。", "我輩獨何人，擁被猶困倦。"]'),
('96ddd2ae-0438-4e1d-b2f0-710ddf725123','五更  其一○','仇遠','宋','宋诗','song-poetry','','[]','爐藏火尚紅，雪映窗已白。',24,'全唐诗/poet.song.246000.json','["爐藏火尚紅，雪映窗已白。", "夢遊無色界，不知身是客。"]'),
('3c295b10-19b3-432d-9d1a-4a7ef83db51c','枕上  其一','仇遠','宋','宋诗','song-poetry','','[]','雞鳴夜過半，霜氣入孤衾。',24,'全唐诗/poet.song.246000.json','["雞鳴夜過半，霜氣入孤衾。", "歲時將脫屣，鄰家方擣砧。"]'),
('f5d17c42-5b17-4157-b88f-fe2234f0dfe7','枕上  其二','仇遠','宋','宋诗','song-poetry','','[]','出門雞一鳴，僕馬蹋曉凍。',24,'全唐诗/poet.song.246000.json','["出門雞一鳴，僕馬蹋曉凍。", "豈知牧牛兒，正作維魚夢。"]'),
('97aa60a5-b17a-4b1d-87ad-4d21932e6846','枕上  其三','仇遠','宋','宋诗','song-poetry','','[]','一官振饑荒，一官覆水旱。',24,'全唐诗/poet.song.246000.json','["一官振饑荒，一官覆水旱。", "州里多應酬，田家少愁嘆。"]'),
('f157be62-7c96-46f2-99d0-ea149866b52a','三學士圖','仇遠','宋','宋诗','song-poetry','','[]','三賢品坐一枰棋，日永官閒對紫薇。',32,'全唐诗/poet.song.246000.json','["三賢品坐一枰棋，日永官閒對紫薇。", "好袖玉堂揮翰手，不爭勝負是知幾。"]'),
('ce1ae83f-4ba6-4704-87fc-9f4211af12e0','自笑','仇遠','宋','宋诗','song-poetry','','[]','謁客登門不敢嗔，强顔應接暫時親。',32,'全唐诗/poet.song.246000.json','["謁客登門不敢嗔，强顔應接暫時親。", "一官本自如冰冷，更有依冰借暖人。"]'),
('5f2231af-3351-4258-810a-21fe64c0567c','正月辛酉大雪三首  其一','仇遠','宋','宋诗','song-poetry','','[]','繽紛萬片打窗來，驀趁斜風舞却回。',32,'全唐诗/poet.song.246000.json','["繽紛萬片打窗來，驀趁斜風舞却回。", "可怪今春寒特甚，梅花一半未曾開。"]'),
('12ee8b39-edcb-4fdb-b470-42356100f6a0','正月辛酉大雪三首  其二','仇遠','宋','宋诗','song-poetry','','[]','酒樓柳絮白紛如，带雨隨風密又疏。',32,'全唐诗/poet.song.246000.json','["酒樓柳絮白紛如，带雨隨風密又疏。", "萬景天全羣動息，玉堂人老卧茅廬。"]'),
('4a37a154-42f7-4300-a269-e7c983e19e50','正月辛酉大雪三首  其三','仇遠','宋','宋诗','song-poetry','','[]','從來春雪有人嫌，六出雖工亦漫然。',32,'全唐诗/poet.song.246000.json','["從來春雪有人嫌，六出雖工亦漫然。", "客舍無氈渾可事，爐無薪炭褐無綿。"]'),
('32c3aa06-ccf3-4749-aca9-1b71b77b0e4b','閏正月十三日夜雪','仇遠','宋','宋诗','song-poetry','','[]','東風散雪亂如麻，擲瓦敲窗細撒沙。',32,'全唐诗/poet.song.246000.json','["東風散雪亂如麻，擲瓦敲窗細撒沙。", "只恐市中薪米貴，不愁江上落梅花。"]'),
('fa2cd66d-ec0e-433b-a804-b06716aaa6be','花竹圖','仇遠','宋','宋诗','song-poetry','','[]','梅癯竹潤楚蘭馨，相約凌波作四清。',32,'全唐诗/poet.song.246000.json','["梅癯竹潤楚蘭馨，相約凌波作四清。", "最愛此君秋一片，湘江煙水曉初晴。"]'),
('e56696f0-59a5-4156-bf8d-26b9a6a40119','倦繡圖','仇遠','宋','宋诗','song-poetry','','[]','花殘院靜晝陰長，困思瞢騰下繡床。',32,'全唐诗/poet.song.246000.json','["花殘院靜晝陰長，困思瞢騰下繡床。", "肯信村中蓬鬢女，夜燈辛苦織機忙。"]'),
('a2a645e5-1d5b-44bb-bed2-2ef399997790','書齋壁  其一','仇遠','宋','宋诗','song-poetry','','[]','苔色排簷綠上階，詵詵衿佩集虛齋。',32,'全唐诗/poet.song.246000.json','["苔色排簷綠上階，詵詵衿佩集虛齋。", "耳根厭聽閒風雨，惟有讀書聲最佳。"]'),
('b6e53384-4597-4622-a28c-62ad0084f369','書齋壁  其二','仇遠','宋','宋诗','song-poetry','','[]','風收細雨斷梅天，晝永身閒但欲眠。',32,'全唐诗/poet.song.246000.json','["風收細雨斷梅天，晝永身閒但欲眠。", "木枕桃笙真有味，廣文不用歎無氈。"]'),
('91e3eb1f-d933-4085-94c4-cbe514725e3d','早赴東寺行香','仇遠','宋','宋诗','song-poetry','','[]','衝風冒雨過南橋，馬上聞鐘覺寺遥。',32,'全唐诗/poet.song.246000.json','["衝風冒雨過南橋，馬上聞鐘覺寺遥。", "客髪頓驚秋信早，飛蓬落葉兩蕭蕭。"]'),
('7d88a03f-2684-48f7-9c84-20d836624c9f','喜晴','仇遠','宋','宋诗','song-poetry','','[]','一簾遲日忽開晴，側近園池得散行。',32,'全唐诗/poet.song.246000.json','["一簾遲日忽開晴，側近園池得散行。", "儘勝草堂窮處士，有花有酒作清明。"]'),
('a009173f-2e61-41c1-b082-b35e9deddcef','東郊少步  其一','仇遠','宋','宋诗','song-poetry','','[]','高低遠近樹陰濃，杖屨閒行萬綠中。',32,'全唐诗/poet.song.246000.json','["高低遠近樹陰濃，杖屨閒行萬綠中。", "一片殘紅無覓處，却疑身在碧紗籠。"]'),
('1c3fd5b3-94da-4ebc-aeb2-0b4bcdea1467','東郊少步  其二','仇遠','宋','宋诗','song-poetry','','[]','野風吹樹廟門開，神象凝塵壁擁苔。',32,'全唐诗/poet.song.246000.json','["野風吹樹廟門開，神象凝塵壁擁苔。", "笑爾不能爲禍福，村人誰送紙錢來。"]'),
('acf271e4-393d-41d8-996c-1d21e662de3d','寒食雨三首  其一','仇遠','宋','宋诗','song-poetry','','[]','山色空濛寒食雨，楊花零亂溧陽樓。',32,'全唐诗/poet.song.246000.json','["山色空濛寒食雨，楊花零亂溧陽樓。", "老人豈有傷春事，酒後情懷似感秋。"]'),
('e1751dfc-0b58-4d3f-8cc2-80075ee4c632','寒食雨三首  其二','仇遠','宋','宋诗','song-poetry','','[]','監官州牧趣修圍，里正喧呼急報饑。',32,'全唐诗/poet.song.246000.json','["監官州牧趣修圍，里正喧呼急報饑。", "店舍無烟雞犬靜，山村桃李已空枝。"]'),
('7720fa26-a612-42a2-b9c0-3af429986d29','寒食雨三首  其三','仇遠','宋','宋诗','song-poetry','','[]','梨花白白柳條青，閉閣焚香奈雨聲。',32,'全唐诗/poet.song.246000.json','["梨花白白柳條青，閉閣焚香奈雨聲。", "聞道清明明日是，江南風土只宜晴。"]'),
