('f672cb74-58b4-4c2b-b808-3c39f0d6817c','倚月','仇遠','宋','宋诗','song-poetry','','[]','大江東去月分明，烏鵲南飛露氣清。',32,'全唐诗/poet.song.246000.json','["大江東去月分明，烏鵲南飛露氣清。", "如此嬋娟人不愛，倚樓獨立過三更。"]'),
('c73f74d1-bb29-460a-8b08-4cd810a36d78','月上','仇遠','宋','宋诗','song-poetry','','[]','月到東窗夜正中，人間天上廣寒宮。',32,'全唐诗/poet.song.246000.json','["月到東窗夜正中，人間天上廣寒宮。", "蚊蟲血食三千國，盡被西風一掃空。"]'),
('fa9e8f80-4cf4-45b3-b094-668b11d05971','題煙竹圖','仇遠','宋','宋诗','song-poetry','','[]','楚山晴雨未分明，淡鎖蒼筠曉更清。',32,'全唐诗/poet.song.246000.json','["楚山晴雨未分明，淡鎖蒼筠曉更清。", "渾是一江秋色染，只疑無處著秋聲。"]'),
('3cb39a90-fd5a-44df-b544-94d5455b16e5','憶窊石章氏女子','仇遠','宋','宋诗','song-poetry','','[]','湖樹江雲隔杳冥，千峰萬壑夢中青。',32,'全唐诗/poet.song.246000.json','["湖樹江雲隔杳冥，千峰萬壑夢中青。", "懸知茅屋孤燈下，逐字教兒讀孝經。"]'),
('6acfa30a-fbd9-4d64-899f-8c958dcee51d','題孟浩然圖','仇遠','宋','宋诗','song-poetry','','[]','風吹衿帽不知寒，款段奚奴凍亦頑。',32,'全唐诗/poet.song.246000.json','["風吹衿帽不知寒，款段奚奴凍亦頑。", "縮項鯿魚無可釣，歸鞭遥指鹿門山。"]'),
('03b553ba-e3a7-40cc-bfea-4ed5d0656863','立冬即事二首  其一','仇遠','宋','宋诗','song-poetry','','[]','細雨生寒未有霜，庭前木葉半青黄。',32,'全唐诗/poet.song.246000.json','["細雨生寒未有霜，庭前木葉半青黄。", "小春此去無多日，何處梅花一綻香。"]'),
('88c65ab3-8bab-483c-828e-0d17f3e46ff0','立冬即事二首  其二','仇遠','宋','宋诗','song-poetry','','[]','凄風浩蕩散茶烟，小雨霏微濕座氈。',32,'全唐诗/poet.song.246000.json','["凄風浩蕩散茶烟，小雨霏微濕座氈。", "肯信今年寒信早，老夫布褐未裝綿。"]'),
('d3cf7395-e7cb-4923-8341-369d5508bef7','送客湖橋  其一','仇遠','宋','宋诗','song-poetry','','[]','赤葉岡頭送客行，峰回路轉石橋橫。',32,'全唐诗/poet.song.246000.json','["赤葉岡頭送客行，峰回路轉石橋橫。", "小春天氣晴偏好，禾稼新收麥又耕。"]'),
('60b243db-bff4-469c-8ba6-910d0f8bd543','送客湖橋  其二','仇遠','宋','宋诗','song-poetry','','[]','別酒離歌送馬蹄，歸鞍斜日故遲遲。',32,'全唐诗/poet.song.246000.json','["別酒離歌送馬蹄，歸鞍斜日故遲遲。", "小兒拍手山翁醉，江左風流一晉時。"]'),
('be517db0-7e9b-4c9e-a9fd-7cfdc76aa634','題畫  其一','仇遠','宋','宋诗','song-poetry','','[]','紛紛鷄鶩一冥鴻，全放全收旦暮同。',32,'全唐诗/poet.song.246000.json','["紛紛鷄鶩一冥鴻，全放全收旦暮同。", "各爲稻粱飛不起，偶然相聚小池中。"]'),
('6acae15a-f5fe-4096-8887-7568beb32cc7','題畫  其二','仇遠','宋','宋诗','song-poetry','','[]','天上高飛地上行，終難萬里附鵬程。',32,'全唐诗/poet.song.246000.json','["天上高飛地上行，終難萬里附鵬程。", "鷺鷥股肉無人割，老守菰蒲過一生。"]'),
('65246a57-b310-441a-94c2-45a97bce715c','野籬','仇遠','宋','宋诗','song-poetry','','[]','豆花小白槿花紅，野屋籬門處處同。',32,'全唐诗/poet.song.246000.json','["豆花小白槿花紅，野屋籬門處處同。", "無限春風桃李占，却將顔色媚秋風。"]'),
('d479a899-1eba-4199-981a-6146163c7175','二馬圖','仇遠','宋','宋诗','song-poetry','','[]','平生自比九方臯，牝牡驪黄骨相高。',32,'全唐诗/poet.song.246000.json','["平生自比九方臯，牝牡驪黄骨相高。", "寄語金臺求駿者，精神元不在皮毛。"]'),
('76d13a6f-2eb3-4065-818f-ae8da7e366cd','紀事  其一','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','圩田平沒石田枯，秋暑如蒸雨竟無。',32,'全唐诗/poet.song.246000.json','["圩田平沒石田枯，秋暑如蒸雨竟無。", "六十年前曾記得，步行一直過西湖。"]'),
('d591758d-6ea0-4fab-aaed-3ac94b4368d4','紀事  其二','仇遠','宋','宋诗','song-poetry','','[]','龍君鼎鼎出雲關，分祀仙宮佛剎間。',32,'全唐诗/poet.song.246000.json','["龍君鼎鼎出雲關，分祀仙宮佛剎間。", "兩月更無涓滴雨，問君何日可還山。"]'),
('8d9e12d9-2b81-44dd-a078-d73e6df6d467','紀事  其三','仇遠','宋','宋诗','song-poetry','','[]','柴扉深閉百蟲秋，落葉幽花露未收。',32,'全唐诗/poet.song.246000.json','["柴扉深閉百蟲秋，落葉幽花露未收。", "野僻了無雞報曉，啟明星在樹梢頭。"]'),
('e57305ed-88f9-4f1e-b0fd-6045656db994','馬斃三首  其一','仇遠','宋','宋诗','song-poetry','','[]','曉廄驚呼我馬瘖，塞翁一笑欲何如。',32,'全唐诗/poet.song.246000.json','["曉廄驚呼我馬瘖，塞翁一笑欲何如。", "西郊或有閒迎送，却向東家借蹇馿。"]'),
('e8c83721-d0b0-4821-b02a-bcb95327bf98','馬斃三首  其二','仇遠','宋','宋诗','song-poetry','','[]','苦無馳驟但加餐，馬性由來不耐閒。',32,'全唐诗/poet.song.246000.json','["苦無馳驟但加餐，馬性由來不耐閒。", "官滿馬亡歸去好，且騎白犢看青山。"]'),
('25422582-c13f-4c74-b9db-9bf2cd15f8e7','馬斃三首  其三','仇遠','宋','宋诗','song-poetry','','[]','我無筋力汝難騎，埋汝郊原有敝帷。',32,'全唐诗/poet.song.246000.json','["我無筋力汝難騎，埋汝郊原有敝帷。", "二尺箯輿元自穩，不勞鞭策强驅馳。"]'),
('19f86fd1-0cb6-4b3e-9e12-83d0f2854a37','鄰家曉雞','仇遠','宋','宋诗','song-poetry','','[]','嚴城鼓角送鐘聲，頃刻三更四五更。',32,'全唐诗/poet.song.246000.json','["嚴城鼓角送鐘聲，頃刻三更四五更。", "却是鄰家雞唱準，不差消息已天明。"]'),
('47cbdf0e-3e64-4369-b8c2-f167392c28fa','憶桐廬二女','仇遠','宋','宋诗','song-poetry','','[]','子女生來願有家，耕桑隨分各生涯。',32,'全唐诗/poet.song.246000.json','["子女生來願有家，耕桑隨分各生涯。", "誰知我輩鍾情處，看過桃花看藕花。"]'),
('68b12503-5304-491e-a31d-1ccff72359f3','沖真庵','仇遠','宋','宋诗','song-poetry','','[]','洞房深鎖老雙成，門徑幽修石沼清。',32,'全唐诗/poet.song.246000.json','["洞房深鎖老雙成，門徑幽修石沼清。", "萬紫千紅秋已盡，眼中黄菊最分明。"]'),
('a48cba6d-f204-4805-840f-8c7975b3155e','落桂','仇遠','宋','宋诗','song-poetry','','[]','養成花魄是輕陰，風露凄凄已滿林。',32,'全唐诗/poet.song.246000.json','["養成花魄是輕陰，風露凄凄已滿林。", "到底難磨秋富貴，一庭香粟萬黄金。"]'),
('69f20832-887f-4635-87b7-a8d4438a5343','冬夜和陳道士韻  其一','仇遠','宋','宋诗','song-poetry','','[]','焚香讀易樂閒居，參訂先天太極圖。',32,'全唐诗/poet.song.246000.json','["焚香讀易樂閒居，參訂先天太極圖。", "人道三分程氏傳，較他漢上有差殊。"]'),
('2cc588fc-9e10-42e4-aaf6-0834069325b9','冬夜和陳道士韻  其二','仇遠','宋','宋诗','song-poetry','','[]','聞道孤根暖已回，扶筇携酒出山來。',32,'全唐诗/poet.song.246000.json','["聞道孤根暖已回，扶筇携酒出山來。", "數花羞澀西坡上，也當春風一度開。"]'),
('a775d45e-b7dd-46fa-8b49-edd8e6eee1d8','冬夜和陳道士韻  其三','仇遠','宋','宋诗','song-poetry','','[]','石銚溪芽活火烹，旋燒敗葉带枯藤。',32,'全唐诗/poet.song.246000.json','["石銚溪芽活火烹，旋燒敗葉带枯藤。", "路遥難遞中𤃩水，且試梅花澗底冰。"]'),
('3ed61f26-84ad-46d7-ba67-c92df00cbe1d','冬夜和陳道士韻  其四','仇遠','宋','宋诗','song-poetry','','[]','三白先春慰客情，瑶林照耀夜窗明。',32,'全唐诗/poet.song.246000.json','["三白先春慰客情，瑶林照耀夜窗明。", "淺斟低唱癡兒女，那得工夫問雪聲。"]'),
('ad377960-ad0a-4fef-8d33-6a55bce96b3e','多雨','仇遠','宋','宋诗','song-poetry','','[]','菜色青肥麥漸黄，雨多泥滑野畦荒。',32,'全唐诗/poet.song.246000.json','["菜色青肥麥漸黄，雨多泥滑野畦荒。", "官田昨夜方車水，早起看來又渺茫。"]'),
('d9f6e628-8778-4a8d-9da6-e8949dbf41e0','自嘆','仇遠','宋','宋诗','song-poetry','','[]','休言五十九年非，本自無知底用疑。',32,'全唐诗/poet.song.246000.json','["休言五十九年非，本自無知底用疑。", "已往方來俱夢境，是非元不較毫釐。"]'),
('90887bc6-543f-44f3-8227-9cfa85c79627','言懷  其一','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','辛苦移家向溧州，微官祗爲斗升謀。',32,'全唐诗/poet.song.246000.json','["辛苦移家向溧州，微官祗爲斗升謀。", "尋思終是西湖好，且與山僧野老遊。"]'),
('f29b9115-867e-45b8-8106-b16cc7d846d4','言懷  其二','仇遠','宋','宋诗','song-poetry','','[]','奉溪半日到杭城，溪外青山喜送迎。',32,'全唐诗/poet.song.246000.json','["奉溪半日到杭城，溪外青山喜送迎。", "結屋臨溪差易事，買山無計若爲情。"]'),
('c8a77388-1e39-41f3-bdb8-8c88b30b0bbf','言懷  其三','仇遠','宋','宋诗','song-poetry','','[]','湖光門外草連空，萬壑千崖紫翠叢。',32,'全唐诗/poet.song.246000.json','["湖光門外草連空，萬壑千崖紫翠叢。", "縱未便能營隠墅，也須先畫作屏風。"]'),
('75c79fda-09c3-40b3-921a-67424b49ca2d','言懷  其四','仇遠','宋','宋诗','song-poetry','','[]','白嶺溪上野田平，黄隴山前竹樹清。',32,'全唐诗/poet.song.246000.json','["白嶺溪上野田平，黄隴山前竹樹清。", "已許數椽容小住，餘英愛我愛餘英。"]'),
('c2398ffa-f588-4bf9-83ca-5fcf62b4b881','言懷  其五','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','故家喬木盡丘墟，筍石猶存十數株。',32,'全唐诗/poet.song.246000.json','["故家喬木盡丘墟，筍石猶存十數株。", "誰有挾山超海力，爲分雲片過西湖。"]'),
('787ad486-d121-43e2-95f1-9b570383b907','言懷  其六','仇遠','宋','宋诗','song-poetry','','[]','此地曾經李白遊，湖山消得好詩留。',32,'全唐诗/poet.song.246000.json','["此地曾經李白遊，湖山消得好詩留。", "兩橋十里東西市，只欠春風一酒樓。"]'),
('4e2bcbd9-cfee-4c80-b12b-1cac6269709b','言懷  其七','仇遠','宋','宋诗','song-poetry','','[]','溧尉唐時本小官，詩人爭笑孟酸寒。',32,'全唐诗/poet.song.246000.json','["溧尉唐時本小官，詩人爭笑孟酸寒。", "我來莫道儒官冷，今古酸寒只一般。"]'),
('7dbee066-19c8-4c06-ad88-a6627b13145d','言懷  其八','仇遠','宋','宋诗','song-poetry','','[]','隔岸修筠拂細瀾，風香雨色晝陰寒。',32,'全唐诗/poet.song.246000.json','["隔岸修筠拂細瀾，風香雨色晝陰寒。", "遥知新買栖霞地，坡上應添竹數竿。"]'),
('d85bf7c0-bc0d-4c31-901c-d79e90e99263','言懷  其九','仇遠','宋','宋诗','song-poetry','','[]','馬蹄赤日走紅塵，汗濕林宗折角巾。',32,'全唐诗/poet.song.246000.json','["馬蹄赤日走紅塵，汗濕林宗折角巾。", "輸與夷山班博士，深衣脫却作閑人。"]'),
('6fc1c47d-2490-43fa-8799-029ba71cb48f','采薇吟','仇遠','宋','宋诗','song-poetry','','[]','采薇采薇，西山之西。',30,'全唐诗/poet.song.246000.json','["采薇采薇，西山之西。", "薇死復生，不生夷齊。", "陟彼西山，我心悲兮。"]'),
('3acd57f6-128f-447d-84e4-72b05f1474e8','步出上東門','仇遠','宋','宋诗','song-poetry','','[]','步出上東門，肺肺東門柳。',84,'全唐诗/poet.song.246000.json','["步出上東門，肺肺東門柳。", "彼美窈窕娘，惜爲蕩子婦。", "中堂裁衣裳，刀尺常在手。", "之子未歸家，何以奉箕帚。", "爲君長相思，躑躅歲云久。", "思君頭易白，惜無百年壽。", "誰能學仙人，辟穀但飲酒。"]'),
('57a3b4d9-9130-4342-b271-904b161d3675','素月出東嶺','仇遠','宋','宋诗','song-poetry','','[]','素月出東嶺，照我白玉牀。',84,'全唐诗/poet.song.246000.json','["素月出東嶺，照我白玉牀。", "牀上何所有，纍纍書一囊。", "詰曲科斗文，讀之不成章。", "君車自翱翔，駕景朝紫皇。", "蒼苔滿石匣，瑶書空秘藏。", "仙人百尺臺，吹竹引鳳凰。", "鳳兮來不來，虛此明月光。"]'),
('a4473df0-4a13-45a2-b36d-b2fffa197354','雜畫','仇遠','宋','宋诗','song-poetry','','[]','東風吹寒晴，春事歸花柳。',72,'全唐诗/poet.song.246000.json','["東風吹寒晴，春事歸花柳。", "既有杖頭錢，何苦不飲酒。", "嗟嗟王孫去，芳草入戶牖。", "惟有南山高，曉霧亦白首。", "去年秉燭游，知有今日否。", "所以晉名流，酒杯不去手。"]'),
('4d3c47de-0247-4575-ad6b-a87ed30961a3','窗下','仇遠','宋','宋诗','song-poetry','','[]','黄昏忽上雲，西窗竟無月。',48,'全唐诗/poet.song.246000.json','["黄昏忽上雲，西窗竟無月。", "燭花自盈枝，可玩不可折。", "天風吹鐘聲，急急吹燭滅。", "可惜窗下書，少讀三四葉。"]'),
('c84e6b4e-2da6-4eb6-918a-9b70b3b6c515','紀夢','仇遠','宋','宋诗','song-poetry','','[]','安翔紫雲軿，游盼璚仙家。',36,'全唐诗/poet.song.246000.json','["安翔紫雲軿，游盼璚仙家。", "斜陽射巖谷，眩目皆丹砂。", "娃鬟挾鸞尾，倦埽菖蒲花。"]'),
('eb2bfff2-6457-4590-9700-dce650a54513','相隨曲','仇遠','宋','宋诗','song-poetry','','[]','腸結錐可解，眉皺熨可伸。',84,'全唐诗/poet.song.246000.json','["腸結錐可解，眉皺熨可伸。", "獨不禁子規，日日啼春心。", "春風醉行客，門外芳草深。", "芳草已無路，行行又何處。", "東園花柳多，賤妾不復顧。", "秋胡夫不夫，買臣婦不婦。", "人心匪金石，悔不隨郎去。"]'),
('a59235c8-a749-4235-abc1-ba1eee043518','題高房山寫山村圖卷','仇遠','宋','宋诗','song-poetry','','[]','我家仇山陽，昔有數椽屋。',120,'全唐诗/poet.song.246000.json','["我家仇山陽，昔有數椽屋。", "誤落塵市間，讀書學干祿。", "井枯竈烟絕，况復問松菊。", "如此五十年，一出不可復。", "高侯丘壑胸，知我志幽獨。", "爲寫隠居圖，寒溪入空谷。", "蒼石壓危構，白雲養喬木。", "向來仇池夢，歷歷在我目。", "何哉草堂資，政爾飯不足。", "視我舌尚存，吾居有時卜。"]'),
('8144aee1-913a-4849-90c6-6790d03df5df','春風謠','仇遠','宋','宋诗','song-poetry','','[]','春風吹柳枝，柳枝拂短牆。',56,'全唐诗/poet.song.246000.json','["春風吹柳枝，柳枝拂短牆。", "春風吹桃葉，桃葉浮烟江。", "春風薄情不可當，鳴鳩乳燕相頡頏。", "春日長，春夜短，雪花撲帳春不暖。"]'),
('0d0deb45-c334-4064-bc1b-22e25d70043a','秋日曲','仇遠','宋','宋诗','song-poetry','','[]','秋風悲，梧桐知不知。',54,'全唐诗/poet.song.246000.json','["秋風悲，梧桐知不知。", "渴虹挾雨吸河漢，嘹嘹數雁天四垂。", "雁急不成字，遠向瀟湘飛。", "銅盤露下夜如水，宋玉新自巫山歸。"]'),
('a08ed4ed-9054-4c9f-aae2-6c38d5d0c269','巴東西','仇遠','宋','宋诗','song-poetry','','[]','巴東有杜鵑，杜鵑啼春花正妍。',52,'全唐诗/poet.song.246000.json','["巴東有杜鵑，杜鵑啼春花正妍。", "巴西有杜鵑，杜鵑啼血花可憐。", "巴東巴西久爲客，目斷江南歸未得，月明滿地山花白。"]'),
('8634a831-42e5-4318-a53b-bdb31c8ec592','聽杜將軍帳下兒歌  其一','仇遠','宋','宋诗','song-poetry','','[]','桓將軍，軍城南。',32,'全唐诗/poet.song.246000.json','["桓將軍，軍城南。", "牛將軍，軍城北。", "他軍只有八千人，卒急臨洮攻未得。"]'),
('cdc39e3b-a080-4607-94d5-52f237c45f1c','聽杜將軍帳下兒歌  其二','仇遠','宋','宋诗','song-poetry','','[]','鞾尖蹴城城未頹，馬箠填河河未滿。',32,'全唐诗/poet.song.246000.json','["鞾尖蹴城城未頹，馬箠填河河未滿。", "十歲健兒下馬行，兩足胡爲自長短。"]'),
('42ce124b-cb56-47f3-9542-f56e95b8c54f','聽杜將軍帳下兒歌  其三','仇遠','宋','宋诗','song-poetry','','[]','什什伍伍金人降，將軍忍殺令歸鄉。',32,'全唐诗/poet.song.246000.json','["什什伍伍金人降，將軍忍殺令歸鄉。", "歸時說與汝郎長，納土封汝異姓王。"]'),
('f2b180b3-ea98-401b-8f76-20e785d9e121','葛雄女子舞劍歌','仇遠','宋','宋诗','song-poetry','','[]','葛家女兒十四五，不向深閨學針縷。',176,'全唐诗/poet.song.246000.json','["葛家女兒十四五，不向深閨學針縷。", "遍身繡出蛟螭文，赤手交持太阿舞。", "紅羅帕兮錦纏頭，口吐長安游俠語。", "側身捷如飛鳥輕，嗔目勇如獨鶻舉。", "雲窗霧閣豈無情，終欠嬌嬈太麤武。", "黄堂張燕燈燭光，兩耳喧喧厭歌鼓。", "人言葛氏善舞劍，曾向梨園奉尊俎。", "短衣結束當筵呈，壯士增雄懦夫沮。", "我憐健婦勝丈夫，却欲驕兵如處女。", "安得成軍如娘子，直氣端能捷秦楚。", "只愁逢著裴將軍，公孫大娘汗成雨。"]'),
('c9b24668-e7f4-40df-9b75-079ed8142fa6','海上圖澄江仙刻','仇遠','宋','宋诗','song-poetry','','[]','老仙指甲堅如鐵，夜畫枯杉出宮闕。',128,'全唐诗/poet.song.246000.json','["老仙指甲堅如鐵，夜畫枯杉出宮闕。", "翠深紅遠十二樓，猶理霓裳舞迴雪。", "山椒覆亭小於笠，石脚插船輕似葉。", "桃花幾度春酣酣，弱水何日通舟楫。", "醉中作此狡獪事，收拾乾坤入毫髪。", "神刓鬼刻未百年，不與丹青共磨滅。", "天風頡頏飛霞珮，水雲妥帖凌波襪。", "我將就此逍遥遊，高步青霄拾明月。"]'),
('e167e563-2358-43b0-9f33-95db114db34a','題石民瞻畫鶴溪圖','仇遠','宋','宋诗','song-poetry','','[]','鶴溪近與練湖連，一境秋水清無邊。',64,'全唐诗/poet.song.246000.json','["鶴溪近與練湖連，一境秋水清無邊。", "依稀淮岸瀟湘浦，慣見月虹書畫船。", "山翁幾年吳下客，溪草溪花未相識。", "筆床茶竈老玄真，肯與沙鷗分半席。"]'),
('799b8940-16b8-4281-89f8-aca076738b34','贈張玉田','仇遠','宋','宋诗','song-poetry','','["\u592a\u6e56"]','秦川公子謫仙人，布袍落魄餘一身。',128,'全唐诗/poet.song.246000.json','["秦川公子謫仙人，布袍落魄餘一身。", "錦囊香歇玉簫斷，庾郎白髪徒傷春。", "金臺掉頭不肯住，欲把釣竿東海去。", "故鄉入夢忽歸來，井邑依依鐵爐步。", "碧池槐葉玄都桃，眼空舊雨秋蕭颾。", "太湖風月數萬頃，扁舟乘興尋三高。", "西北高樓一杯酒，與子長歌折楊柳。", "江山信美盍便留，蓴菜鱸魚隨處有。"]'),
('caf4935c-aff8-46ee-aeba-3ce421e1f8e9','圓通峰頂','仇遠','宋','宋诗','song-poetry','','[]','結亭孤絕處，登眺不辭勞。',48,'全唐诗/poet.song.246000.json','["結亭孤絕處，登眺不辭勞。", "萬木俯在下，一峰如此高。", "山圍湖面小，藤絡樹根牢。", "揮手紅塵表，天風欲跨鼇。"]'),
('8c2b6422-03a9-427c-99cc-1f1028f5a0db','雪花','仇遠','宋','宋诗','song-poetry','','[]','仙人初翦水，欲下復遲遲。',48,'全唐诗/poet.song.246000.json','["仙人初翦水，欲下復遲遲。", "半夜忽自落，東風竟不知。", "無香黏客袖，有意補春枝。", "却憶江南柳，飄緜送子時。"]'),
('dc800b6b-3081-40e1-af93-c52ebb36eecb','渡越','仇遠','宋','宋诗','song-poetry','','[]','蒼烟迷古道，白水滿平疇。',48,'全唐诗/poet.song.246000.json','["蒼烟迷古道，白水滿平疇。", "落雁湘湖月，孤砧粵樹秋。", "壯心消蠟屐，老淚入貂裘。", "市飲成淒斷，何人識馬周。"]'),
('0e1e6ca1-b7ab-4630-8533-f91ceb401f98','韶華','仇遠','宋','宋诗','song-poetry','','[]','韶華已如此，冉冉積芳塵。',48,'全唐诗/poet.song.246000.json','["韶華已如此，冉冉積芳塵。", "石潤先知雨，山濃渾是春。", "釣魚臨積水，隔柳見行人。", "應有忘歸者，扁舟採白蘋。"]'),
('2a05388d-dffa-46e8-a2e8-46551f7f4279','和曹之才','仇遠','宋','宋诗','song-poetry','','[]','山林不可住，欲隠更何之。',48,'全唐诗/poet.song.246000.json','["山林不可住，欲隠更何之。", "春去已多日，客愁無了時。", "斜陽依樹下，明月到門遲。", "閒事誰消遣，陶潜一卷詩。"]'),
('9b284fb2-feb0-4cff-aa95-17232b54deec','鎮海亭','仇遠','宋','宋诗','song-poetry','','[]','海塘三十里，此屋獨巍然。',48,'全唐诗/poet.song.246000.json','["海塘三十里，此屋獨巍然。", "有浪方知水，無雲總是天。", "苔痕封石柱，帆影下樓船。", "閒憶童男女，悠悠去幾年。"]'),
('7b7557a5-dbb7-4ff5-80ac-eb08a49b5ce5','寄潘懷古','仇遠','宋','宋诗','song-poetry','','[]','園林摇落夜，靜獨奈秋何。',48,'全唐诗/poet.song.246000.json','["園林摇落夜，靜獨奈秋何。", "黄葉下不止，青苔埽更多。", "回風喧地籟，濃露洗天河。", "懷楚思無極，長簫按九歌。"]'),
('b37b9378-943e-4207-b6c7-b7056bbdd328','石窗','仇遠','宋','宋诗','song-poetry','','[]','玲瓏千丈崖，高處倚蓬萊。',48,'全唐诗/poet.song.246000.json','["玲瓏千丈崖，高處倚蓬萊。", "山月照得白，天風吹不開。", "渴龍棲古井，病鶴下蒼苔。", "祇有麻衣叟，時時把易來。"]'),
('ec71f73b-d20a-4efa-ae7b-01df945dadbc','爲如鏡淨上人賦','仇遠','宋','宋诗','song-poetry','','[]','一片靈臺月，圓明適中規。',48,'全唐诗/poet.song.246000.json','["一片靈臺月，圓明適中規。", "誰知相對者，曾悟未磨時。", "去垢元來淨，觀空了不疑。", "水邊閒獨立，照見白鬚眉。"]'),
('f025422a-0fba-4abb-8ba9-34185088a646','寄題如鏡上人房','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吳城久卜居，歸夢只西湖。',48,'全唐诗/poet.song.246000.json','["吳城久卜居，歸夢只西湖。", "花木四時有，塵埃一點無。", "看經常戒酒，得句少催租。", "盡日坐相對，壁間蓮社圖。"]'),
('7068d984-944d-415d-a947-69d6c389e983','錦城方天瑞玄英先生後人得白雲山居圖彷彿桐廬山中隠所錢舜舉真蹟別有一種風致漫系以詩','仇遠','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','翼翼山千朵，蕭蕭屋數間。',48,'全唐诗/poet.song.246000.json','["翼翼山千朵，蕭蕭屋數間。", "石崖不可度，門徑幾曾關。", "綠樹經秋在，白雲終日閒。", "依稀鏡湖曲，西島水迴環。"]'),
('6dced7cf-cc07-4434-8bf6-5b6273ed2d65','陸君實挽詩','仇遠','宋','宋诗','song-poetry','','[]','乾坤那可問，至痛老臣心。',48,'全唐诗/poet.song.246000.json','["乾坤那可問，至痛老臣心。", "甘抱白日沒，不知滄海深。", "忠魂隨上下，義骨肯浮沈。", "草木長淮淚，秋風起莫陰。"]'),
('aa9f9f85-ca36-4dfc-ae37-2a03a92ccb98','約山中友','仇遠','宋','宋诗','song-poetry','','[]','望極秋空無片雲，前山歷歷見遥岑。',64,'全唐诗/poet.song.246000.json','["望極秋空無片雲，前山歷歷見遥岑。", "新鴻漸到邊城靜，舊雨不來汀草深。", "仙李有時曾入夢，伯桃死後少知心。", "如君真是忘機者，海上鷗盟便可尋。"]'),
('10c7dc48-ba44-4a5f-8d7c-0e9ce38604ef','寄朱飲冰','仇遠','宋','宋诗','song-poetry','','[]','欲共譚詩一解頤，停雲望極思依依。',64,'全唐诗/poet.song.246000.json','["欲共譚詩一解頤，停雲望極思依依。", "梅花賦就廣平老，楊柳門間靖節歸。", "驛路數程征馬瘦，家書千里過鴻稀。", "思君怕倚闌干北，拄笏看山竟落暉。"]'),
('ef5d30ee-cfa5-41c5-8460-cc75bf4757a0','北窗','仇遠','宋','宋诗','song-poetry','','[]','北窗隠几樂吾天，莫遣新愁到耳邊。',64,'全唐诗/poet.song.246000.json','["北窗隠几樂吾天，莫遣新愁到耳邊。", "一帽好花供醉舞，半床凉月伴閑眠。", "故人自欲辭文叔，明主何嘗棄浩然。", "留取長安遮日手，養成指甲理朱絃。"]'),
('2a03e2c3-1bf2-487e-b01d-5970f766f5c1','拜霞嶼待制伯祖墓下','仇遠','宋','宋诗','song-poetry','','[]','難尋華表與豐碑，三尺墳臺山四圍。',64,'全唐诗/poet.song.246000.json','["難尋華表與豐碑，三尺墳臺山四圍。", "翁仲多年蒼珮剝，子孫寒食紙錢稀。", "瘦藤拔地長蛇走，灌木維垣野鼠肥。", "遠也久違鄉族去，忍將椒酒酹斜暉。"]'),
('77cfdf6c-4848-4711-af36-b56169df3fec','高卧','仇遠','宋','宋诗','song-poetry','','[]','人生天地一蘧廬，耕鑿雖勞樂有餘。',64,'全唐诗/poet.song.246000.json','["人生天地一蘧廬，耕鑿雖勞樂有餘。", "因閲杜詩刪舊稿，爲觀羲帖學行書。", "山公醉後猶騎馬，渭叟閒來只釣魚。", "世道秋風總蕭索，何如高卧白雲居。"]'),
('d3ee085d-195c-40fa-b04c-8e4c499543fc','雨餘','仇遠','宋','宋诗','song-poetry','','[]','兩兩鳴鳩語畫檐，雨餘芳草欲生烟。',64,'全唐诗/poet.song.246000.json','["兩兩鳴鳩語畫檐，雨餘芳草欲生烟。", "甕頭酒熟常留客，象外詩成頗類仙。", "揚子有才猶執戟，淵明無事合歸田。", "地偏時事人傳少，收拾琴書且醉眠。"]'),
('7fd7246c-b3b9-461f-bbf0-43b1f1cec4ce','元友山南山新居  其一','仇遠','宋','宋诗','song-poetry','','[]','桃柳參差出短牆，小樓突兀看湖光。',64,'全唐诗/poet.song.246000.json','["桃柳參差出短牆，小樓突兀看湖光。", "出門便與青山對，讀易能消白日長。", "硯石洗來如玉潤，藥苗曬得似茶香。", "鄰僧亦有通文者，常把詩來惱漫郎。"]'),
('9190e3e8-23b3-412f-9294-1d8afc72947d','元友山南山新居  其二','仇遠','宋','宋诗','song-poetry','','[]','幽居穩占南山下，人跡稀疏水竹村。',64,'全唐诗/poet.song.246000.json','["幽居穩占南山下，人跡稀疏水竹村。", "轉巷始知猶有路，傍湖更好別開門。", "酒尊盡日嘗謀婦，詩課閒時略抱孫。", "孤鶴不來高士少，暗香且伴月黄昏。"]'),
('a5b8a3ea-730f-43bd-afb3-9c8cb4323639','答胡葦杭','仇遠','宋','宋诗','song-poetry','','[]','久矣相期物外游，長風吹不斷閑愁。',64,'全唐诗/poet.song.246000.json','["久矣相期物外游，長風吹不斷閑愁。", "兩山翼翼青如舞，霜鬢颾颾白始休。", "蕉鹿夢回天地枕，蓴鱸興到水雲舟。", "舊藏方鏡明如月，看去看來又一秋。"]'),
('011a4c0c-9d0a-474a-81fa-0d15733d2d41','次胡葦杭韻','仇遠','宋','宋诗','song-poetry','','[]','曾識清明上巳時，嬾能游冶步芳菲。',64,'全唐诗/poet.song.246000.json','["曾識清明上巳時，嬾能游冶步芳菲。", "梨花半落雨初過，杜宇不鳴春自歸。", "雙冢年深人祭少，孤山日晚客來稀。", "江南尚有餘寒在，莫倚東風褪絮衣。"]'),
('cff2bb8f-b5d6-4c51-a1f4-27a675fc9fac','送王仙麓使君赴道州暫歸三山','仇遠','宋','宋诗','song-poetry','','[]','家山小爲離支留，征斾催行莫待秋。',64,'全唐诗/poet.song.246000.json','["家山小爲離支留，征斾催行莫待秋。", "應有矮奴騎竹馬，相隨迓吏拜蘭舟。", "舜山如畫當樓見，楚水浮香遶郡流。", "念我有親頭雪白，雲龍追逐恨無由。"]'),
('91e5a1b9-3d44-4f5e-83ce-a6c5a066aa9c','奉寄田上人','仇遠','宋','宋诗','song-poetry','','[]','竹筇輕健草鞋寬，野外消磨半日閒。',64,'全唐诗/poet.song.246000.json','["竹筇輕健草鞋寬，野外消磨半日閒。", "病葉已霜猶戀樹，片雲欲雨又歸山。", "燈分寺塔晴偏見，水隔漁家夜不關。", "愧我莫如霜上鷺，霎時飛去便飛還。"]'),
('0110b0f6-cc63-4d04-99c9-e5f88ce02675','閻氏園池','仇遠','宋','宋诗','song-poetry','','[]','真妃已返鳳臺仙，獨立池亭思愴然。',64,'全唐诗/poet.song.246000.json','["真妃已返鳳臺仙，獨立池亭思愴然。", "海岳不傳青鳥信，石房誰伴白雲眠。", "宮桃移種難生實，院籜初翻又引鞭。", "凝碧荒凉絃管靜，萍花浮滿釣魚船。"]'),
('6e975163-fb46-43fe-be1f-9e1b2b0f2ab0','江上送友','仇遠','宋','宋诗','song-poetry','','[]','知爾懷親憶故州，相逢沽酒且遲留。',64,'全唐诗/poet.song.246000.json','["知爾懷親憶故州，相逢沽酒且遲留。", "夕陽有恨荒荒白，江水無聲泯泯流。", "孤鳥出潮投渚尾，野蘆飛雪壓船頭。", "却愁明月中秋近，不得同登庾亮樓。"]'),
('005feebf-de50-4542-8a14-9c74d6f7851d','送劉竹間歸廬陵','仇遠','宋','宋诗','song-poetry','','[]','驛路梅花漠漠寒，羢衫絮帽出長安。',64,'全唐诗/poet.song.246000.json','["驛路梅花漠漠寒，羢衫絮帽出長安。", "懸知客久歸心切，自覺交深別語難。", "春入西江隨馬去，山留殘雪待人看。", "青原白鷺如相問，十載湖濱只釣竿。"]'),
('dc0f8438-d2cc-4b76-95d2-262fd4f408c5','道場山','仇遠','宋','宋诗','song-poetry','','[]','山行龜背路羊腸，伏虎禪師古道場。',64,'全唐诗/poet.song.246000.json','["山行龜背路羊腸，伏虎禪師古道場。", "老木陰中安御座，白雲堆裏撫僧床。", "勺泉清澈涵秋味，尖塔孤撐界夕陽。", "笑月亭空人影散，松風和雨動天簧。"]'),
('c26a4c2e-f9c7-433b-bbcf-e535b9680259','何山','仇遠','宋','宋诗','song-poetry','','[]','溪轉峰回一徑平，田頭白水照人清。',64,'全唐诗/poet.song.246000.json','["溪轉峰回一徑平，田頭白水照人清。", "寺因何氏封山姓，客把坡詩證地名。", "蘿月長隨行道影，杉風猶带讀書聲。", "雲津橋下潺湲急，僧濯袈裟客濯纓。"]'),
('17773eb9-524a-4a98-b385-f196506a5065','新安郡圃','仇遠','宋','宋诗','song-poetry','','[]','亭榭凌空眼界寬，得閑來處獨憑闌。',64,'全唐诗/poet.song.246000.json','["亭榭凌空眼界寬，得閑來處獨憑闌。", "春浮練水蒸城潤，雪被黄山入座寒。", "古樹巢空羣鳥散，荒池沙滿碎薸乾。", "白雲在望歸期定，不見青油護牡丹。"]'),
('762158ba-0795-4579-857a-964d4b2df0ec','拜孫花翁墓下','仇遠','宋','宋诗','song-poetry','','[]','水仙分地葬詩人，一片荒山野火焚。',64,'全唐诗/poet.song.246000.json','["水仙分地葬詩人，一片荒山野火焚。", "薦菊有亭今作圃，埽松無地漫留墳。", "蝸牛負殻黏碑石，老鸛携雛入隴雲。", "欲把長簫歌楚些，却憐度曲不如君。"]'),
('01539494-0964-40e0-9484-7106efa2c07c','兵間有歌舞者','仇遠','宋','宋诗','song-poetry','','[]','邊城未定苦無謀，年少金多絕不憂。',64,'全唐诗/poet.song.246000.json','["邊城未定苦無謀，年少金多絕不憂。", "野戰已酣紅帕首，塗歌猶醉錦纏頭。", "蛾貪銀燭那知死，月戀金尊不照愁。", "亦欲避秦高隠去，桃花源上覓漁舟。"]'),
('4da73b04-5b40-45b1-8c4c-f36ec1237715','寄董無益','仇遠','宋','宋诗','song-poetry','','[]','郵鈴带箭髪紛紛，何日山深耳不聞。',64,'全唐诗/poet.song.246000.json','["郵鈴带箭髪紛紛，何日山深耳不聞。", "遷客無鄉難避禍，饑民失業半充軍。", "馬蹄亂踏湖西雪，雁陣平拖塞北雲。", "我亦嬾談今世事，自看弔古戰場文。"]'),
('f0b8804b-3de7-44b3-8b74-40469e64bf07','題小閣','仇遠','宋','宋诗','song-poetry','','[]','斲窗黏紙著方床，四面虛明取向陽。',64,'全唐诗/poet.song.246000.json','["斲窗黏紙著方床，四面虛明取向陽。", "氈席坐來終日暖，皮簾揭動北風凉。", "挂缾水滿梅花活，折鼎湯鳴芋子香。", "布被蒙頭晝眠熟，不知門外雪洋洋。"]'),
('9e267fa1-aafa-4135-a365-93013f52541f','董靜傳挂冠四聖觀','仇遠','宋','宋诗','song-poetry','','[]','靜挼秋淥洗荷衣，問隠孤山隻鶴隨。',64,'全唐诗/poet.song.246000.json','["靜挼秋淥洗荷衣，問隠孤山隻鶴隨。", "得酒可謀千日醉，挂冠猶恨十年遲。", "雲和家有仙人譜，石鼎今無道士詩。", "莫對梅花談世事，此花曾見太平時。"]'),
('086856e3-c80f-4f96-90f5-9853431ec266','劉悅心入道三茅觀','仇遠','宋','宋诗','song-poetry','','[]','鶡冠高挂九松巔，去結三茅香火緣。',64,'全唐诗/poet.song.246000.json','["鶡冠高挂九松巔，去結三茅香火緣。", "相國向猶爲道士，將門今又出神仙。", "坐看紅日生滄島，吟寄青衣入洞天。", "跨鶴歸來雲舍近，西風井邑只依然。"]'),
('fa494008-fd03-4854-a89f-fa5afd3c1779','同楊心卿過孤山訪靜傳不遇自游和靖祠下明日奉寄二高士','仇遠','宋','宋诗','song-poetry','','[]','飛仙又向別峰游，竹下閒房且小留。',64,'全唐诗/poet.song.246000.json','["飛仙又向別峰游，竹下閒房且小留。", "滿鬢朔風吹客帽，倚闌落日在漁舟。", "梅花路冷難尋冢，葑草田荒半作洲。", "獨往獨來沙鳥怪，山空木短使人愁。"]'),
('a56d61bb-1c5e-4ad4-86c1-1eef9765c689','酬鄧山房尊師','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山房閒伴白雲棲，琴不須彈聽者稀。',64,'全唐诗/poet.song.246000.json','["山房閒伴白雲棲，琴不須彈聽者稀。", "北道主人新拜號，西湖隠士舊傳衣。", "粵亡未合鴟夷去，蜀遠難隨杜宇歸。", "亦欲共君聯石鼎，龍頭豕腹怕相譏。"]'),
('b6cd4566-ee63-4ebc-8a63-e3fde58a4543','不應聘高士','仇遠','宋','宋诗','song-poetry','','[]','束書入谷起徵君，盥耳淵棲似不聞。',64,'全唐诗/poet.song.246000.json','["束書入谷起徵君，盥耳淵棲似不聞。", "知有故人來問字，喜無逋客爲移文。", "忍貧羞說黄金盡，愛老慵將白髪芸。", "獨倚高樓南北望，青天依舊有閒雲。"]'),
('4f1a4c2d-6cc8-411f-a1d4-3ccdbe4c48d6','懷古','仇遠','宋','宋诗','song-poetry','','[]','吹殺青燈炯不眠，滿衿懷古恨緜緜。',64,'全唐诗/poet.song.246000.json','["吹殺青燈炯不眠，滿衿懷古恨緜緜。", "江東曾識桓司馬，滄海難追魯仲連。", "吳岫月明吟木客，漢宮露冷泣銅仙。", "何時一酌桃源酒，醉倒春風數百年。"]'),
('84e50985-090d-44f3-8fd2-359d441b10db','和范愛竹三首  其一','仇遠','宋','宋诗','song-poetry','','[]','半生豪氣學元龍，湖海惟知敬數公。',64,'全唐诗/poet.song.246000.json','["半生豪氣學元龍，湖海惟知敬數公。", "徒有貞心招隠逸，恨無巨眼識英雄。", "天衢騎馬衣冠異，雨屋鳴雞杼軸空。", "西崦東屯何日了，定應愁老浣花翁。"]'),
('9cb2224e-be4e-4d9a-8ff5-a19a89bda02c','和范愛竹三首  其二','仇遠','宋','宋诗','song-poetry','','[]','秉燭追游憶盛時，歡悰終較昔年稀。',64,'全唐诗/poet.song.246000.json','["秉燭追游憶盛時，歡悰終較昔年稀。", "柳多客折凉陰薄，薇少人餐雨綠肥。", "胡蝶覺來方識夢，海鷗飛去未忘機。", "相逢且可談風月，莫話興亡與是非。"]'),
('f5b40a81-3f17-41ab-842b-17f8e6f8a55a','和范愛竹三首  其三','仇遠','宋','宋诗','song-poetry','','[]','風雨蕭蕭白晝昏，肅襟受此一凉恩。',64,'全唐诗/poet.song.246000.json','["風雨蕭蕭白晝昏，肅襟受此一凉恩。", "丘園不作軒裳夢，陵谷空遺斧鑿痕。", "乍可扣舷歌楚澤，何堪抱瑟立齊門。", "有時散步西原上，共醉田家老瓦盆。"]'),
('98ea2054-f9d2-431e-bad9-20ff0e6f331f','問趙元父病','仇遠','宋','宋诗','song-poetry','','[]','裹飯無因絕往還，惟應帖子報平安。',64,'全唐诗/poet.song.246000.json','["裹飯無因絕往還，惟應帖子報平安。", "山公馬向花前放，岐伯書從枕上看。", "貿易近來多北藥，支持强欲著南冠。", "有時泥醉西園月，只欠梅花共倚闌。"]'),
('b6419b07-d210-4f41-84c3-3104c552dfd6','贈金蓀壁','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黄紙紅旗事已休，莫思入谷有鳴騶。',64,'全唐诗/poet.song.246000.json','["黄紙紅旗事已休，莫思入谷有鳴騶。", "天開東壁圖書府，人立西湖烟雨樓。", "林淺易尋和靖隠，菊荒空憶魏公游。", "客來把玩新題扇，半似鍾繇半似歐。"]'),
('9202fc52-886b-4ab7-823a-d8f4d0e01d44','再答元父','仇遠','宋','宋诗','song-poetry','','[]','騕褭龍媒去未還，獨騎款段客長安。',64,'全唐诗/poet.song.246000.json','["騕褭龍媒去未還，獨騎款段客長安。", "青黄誰采溝中斷，黑白當從局外看。", "尊俎風流陳日月，山林人物古衣冠。", "桂花滿袖王孫遠，空倚天風十二闌。"]'),
('33c745fb-f5ce-44b9-aaf5-11e65f0caf00','寄趙春洲莫兩山','仇遠','宋','宋诗','song-poetry','','[]','湖山滿目舊游空，風景荒凉客路窮。',64,'全唐诗/poet.song.246000.json','["湖山滿目舊游空，風景荒凉客路窮。", "雨意忽生桐葉外，秋光都在木樨中。", "乾坤混混多游騎，江漢寥寥有斷鴻。", "自古隠人多嗜酒，却憐無酒醉新豐。"]'),
('9e660d02-8f1e-43c3-a657-70dc3d701888','和兩山二首  其一','仇遠','宋','宋诗','song-poetry','','[]','世事枰棋入角危，有人袖手只攢眉。',64,'全唐诗/poet.song.246000.json','["世事枰棋入角危，有人袖手只攢眉。", "路通巴蜀那須檄，馬立澶淵更要詩。", "公竟醉耶從汝笑，樹猶如此信吾衰。", "傳聞雙珥消兵氣，猶把葵心向鬰儀。"]'),
('ec54b9da-4ec2-4cce-8e99-558abb7b376f','和兩山二首  其二','仇遠','宋','宋诗','song-poetry','','[]','窮鄉何處覓新豐，身世悠悠醉夢中。',64,'全唐诗/poet.song.246000.json','["窮鄉何處覓新豐，身世悠悠醉夢中。", "未學伏波尸馬革，且隨甫里問龜蒙。", "檐頭喜有桑榆日，兵後那無草木風。", "亦欲飛神游八極，扁舟坦卧不須篷。"]'),
('1cc45467-42ad-4fa4-8a34-475f8ba681e6','讀陳去非集','仇遠','宋','宋诗','song-poetry','','[]','簡齋吟集是吾師，句法能參杜拾遺。',64,'全唐诗/poet.song.246000.json','["簡齋吟集是吾師，句法能參杜拾遺。", "宇宙無人同叫嘯，公卿自古嘆流離。", "窮途劫劫誰憐汝，遺恨茫茫不在詩。", "莫道墨梅曾遇主，黄花一絕更堪悲。"]'),
('f5016156-5696-4fed-b637-2dd46b612f9b','勾龍爽毛女','仇遠','宋','宋诗','song-poetry','','[]','曾是阿房學舞人，玉簫舊譜尚隨身。',64,'全唐诗/poet.song.246000.json','["曾是阿房學舞人，玉簫舊譜尚隨身。", "喜歸商嶺尋仙藥，忍見秦宮化劫塵。", "松蜜春腴差可飽，槲衣秋碎不須紉。", "憑誰喚起勾龍爽，更寫湘妃與洛神。"]'),
('32d02353-a4fe-4166-a14a-65676c6461d1','梅花  其一','仇遠','宋','宋诗','song-poetry','','[]','爲怕緇塵染素衣，凍痕封蕊放春遲。',64,'全唐诗/poet.song.246000.json','["爲怕緇塵染素衣，凍痕封蕊放春遲。", "月來忽送闌干影，春到不分南北枝。", "啼夢翠禽依樹宿，斷魂玉笛隔花吹。", "任他萬片隨風去，須有青青葉底時。"]'),
('b5a9b069-6a7e-43d3-9512-0f0247306c09','梅花  其二','仇遠','宋','宋诗','song-poetry','','[]','夢想幽芳無處尋，相逢依舊歲寒心。',64,'全唐诗/poet.song.246000.json','["夢想幽芳無處尋，相逢依舊歲寒心。", "要看葉底玲瓏玉，休折枝頭蓓蕾金。", "清曉風霜和艷冷，黄昏庭院覺香深。", "揚州一樹春多少，殢得何郎瘦不禁。"]'),
('e37dfdb6-e046-49a7-a94b-d09d4d366ed4','潮','仇遠','宋','宋诗','song-poetry','','[]','一痕初見海門生，頃刻長驅作怒聲。',64,'全唐诗/poet.song.246000.json','["一痕初見海門生，頃刻長驅作怒聲。", "萬馬突圍天鼓碎，六鼇覆背雪山傾。", "遠朝魏闕心猶在，直上嚴灘勢始平。", "寄語吳兒休踏浪，天吳罔象正縱橫。"]'),
('a7d5eada-76cf-4638-abd7-ca1a5f2e2382','湖上','仇遠','宋','宋诗','song-poetry','','[]','嵐霧濛濛曉未收，青紅窗戶失飛樓。',64,'全唐诗/poet.song.246000.json','["嵐霧濛濛曉未收，青紅窗戶失飛樓。", "雨添芳草侵官道，水漲浮萍入御舟。", "蘇小只傳身後曲，江淹曾賦別時愁。", "杏花風急清明近，已覺新寒似麥秋。"]'),
('ac18516d-d1b3-47ec-a437-203a55b4c7a4','春日田園雜興','仇遠','宋','宋诗','song-poetry','','[]','一灣新綠護茅廬，草細泥鬆已可鉏。',64,'全唐诗/poet.song.246000.json','["一灣新綠護茅廬，草細泥鬆已可鉏。", "野老但知分社酒，地官寧復進農書。", "鶑花眼界人烟外，蠶麥生涯穀雨餘。", "我愛賦歸陶令尹，柳邊時見小藍輿。"]'),
('fa1b3c26-ece8-46e1-af08-44cc38cf2d60','次胡葦杭韻','仇遠','宋','宋诗','song-poetry','','[]','連作湖山五日游，沙鷗慣識木蘭舟。',64,'全唐诗/poet.song.246000.json','["連作湖山五日游，沙鷗慣識木蘭舟。", "清風寒日荒城晚，燕子梨花細雨愁。", "賜火恩榮皆舊夢，禁烟風景似初秋。", "鳳絲龍竹繁華意，猶爲西林落日留。"]'),
('2d40aba3-3fdf-4c73-a936-aaccf7f8c8da','秋日西湖園亭','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖一曲百泉通，漠漠青山遶梵宮。',64,'全唐诗/poet.song.246000.json','["西湖一曲百泉通，漠漠青山遶梵宮。", "故國園林秋色淨，明朝風雨桂花空。", "銀笙玉笛清歌外，畫舫珠簾落照中。", "人物風光兩相稱，兒童遮莫笑山翁。"]'),
('df99267f-203a-4e9a-bf91-c2ea525b8b69','飲陸靜復山房分韻得時字','仇遠','宋','宋诗','song-poetry','','[]','連轡行春自作期，尋芳却笑我來遲。',64,'全唐诗/poet.song.246000.json','["連轡行春自作期，尋芳却笑我來遲。", "三杯雲液花前酌，一曲瓊簫竹下吹。", "滄海桑田非舊日，石泉槐火有新詩。", "山中道士閒於鶴，門外紅塵總不知。"]'),
('35c0c56b-8fa2-439f-a0f0-c0c61cfd4b67','石屋洞','仇遠','宋','宋诗','song-poetry','','[]','誰擘空青露石坳，游龍伸臂下南高。',64,'全唐诗/poet.song.246000.json','["誰擘空青露石坳，游龍伸臂下南高。", "鬼神穿鑿地脈碎，風雨支撐天柱牢。", "峭壁蒼苔侵佛髻，懸崖滴乳濕僧袍。", "伽藍聞是香山叟，燈暗荒池沒野蒿。"]'),
('cc092614-4737-468a-a821-c3b5354f0716','蛇山','仇遠','宋','宋诗','song-poetry','','[]','閒尋石澗列雲扉，樹影生凉怯苧衣。',64,'全唐诗/poet.song.246000.json','["閒尋石澗列雲扉，樹影生凉怯苧衣。", "靜碧軒窗聊寄傲，軟紅塵土竟忘歸。", "滿傾竹葉春霞滑，輕折蕉花曉露晞。", "禪意法乘俱莫問，且談舊事更依依。"]'),
('a712ea5b-78fa-4e09-a983-c645573c3c38','湖上值雨','仇遠','宋','宋诗','song-poetry','','[]','波痕新綠草新青，有約尋芳芳不晴。',64,'全唐诗/poet.song.246000.json','["波痕新綠草新青，有約尋芳芳不晴。", "莎徑泥深雙燕濕，柳橋烟淡一鶑鳴。", "山圍故苑春常鎖，泉落低畦暖未耕。", "十載舊蹤時入夢，畫船多處看傾城。"]'),
('60a76385-a638-4f6f-9dc9-05ba66271835','同段吉甫汎湖','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖春碧淨無泥，畫舫朱簾傍岸移。',64,'全唐诗/poet.song.246000.json','["西湖春碧淨無泥，畫舫朱簾傍岸移。", "寒食清明初過後，杏花楊柳乍晴時。", "從教西日催歌鼓，莫放東風轉酒旗。", "只恐明朝成雨去，暗驚濃綠上高枝。"]'),
('a3dd78e4-34f7-4d7e-af11-fd4864d78dbe','同陳彥國汎湖','仇遠','宋','宋诗','song-poetry','','[]','斜堤高柳綠連天，且繫閒人書畫船。',64,'全唐诗/poet.song.246000.json','["斜堤高柳綠連天，且繫閒人書畫船。", "花事已空三月後，湖光還似十年前。", "洛陽園囿惟詩在，江左英雄托酒傳。", "亦欲扣舷歌小海，恐驚沙上白鷗眠。"]'),
('67109dfe-941c-4d03-a064-e927ccdc9b59','陪戴祖禹汎湖分韻得天字','仇遠','宋','宋诗','song-poetry','','[]','冉冉夕陽紅隔雨，悠悠野水碧連天。',64,'全唐诗/poet.song.246000.json','["冉冉夕陽紅隔雨，悠悠野水碧連天。", "山分秋色歸紅葉，風約蘋香入釣船。", "鐘鼓園林已如此，衣冠文物故依然。", "當歌對酒腸堪斷，倒著烏巾且醉眠。"]'),
('97954f9d-3248-4aba-acd0-cc227c9bea4f','鳳凰山故宮','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','漸無南渡舊衣冠，尚有西湖風雨寒。',64,'全唐诗/poet.song.246000.json','["漸無南渡舊衣冠，尚有西湖風雨寒。", "鳳鳥不來山寂寂，鴟夷何在海漫漫。", "荒陵樵採官猶禁，故苑烟花客自看。", "惟恨餘杭門外柳，長年不了送征鞍。"]'),
('153a8a6a-cb7d-4f16-bc69-005867a3ef90','集慶寺','仇遠','宋','宋诗','song-poetry','','[]','平生三宿此招提，眼底交游更有誰。',64,'全唐诗/poet.song.246000.json','["平生三宿此招提，眼底交游更有誰。", "顧愷漫留金粟影，杜陵忍賦玉華詩。", "旋烹紫筍猶含籜，自摘青茶未展旗。", "聽徹洞簫清不寐，月明正照古松枝。"]'),
('bacabf6c-b8e5-4819-a855-3823aaebb322','卜居白龜池上','仇遠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一琴一鶴小生涯，陋巷深居幾歲華。',64,'全唐诗/poet.song.246000.json','["一琴一鶴小生涯，陋巷深居幾歲華。", "爲愛西湖來卜隠，却憐東野又移家。", "荒城雨滑難騎馬，小市天明已賣花。", "阿母抱孫閒指點，疏林盡處是棲霞。"]'),
('4779fbcd-bae9-4dbe-a8a9-d291e82530d7','過李山人居','仇遠','宋','宋诗','song-poetry','','[]','數椽竹屋傍秋江，屋外疏籬隔柳樁。',64,'全唐诗/poet.song.246000.json','["數椽竹屋傍秋江，屋外疏籬隔柳樁。", "客至旋分垂釣石，雨來自掩讀書窗。", "癡兒弄鏡時翻背，小婦彈箏不識腔。", "自古漁樵有遺逸，未應只說鹿門龐。"]'),
('90e9f3ec-b9aa-4c17-91de-73f759a41b21','題趙子固水墨雙鈎水仙卷','仇遠','宋','宋诗','song-poetry','','[]','冰薄沙昏短草枯，采香人遠隔湘湖。',64,'全唐诗/poet.song.246000.json','["冰薄沙昏短草枯，采香人遠隔湘湖。", "誰留夜月群仙珮，絕勝秋風九畹圖。", "白粲銅盤傾沆瀣，清明寶玦破珊瑚。", "却憐不得同蘭蕙，一識清醒楚大夫。"]'),
('0e41f922-4eba-4a9c-bc9a-ee72626a737b','書與士瞻上人十首  其一','仇遠','宋','宋诗','song-poetry','','[]','我本迂疏落拓人，滿頭霜雪滿懷春。',64,'全唐诗/poet.song.246000.json','["我本迂疏落拓人，滿頭霜雪滿懷春。", "登山有屐身恒健，挂壁無弦趣更真。", "往歲效官殊漫浪，老來學佛離貪嗔。", "却憐衛鶴齊雞輩，空費心機不庇身。"]'),
('58b75ca8-3226-472a-bb18-856487f197ea','書與士瞻上人十首  其二','仇遠','宋','宋诗','song-poetry','','[]','野鶴清高六翮輕，孤雲萬里去冥冥。',64,'全唐诗/poet.song.246000.json','["野鶴清高六翮輕，孤雲萬里去冥冥。", "漢科合應茂才選，唐士曾書遺教經。", "好趁江南諸老在，盡看薊北衆山青。", "錦衣歸日春風滿，期醉沙堤雙玉瓶。"]'),
('b821fa72-a4fb-40f6-8c60-c7846efd8bc7','書與士瞻上人十首  其三','仇遠','宋','宋诗','song-poetry','','[]','嬾學羊裘漢子陵，亦非解印晉淵明。',64,'全唐诗/poet.song.246000.json','["嬾學羊裘漢子陵，亦非解印晉淵明。", "好山好水恒相對，浮利浮名不願爭。", "詩酒每尋朋友共，山園都付子孫耕。", "野心直與閑雲似，却笑孤雲出岫輕。"]'),
('a8f6a0d5-0904-4df2-a9a6-8d19ab355e45','書與士瞻上人十首  其四','仇遠','宋','宋诗','song-poetry','','[]','末俗由來不貴儒，愚夫愚婦恣揶揄。',64,'全唐诗/poet.song.246000.json','["末俗由來不貴儒，愚夫愚婦恣揶揄。", "束書合向山林隠，絕跡莫登名利途。", "膝下有孫貧亦樂，門前無債醉如泥。", "咸平處士真堪羨，靜守梅花住裏湖。"]'),
('df2864ff-a18b-4b25-8b6d-9316854779f5','書與士瞻上人十首  其五','仇遠','宋','宋诗','song-poetry','','[]','宦海漂流四十年，老來默默守吾玄。',64,'全唐诗/poet.song.246000.json','["宦海漂流四十年，老來默默守吾玄。", "艱危頗得文章力，嫁娶各隨兒女緣。", "白飯充腸聊當肉，好書到手不論錢。", "閒心嬾作邯鄲夢，樂取西窗一枕眠。"]'),
('90e9a141-8d5c-492c-9b70-18b2ea761a48','書與士瞻上人十首  其六','仇遠','宋','宋诗','song-poetry','','[]','筆硯生涯獨善身，一區花竹四時春。',64,'全唐诗/poet.song.246000.json','["筆硯生涯獨善身，一區花竹四時春。", "無求莫問朝廷事，有恥難交市井人。", "簾外烏衣飛上下，窗前蜂蕊結輪囷。", "鑑如居士東鄰住，肯借霜豪爲寫真。"]'),
('aae42c1f-c557-421b-94db-7e8a2153d3ce','書與士瞻上人十首  其七','仇遠','宋','宋诗','song-poetry','','[]','難得心交左伯桃，亦無善相九方臯。',64,'全唐诗/poet.song.246000.json','["難得心交左伯桃，亦無善相九方臯。", "而今賤子多儒誤，自古山人索價高。", "衆雀豈能知鵠志，一雞何足用牛刀。", "獨醒獨醉俱堪樂，妙理依然有濁醪。"]'),
('4e1a7e4d-8666-467e-8cb7-239da32923f6','書與士瞻上人十首  其八','仇遠','宋','宋诗','song-poetry','','[]','倦游嬾著小烏巾，短髪絲絲雪滿簪。',64,'全唐诗/poet.song.246000.json','["倦游嬾著小烏巾，短髪絲絲雪滿簪。", "信手拈書聊慰眼，轉頭忘事太無心。", "笑他杜老頻看鏡，愛我昭文不鼓琴。", "喜有山林方外友，時携佳紙索新吟。"]'),
('4948cddc-2396-44b6-96a0-982432055939','書與士瞻上人十首  其九','仇遠','宋','宋诗','song-poetry','','[]','北風雨後忽南風，頃刻開晴又轉東。',64,'全唐诗/poet.song.246000.json','["北風雨後忽南風，頃刻開晴又轉東。", "后土未乾偏有恨，漏天難補太無功。", "小樓兀坐思猨鶴，好客相期避燕鴻。", "壁上墨蘭香可掬，令人常憶所南翁。"]'),
('fdce4b59-3bb5-4259-8ecd-04e59709ee42','書與士瞻上人十首  其一○','仇遠','宋','宋诗','song-poetry','','[]','豪氣年來漸埽除，簞瓢自樂守臞儒。',64,'全唐诗/poet.song.246000.json','["豪氣年來漸埽除，簞瓢自樂守臞儒。", "江頭盡醉唐朝士，澤畔行吟楚大夫。", "萬里茝鵬何必羨，一官蟣蝨不如無。", "葛巾草履從人笑，莫問青衫似葉枯。"]'),
('25f89ae8-bf5d-4acd-b2e5-3f3a515d7ec3','題溧陽市','仇遠','宋','宋诗','song-poetry','','["\u592a\u6e56"]','萬家大縣舊留都，一派中江入太湖。',64,'全唐诗/poet.song.246000.json','["萬家大縣舊留都，一派中江入太湖。", "縮項魚肥人鱠玉，長腰米貴客量珠。", "府分南北寒蕪合，橋直東西夜市無。", "却是旗亭浮蟻美，杖頭能費幾青蚨。"]'),
('b8843bf2-cf19-410d-ad5a-edb7ac4dfd9d','魯庵尊師以彝齋白描四薌命作韻語','仇遠','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','淡墨英英妙寫真，一花一葉一精神。',64,'全唐诗/poet.song.246000.json','["淡墨英英妙寫真，一花一葉一精神。", "繁香曾入廬山夢，遺珮如行湘水春。", "小白凝珠還勝雪，輕黄承襪不生塵。", "老僧嬾作浮華想，空谷猶疑見似人。"]'),
('6f466885-50b9-4d9e-a837-1836f4413183','題李公略示高郎中吳山觀月圖','仇遠','宋','宋诗','song-poetry','','[]','憑高宜晚更宜秋，下馬歸來即倚樓。',64,'全唐诗/poet.song.246000.json','["憑高宜晚更宜秋，下馬歸來即倚樓。", "納納乾坤雙老眼，滔滔江漢一扁舟。", "滿城明月空吳苑，隔岸青山認越州。", "李白酒豪高適筆，當時人物總風流。"]'),
('215346d1-596f-4f79-8cd4-f9abbab1c6e1','檇李亭','仇遠','宋','宋诗','song-poetry','','[]','閑抱琴書檇李游，仙壇古屋一茆留。',64,'全唐诗/poet.song.246000.json','["閑抱琴書檇李游，仙壇古屋一茆留。", "驛橋通市人沽酒，湖水依城客放舟。", "葵扇桃笙聊却暑，蘋花楓葉已知秋。", "坡翁仙去詩聲在，寂寞林塘卧白鷗。"]'),
('4628075d-af15-402f-b566-072fefe5ddc8','真如寺','仇遠','宋','宋诗','song-poetry','','[]','一橋夭矯界雙湖，野徑沿流到佛廬。',64,'全唐诗/poet.song.246000.json','["一橋夭矯界雙湖，野徑沿流到佛廬。", "石塔殘燈猶閃爍，相家喬木已蕭疏。", "苔封古井晴逾滑，骨冷荒山草不除。", "長水法師癡□甚，□根人定欲何如。"]'),
('4a3268ae-7a87-4e56-8692-60c5a8e41647','劉伶墓','仇遠','宋','宋诗','song-poetry','','[]','鳳浦鴛湖西有墳，此塋寂寞海邊村。',64,'全唐诗/poet.song.246000.json','["鳳浦鴛湖西有墳，此塋寂寞海邊村。", "落花紅雨鬼仙句，淡月黄昏酒聖魂。", "有鍤已隨棺槨化，無碑空信艾芻言。", "螟蛉蜾蠃今何在，起爲先生酹一尊。"]'),
('21d98a1a-1a90-4d66-be2c-dd95e5376ec9','送峿侍者游茅山','仇遠','宋','宋诗','song-poetry','','[]','雲開三茅古洞天，借風一棹荆溪船。',64,'全唐诗/poet.song.246000.json','["雲開三茅古洞天，借風一棹荆溪船。", "所思緜緜常在夢，此行冉冉如登仙。", "汲泉淨洗黄獨雪，劚石深耕瑶草烟。", "蕙帳香凝蒲坐暖，共讀南華秋水篇。"]'),
('366b78a3-1f0a-4602-b726-cce76f5b2606','集虛書院','仇遠','宋','宋诗','song-poetry','','[]','築室東臯野水濱，室中生白坐生春。',64,'全唐诗/poet.song.246000.json','["築室東臯野水濱，室中生白坐生春。", "了知空洞元無物，須信清明自有神。", "幽徑草花聊適趣，閒窗筆硯不留塵。", "酒經丹訣非吾事，萬卷書藏一老身。"]'),
('a02bc794-191d-4e7c-84a3-89c9032b78d3','游天竺二首  其一','仇遠','宋','宋诗','song-poetry','','[]','行遍山巔又水涯，尚無紅葉與黄花。',64,'全唐诗/poet.song.246000.json','["行遍山巔又水涯，尚無紅葉與黄花。", "長松夾道六七里，小墅通村十數家。", "竺國雲深僧寂寞，草堂洞古石嵯牙。", "野翁共醉官壚酒，扶醉歸來已暮鴉。"]'),
('5721fae6-644c-4ecf-8efd-fd182215a339','游天竺二首  其二','仇遠','宋','宋诗','song-poetry','','[]','登覽欣逢勝日閑，蒼松九里費躋攀。',64,'全唐诗/poet.song.246000.json','["登覽欣逢勝日閑，蒼松九里費躋攀。", "行過綠水盡頭路，步入白雲生處山。", "猿鳥尚能知異境，仙凡原不隔重關。", "幾時拂袖逃塵網，野衲村樵共往還。"]'),
('9177ec39-4c54-4df5-9e9b-733c324a26b7','游智果寺','仇遠','宋','宋诗','song-poetry','','[]','獨逕蒼苔引瘦筇，牆陰修竹碧玲瓏。',64,'全唐诗/poet.song.246000.json','["獨逕蒼苔引瘦筇，牆陰修竹碧玲瓏。", "青山猶見及坡老，小雨何須問社公。", "雲冷石藏烹茗雪，日長門掩落花風。", "定知神扈題梁字，不與當時劫火同。"]'),
('31ebbb9d-248f-4e7b-aa98-3a6868822268','晦日携幼湖上','仇遠','宋','宋诗','song-poetry','','[]','葛嶺蘇堤晝寂然，東風吹我過湖船。',64,'全唐诗/poet.song.246000.json','["葛嶺蘇堤晝寂然，東風吹我過湖船。", "江山信美無人會，兒女情多只自憐。", "柳色染勻春淡蕩，楊花落盡日暄妍。", "麥秋天氣渾如此，却笑征衫未脫緜。"]'),
('6a7870b4-c006-49b4-81fa-d06be245dd44','丹心','仇遠','宋','宋诗','song-poetry','','[]','丹心只有杜陵知，愁讀傷春五首詩。',32,'全唐诗/poet.song.246000.json','["丹心只有杜陵知，愁讀傷春五首詩。", "傳語龜年休度曲，江南正是落花時。"]'),
('3631cd82-74d2-4ff4-88a1-ec038cc0f389','登寶林應天塔','仇遠','宋','宋诗','song-poetry','','[]','越王城下草青青，眺遠須登第幾層。',32,'全唐诗/poet.song.246000.json','["越王城下草青青，眺遠須登第幾層。", "白髪山僧閒指點，斜陽古木是諸陵。"]'),
('75925aaf-1a2b-4709-857a-3716c901699c','朝天門城角','仇遠','宋','宋诗','song-poetry','','[]','颯颯秋風起白榆，山前吹徹小單于。',32,'全唐诗/poet.song.246000.json','["颯颯秋風起白榆，山前吹徹小單于。", "行人便作邊城聽，忘却杭州是故都。"]'),
('c1076852-e72d-4473-aef4-b6c0b69db68e','斷橋聞角','仇遠','宋','宋诗','song-poetry','','[]','柳外官橋出戍樓，和霜和月按梁州。',32,'全唐诗/poet.song.246000.json','["柳外官橋出戍樓，和霜和月按梁州。", "吹時莫近孤山下，千樹梅花不識愁。"]'),
('da475517-0385-499a-ba7c-72c9d173d7fa','懷向古','仇遠','宋','宋诗','song-poetry','','[]','曾同野竈煮溪魚，別鶴歸遲信息疏。',32,'全唐诗/poet.song.246000.json','["曾同野竈煮溪魚，別鶴歸遲信息疏。", "不是山中無楮葉，尋常嬾寄入城書。"]'),
('44b07c64-d0f0-4a3f-b444-d12ae47d4010','博望','仇遠','宋','宋诗','song-poetry','','[]','使者星明犯斗牛，歸槎穩放絳河秋。',32,'全唐诗/poet.song.246000.json','["使者星明犯斗牛，歸槎穩放絳河秋。", "茂陵可是無仙分，不載丹砂載石榴。"]'),
('92238b04-f595-4b8d-892e-11c5b5679c91','上巳感懷','仇遠','宋','宋诗','song-poetry','','[]','一春無況嬾游山，風景依然三月三。',32,'全唐诗/poet.song.246000.json','["一春無況嬾游山，風景依然三月三。", "十里楊花深似雪，馬蹄無路入江南。"]'),
('cadb3fdc-4bd2-4cf4-beba-af16938c364d','范文正公黄素小楷昌黎伯夷頌蓋在青社時所書以遺京西轉運使舜元蘇公者也後二百年大興李侯戡得此本於燕及南來守吳乃文正鄉里即訪公子孫以畀之范氏喜而求詩爲賦此二首  其一','仇遠','宋','宋诗','song-poetry','','[]','小楷青州三絕碑，復還范氏事尤奇。',32,'全唐诗/poet.song.246000.json','["小楷青州三絕碑，復還范氏事尤奇。", "不知百世聞風者，更有何人似伯夷。"]'),
('fbf5d2ba-0514-4475-9c49-9dfacf92ee09','范文正公黄素小楷昌黎伯夷頌蓋在青社時所書以遺京西轉運使舜元蘇公者也後二百年大興李侯戡得此本於燕及南來守吳乃文正鄉里即訪公子孫以畀之范氏喜而求詩爲賦此二首  其二','仇遠','宋','宋诗','song-poetry','','[]','古今一理是綱常，范筆韓文妙發揚。',32,'全唐诗/poet.song.246000.json','["古今一理是綱常，范筆韓文妙發揚。", "公卧首陽原不死，春風歲歲蕨薇香。"]'),
('03379667-145e-4d2b-be7c-3b6a218b2e67','題李成寒鴉圖','仇遠','宋','宋诗','song-poetry','','[]','老樹枯苔雪乍晴，饑烏飛集噤無聲。',32,'全唐诗/poet.song.246000.json','["老樹枯苔雪乍晴，饑烏飛集噤無聲。", "蒺藜沙上花開早，且讓春風與燕鶑。"]'),
('9fcf1e03-f83a-44f5-b551-d536801da3d6','題燕肅畫卷','仇遠','宋','宋诗','song-poetry','','[]','溪路迢迢繞碧峰，白雲迷却舊行蹤。',32,'全唐诗/poet.song.246000.json','["溪路迢迢繞碧峰，白雲迷却舊行蹤。", "買舟歸去山中住，終日茆亭坐聽松。"]'),
('a5831938-3172-4c8c-ae86-e40f1357a162','題趙松雲迷禽竹石圖','仇遠','宋','宋诗','song-poetry','','[]','錦石傾欹玉樹荒，雪兒無語戀斜陽。',32,'全唐诗/poet.song.246000.json','["錦石傾欹玉樹荒，雪兒無語戀斜陽。", "百年花鳥春風夢，不是錢塘是汴梁。"]'),
('e3c43d32-5899-4b6c-9153-5d50b25ef68d','題和靖先生觀梅圖無懷上人徵予作','仇遠','宋','宋诗','song-poetry','','[]','癡童癯鶴冷相隨，笑指南枝傍小溪。',32,'全唐诗/poet.song.246000.json','["癡童癯鶴冷相隨，笑指南枝傍小溪。", "到處一般香影色，孤山只在斷橋西。"]'),
('9c96c9e3-e0aa-4e4c-82b4-8ce1c5e3a2e8','雲屋上人久別承寄以詩次韻謝','仇遠','宋','宋诗','song-poetry','','[]','月落城空鶴倦飛，密雲深樹靜相依。',32,'全唐诗/poet.song.246000.json','["月落城空鶴倦飛，密雲深樹靜相依。", "閶門北去山如畫，有日同師步翠微。"]'),
('75c7c4ed-fd17-4533-8492-7d2d997ecc64','趙子昂陳仲美合作水鳬小景','仇遠','宋','宋诗','song-poetry','','[]','良工苦思可心降，底事文禽不解雙。',32,'全唐诗/poet.song.246000.json','["良工苦思可心降，底事文禽不解雙。", "欲采芳華波浪闊，芙蓉朵朵隔秋江。"]'),
('a36b3b7e-4ebe-4708-a2f2-fb8685fdbaf3','題三忠堂三首  其一','仇遠','宋','宋诗','song-poetry','','[]','丞相當年握筆時，封胡羯末總佳兒。',32,'全唐诗/poet.song.246000.json','["丞相當年握筆時，封胡羯末總佳兒。", "後來家有無窮事，便是天仙也不知。"]'),
('4ca916c9-2a1e-4083-bb23-3de66ce17243','題三忠堂三首  其二','仇遠','宋','宋诗','song-poetry','','[]','謝砌諸郎入寄奴，機雲忘祖亦忘吳。',32,'全唐诗/poet.song.246000.json','["謝砌諸郎入寄奴，機雲忘祖亦忘吳。", "一門一品如今有，三世三忠自古無。"]'),
('b76e0bbf-c1d5-4509-9bb6-394d63e86ea6','題三忠堂三首  其三','仇遠','宋','宋诗','song-poetry','','[]','一紙郇雲傲劫灰，慈親一見一心摧。',32,'全唐诗/poet.song.246000.json','["一紙郇雲傲劫灰，慈親一見一心摧。", "如今王謝堂前燕，飛入人家更不回。"]'),
('fa396eeb-7546-4afd-9dc3-db4d21f55c64','題趙仲穆山水二首  其一','仇遠','宋','宋诗','song-poetry','','[]','綠林紅樹石崢嶸，有客携琴訪友生。',32,'全唐诗/poet.song.246000.json','["綠林紅樹石崢嶸，有客携琴訪友生。", "今夜西軒風月好，殷勤爲我鼓商聲。"]'),
('58aeceee-e990-40c2-86d9-2af11da4deeb','題趙仲穆山水二首  其二','仇遠','宋','宋诗','song-poetry','','[]','王孫遺迹在桐鄉，留意當年翰墨香。',32,'全唐诗/poet.song.246000.json','["王孫遺迹在桐鄉，留意當年翰墨香。", "回首西風多感慨，不辭援筆賦嵇康。"]'),
('9c739a9b-8da9-4d5c-a0b0-2a5bafb9ae41','題趙松雲竹石幽蘭','仇遠','宋','宋诗','song-poetry','','[]','舊時長見揮毫處，修竹幽蘭取次分。',32,'全唐诗/poet.song.246000.json','["舊時長見揮毫處，修竹幽蘭取次分。", "欲把一竿苕水上，鷗波千頃看秋雲。"]'),
('80ed2821-dc56-4fc0-ba10-b741c027a4a5','岊山','仇遠','宋','宋诗','song-poetry','','[]','岊老峰高翠倚天，洮河春水綠無邊。',32,'全唐诗/poet.song.246000.json','["岊老峰高翠倚天，洮河春水綠無邊。", "不知楊柳蒹葭外，何處泊君書畫船。"]'),
('ac5d2f9a-224e-4dea-a742-6284a6c0c50d','閒居十詠  其一','仇遠','宋','宋诗','song-poetry','','[]','階前紫蔓金絲草，籬角紅垂錦带花。',32,'全唐诗/poet.song.246000.json','["階前紫蔓金絲草，籬角紅垂錦带花。", "梓澤平泉易消歇，春留富貴與詩家。"]'),
('7f5bd7fe-d873-4a39-bf81-84ef17a9ba68','閒居十詠  其二','仇遠','宋','宋诗','song-poetry','','[]','樹隔殘鐘遠欲無，野雲漠漠雨疏疏。',32,'全唐诗/poet.song.246000.json','["樹隔殘鐘遠欲無，野雲漠漠雨疏疏。", "飛蚊盡逐南風去，父子燈前共讀書。"]'),
('0e8ea7dd-bcb2-4ac8-a4c3-6490d3a30fb7','閒居十詠  其三','仇遠','宋','宋诗','song-poetry','','[]','仰屋著書無筆力，閉門覓句費心機。',32,'全唐诗/poet.song.246000.json','["仰屋著書無筆力，閉門覓句費心機。", "不如花下冥冥坐，靜看蜻蜓蛺蝶飛。"]'),
('34ab53f8-8167-4d3c-8672-2e8be9e371cf','閒居十詠  其四','仇遠','宋','宋诗','song-poetry','','[]','鶑花韋曲舊時游，老去閒情已五休。',32,'全唐诗/poet.song.246000.json','["鶑花韋曲舊時游，老去閒情已五休。", "却笑東風無檢束，又隨飛絮過南樓。"]'),
('b420492a-aa27-42ce-bbaa-dc8b2229781f','閒居十詠  其五','仇遠','宋','宋诗','song-poetry','','[]','鳥雀喧秋未肯棲，狂風吹樹影離披。',32,'全唐诗/poet.song.246000.json','["鳥雀喧秋未肯棲，狂風吹樹影離披。", "屋邊尚有斜陽在，更看山人一局棋。"]'),
('8d16bd1a-fa7e-4715-9d08-fa956be64787','閒居十詠  其六','仇遠','宋','宋诗','song-poetry','','[]','風挾濃雲起炮車，捎窗雨脚亂如麻。',32,'全唐诗/poet.song.246000.json','["風挾濃雲起炮車，捎窗雨脚亂如麻。", "山中茆屋應安穩，不向溪聲送落花。"]'),
('3c2aa587-ff5e-4885-a099-79f31222b3d0','閒居十詠  其七','仇遠','宋','宋诗','song-poetry','','[]','新竹修修綠過牆，讀書門外亦陰凉。',32,'全唐诗/poet.song.246000.json','["新竹修修綠過牆，讀書門外亦陰凉。", "道人清福不肯受，却入西山看夕陽。"]'),
('cd806525-02b6-47aa-a0a4-de64bf79c1a3','閒居十詠  其八','仇遠','宋','宋诗','song-poetry','','[]','翠袖佳人倚莫寒，雙禽踏破玉闌干。',32,'全唐诗/poet.song.246000.json','["翠袖佳人倚莫寒，雙禽踏破玉闌干。", "空山月落春風換，直作羅浮夢裏看。"]'),
('eba9333c-8e9d-41b9-9b5e-87d502301167','閒居十詠  其九','仇遠','宋','宋诗','song-poetry','','[]','茶甌沙帽慣迎賓，不是詩人即道人。',32,'全唐诗/poet.song.246000.json','["茶甌沙帽慣迎賓，不是詩人即道人。", "細雨斜風君莫出，綠陰門外有紅塵。"]'),
('510443d7-bf0b-4c47-8488-26e6d2fb27dd','閒居十詠  其一○','仇遠','宋','宋诗','song-poetry','','[]','珠簾玉柵綺羅叢，猶有承平京洛風。',32,'全唐诗/poet.song.246000.json','["珠簾玉柵綺羅叢，猶有承平京洛風。", "飲罷歸來游騎少，一庭明月夜方中。"]'),
('525718ea-aa0e-465d-95ab-9b9f68e00eea','題馬秀卿郊墅','仇遠','宋','宋诗','song-poetry','','[]','仙人朝去莫知還，野色風光一草庵。',32,'全唐诗/poet.song.246000.json','["仙人朝去莫知還，野色風光一草庵。", "少室何妨高索價，莫教輕指作終南。"]'),
('4b873f13-e191-4ff3-98fe-11cca5e0b58a','題天壽觀清隠山房','仇遠','宋','宋诗','song-poetry','','[]','紫極秋聲竹滿軒，一塵飛不涴琴樽。',32,'全唐诗/poet.song.246000.json','["紫極秋聲竹滿軒，一塵飛不涴琴樽。", "白雲自逐秋風去，卧看青山嬾出門。"]'),
('294fd9e3-243b-42f7-94d0-1ce5066095c6','泊桐鄉','仇遠','宋','宋诗','song-poetry','','[]','雪晴霜樹勝春紅，回首臨平杳靄中。',32,'全唐诗/poet.song.246000.json','["雪晴霜樹勝春紅，回首臨平杳靄中。", "正是詩人棲穩處，青山明月滿歸篷。"]'),
('926fc30a-9571-4c8f-a44d-15e5904fae62','宿本覺寺','仇遠','宋','宋诗','song-poetry','','[]','竹樹號風似說禪，青燈布被抱愁眠。',32,'全唐诗/poet.song.246000.json','["竹樹號風似說禪，青燈布被抱愁眠。", "東坡三過我一宿，盡是人生清淨緣。"]'),
('d4b77057-c902-440c-a966-81c586ecbe88','李待詔虎溪三笑圖','仇遠','宋','宋诗','song-poetry','','[]','偶然行過溪橋，正自不值一笑。',28,'全唐诗/poet.song.246000.json','["偶然行過溪橋，正自不值一笑。", "三人必有我師，不笑不足爲道。"]'),
('d072e92f-9233-461d-a603-efcb085fe2ac','句  其一','仇遠','宋','宋诗','song-poetry','','[]','久欲脫塵網，未有辟穀方。',48,'全唐诗/poet.song.246000.json','["久欲脫塵網，未有辟穀方。", "釋然山中游，世慮可暫忘。", "鷗鷺亦知幾，深入菰蒲藏。", "卧舟放中流，吾不如漁郎。"]'),
('42c79c49-4478-4a32-aa52-a96c5c314d6d','句  其二','仇遠','宋','宋诗','song-poetry','','[]','高荷不受雨，傾瀉與低荷。',60,'全唐诗/poet.song.246000.json','["高荷不受雨，傾瀉與低荷。", "低荷强自持，聚雨傾入波。", "朝雨尚滴瀝，晚雨忽滂沱。", "臨池卧以聽，雨聲靜中多。", "兩耳本自清，奈此荷葉何。"]'),
('f1d4c7f1-5a85-4df0-af58-98eadb6a452d','句  其三','仇遠','宋','宋诗','song-poetry','','[]','螢火惟知夜，燈花不待春。',12,'全唐诗/poet.song.246000.json','["螢火惟知夜，燈花不待春。"]'),
('9a842050-05eb-41e0-828a-517e7e088d7f','句  其四','仇遠','宋','宋诗','song-poetry','','[]','割蒲分坐具，貯瀑入軍持。',12,'全唐诗/poet.song.246000.json','["割蒲分坐具，貯瀑入軍持。"]'),
('58d586d2-e231-4479-8d66-962f6b7ccbeb','句  其五','仇遠','宋','宋诗','song-poetry','','[]','風雨不出戶，兒孫共讀書。',12,'全唐诗/poet.song.246000.json','["風雨不出戶，兒孫共讀書。"]'),
('5721864a-93be-4bc2-a523-82f61f548587','句  其六','仇遠','宋','宋诗','song-poetry','','[]','姓名不入六臣傳，容貌堪傳九老碑。',16,'全唐诗/poet.song.246000.json','["姓名不入六臣傳，容貌堪傳九老碑。"]'),
('f1fe76f2-e915-4bb4-83a0-a32b628e7895','句  其七','仇遠','宋','宋诗','song-poetry','','[]','老尚留樊素，貧休比范丹。',12,'全唐诗/poet.song.246000.json','["老尚留樊素，貧休比范丹。"]'),
('2176d8a9-d8b4-4d37-af73-8ee3c5d71c41','偶作','仇遠','宋','宋诗','song-poetry','','[]','元亮真止酒，昭文不鼓琴。',48,'全唐诗/poet.song.246000.json','["元亮真止酒，昭文不鼓琴。", "文章成小伎，道德負初心。", "故友凋零盡，中年感慨深。", "從來麋鹿性，只是愛山林。"]'),
('e2114c48-4105-45cf-9054-60bb55f852a8','無題','仇遠','宋','宋诗','song-poetry','','[]','粉圍香陣畫梁塵，幾夢梨花漠漠雲。',32,'全唐诗/poet.song.246000.json','["粉圍香陣畫梁塵，幾夢梨花漠漠雲。", "一夜春風忽吹醒，鏡中白髪不須耘。"]'),
('0f4ffd09-bf41-4c63-a5e8-8ced4b956d4c','後園野池詩','仇遠','宋','宋诗','song-poetry','','[]','欲和滄浪孺子歌，東風吹皺縠紋波。',64,'全唐诗/poet.song.246000.json','["欲和滄浪孺子歌，東風吹皺縠紋波。", "幽禽哺子櫻桃少，浮草一苗蝌蚪多。", "天與一官□□拙，春餘幾日喜晴和。", "少須幸有寬閑地，□□茅亭俯芰荷。"]'),
('fd22d83a-d514-40c5-aa43-6b87dfd69ec8','東園賞紅梅','仇遠','宋','宋诗','song-poetry','','[]','花姨夜擣守宮血，染就南枝花貌別。',112,'全唐诗/poet.song.246000.json','["花姨夜擣守宮血，染就南枝花貌別。", "宿酲未解春正酣，一片晴霞消凍雪。", "莫道有人疑作杏，老眼頻看亦生纈。", "東闌更有萼綠華，精神標致尤清絕。", "先生焚香讀書處，把酒花前相暖熱。", "羣蜂知香不知色，一枝肯許兒童折。", "兩株橫卧處士橋，夢中歸踏孤山月。"]'),
('24da67de-51d1-457d-8892-94c94758bd54','頃溧水歸登官塘湯漢章義門  其一','仇遠','宋','宋诗','song-poetry','','[]','五山翔鳳集東廬，花竹園池可隠居。',64,'全唐诗/poet.song.246000.json','["五山翔鳳集東廬，花竹園池可隠居。", "奕代文聲傳學館，大書義字式門閭。", "壎箎雅奏和爲貴，樽俎清言樂有餘。", "車笠重逢當一笑，白眉青眼尚如初。"]'),
('44e3b025-7fd0-42a2-b979-575d926c7cd3','頃溧水歸登官塘湯漢章義門  其二','仇遠','宋','宋诗','song-poetry','','[]','一塘分雨百泉流，喜作山房信宿留。',64,'全唐诗/poet.song.246000.json','["一塘分雨百泉流，喜作山房信宿留。", "騎馬傍門知不厭，坐牀索酒合應羞。", "生平仲舉延徐穉，老去文淵憶少遊。", "霧豹直疑斑已露，翩翩入谷有鳴騶。"]'),
('b4480c7c-db39-4a54-a574-ffc8c21fc715','村中語','仇遠','宋','宋诗','song-poetry','','[]','吳儂曾在山村住，聽得村中老人語。',144,'全唐诗/poet.song.246000.json','["吳儂曾在山村住，聽得村中老人語。", "六月祈雨不祈晴，十月祈晴不祈雨。", "今年三伏雨水多，官吏祈晴救禾黍。", "祈晴得晴雖可喜，農夫車水方勞苦。", "汗流如漿面如鐵，但要田乾那畏暑。", "黑雲一片來何忙，心怕雨作身願凉。", "安得長風爲吹散，乍可赤體當秋陽。", "東橋西橋日荒荒，南圩北圩水茫茫。", "中熟下熟亦足飽，儘勝淮頭爭捕蝗。"]'),
('dd1b5f70-7ea2-49b5-89d0-344d0e82fd4e','村舍即事  其一','仇遠','宋','宋诗','song-poetry','','[]','依籬疊塹作人家，西日還將葦箔遮。',32,'全唐诗/poet.song.246000.json','["依籬疊塹作人家，西日還將葦箔遮。", "窗戶莫嫌秋色淡，紫蘇紅莧老生花。"]'),
('884f4c52-27dd-4d63-b646-b7ad3f8e6dee','村舍即事  其二','仇遠','宋','宋诗','song-poetry','','[]','鳳仙繞砌錦斕斑，未著秋霜儘耐看。',32,'全唐诗/poet.song.246000.json','["鳳仙繞砌錦斕斑，未著秋霜儘耐看。", "不似南窗數竿竹，年年日日報平安。"]'),
('7f4415eb-f035-4f23-b36c-4e425c7cede2','程公明家玉蕊花','仇遠','宋','宋诗','song-poetry','','[]','招隠山中有此花，仙人曾住七香車。',32,'全唐诗/poet.song.246000.json','["招隠山中有此花，仙人曾住七香車。", "可憐一架開如雪，冷落西門處士家。"]'),
('3742c77a-3aa0-4007-8bf9-7cc33df586d0','送李介甫赴官塘湯氏館','仇遠','宋','宋诗','song-poetry','','[]','東盧山下義門中，弘開講席招蜀翁。',64,'全唐诗/poet.song.246000.json','["東盧山下義門中，弘開講席招蜀翁。", "主人擇客又擇主，童蒙求我我求童。", "俊傑識時審出處，道義結交全始終。", "惟應上墓似龐老，便合移家隨葛公。"]'),
('8ab74f66-e232-48a7-8594-b2994965f037','元夕恩霈即事','仇遠','宋','宋诗','song-poetry','','[]','馹騎中宵至，圜扉徹曉空。',48,'全唐诗/poet.song.246000.json','["馹騎中宵至，圜扉徹曉空。", "天恩何曠蕩，春意亦沖融。", "燈火千家市，絃歌一畝宮。", "明知和氣聚，瑞雪舞東風。"]'),
('9295dd9a-b6bb-459c-a951-e71c4c831c36','李唐虎溪三笑圖','仇遠','宋','宋诗','song-poetry','','[]','人生一笑良難，問此是同是別。',28,'全唐诗/poet.song.246000.json','["人生一笑良難，問此是同是別。", "青山相對無言，溪聲出廣長舌。"]'),
('ccb8c9d0-9c3a-4cc4-b4c6-995699bafcfd','即事','史蒙卿','宋','宋诗','song-poetry','','[]','宮花攢曉日，仙鶴下雲端。',48,'全唐诗/poet.song.246000.json','["宮花攢曉日，仙鶴下雲端。", "自是傷心極，那能著眼看。", "風沙兩宮恨，烟草八陵寒。", "一掬孤臣淚，秋霖對不乾。"]'),
('0e17d60c-46ca-4518-b62f-b477d47db43e','有感','史蒙卿','宋','宋诗','song-poetry','','[]','途窮那免哭，哭罷一高歌。',48,'全唐诗/poet.song.246000.json','["途窮那免哭，哭罷一高歌。", "白日催年急，青山閲世多。", "浮生從潦倒，遺恨不消磨。", "何許南來雁，殷勤掠暝過。"]'),
('c338804e-fd00-4d6e-aad5-b0187f4936d6','九鎖山十詠 大滌洞','鄧牧','宋','宋诗','song-poetry','','[]','陰陰大滌洞，古色閟積鐵。',36,'全唐诗/poet.song.246000.json','["陰陰大滌洞，古色閟積鐵。", "誰橫一石礙，坐與三島絕。", "元同我先去，不見肝肺熱。"]'),
('61365b78-2934-41e6-a0dd-12c06fd03eaa','九鎖山十詠 棲真洞','鄧牧','宋','宋诗','song-poetry','','[]','何年采真游，遺此棲遁跡。',36,'全唐诗/poet.song.246000.json','["何年采真游，遺此棲遁跡。", "流泉金石奏，伏鼠霜雪色。", "浮世幾興亡，殘棋耿苔石。"]'),
('9953e814-002d-4f00-a585-303d072bc74a','九鎖山十詠 龍洞','鄧牧','宋','宋诗','song-poetry','','[]','老龍山中居，出山作霖雨。',36,'全唐诗/poet.song.246000.json','["老龍山中居，出山作霖雨。", "風雲幾聚散，田野正辛苦。", "神仙地位高，使爾司下土。"]'),
('d967697c-ecd5-480b-bae6-1fa11a2ea947','九鎖山十詠 鳳洞','鄧牧','宋','宋诗','song-poetry','','[]','鳳來青天開，鳳去蒼石裂。',36,'全唐诗/poet.song.246000.json','["鳳來青天開，鳳去蒼石裂。", "玄風不復返，世事日消歇。", "永懷接輿歌，勿蹈東魯轍。"]'),
('e64ebcc8-af4e-4ad0-970d-acc813e81858','九鎖山十詠 仙人隠跡','鄧牧','宋','宋诗','song-poetry','','[]','至人猶神龍，變化不可測。',36,'全唐诗/poet.song.246000.json','["至人猶神龍，變化不可測。", "隆然七尺軀，印此一片石。", "我行半江海，空飛杳無跡。"]'),
('54b856c5-de0b-443b-82a8-014b20206143','九鎖山十詠 雲根石','鄧牧','宋','宋诗','song-poetry','','[]','浮雲無定姿，滅沒須臾閒。',36,'全唐诗/poet.song.246000.json','["浮雲無定姿，滅沒須臾閒。", "一朝化頑石，千古遺空山。", "天地亦幻物，誰能詰其端。"]'),
('a794bed1-94f4-400a-8f29-5f9d68bfc0f1','九鎖山十詠 翠蛟亭','鄧牧','宋','宋诗','song-poetry','','[]','寒磵豈成蛟，流泉亦非翠。',36,'全唐诗/poet.song.246000.json','["寒磵豈成蛟，流泉亦非翠。", "色緣映带得，意出飛舞外。", "雖無風霆化，自與江海會。"]'),
('e80de955-b92a-4a6c-83d6-416ec77dd02d','九鎖山十詠 來賢巖','鄧牧','宋','宋诗','song-poetry','','[]','石巖千尺高，曾見坡仙來。',36,'全唐诗/poet.song.246000.json','["石巖千尺高，曾見坡仙來。", "坡仙化黄土，巖石空蒼苔。", "縣知今人游，復令後人哀。"]'),
('010fb3c2-0fe7-4ae5-9e24-505563cfc9ea','九鎖山十詠 丹泉','鄧牧','宋','宋诗','song-poetry','','[]','仙翁鍊丹去，流水作丹色。',36,'全唐诗/poet.song.246000.json','["仙翁鍊丹去，流水作丹色。", "縈盤出九鎖，川后不敢惜。", "豈無得道者，一飲淩八極。"]'),
('f0e2b2ac-0966-459f-bcca-a70fa6c9f4e6','九鎖山十詠 天壇','鄧牧','宋','宋诗','song-poetry','','[]','空山遺天壇，之人在天闕。',36,'全唐诗/poet.song.246000.json','["空山遺天壇，之人在天闕。", "風雷長爲護，草樹不敢茁。", "何當追遐蹤，一笑俯明月。"]'),
('9aac7aa7-f9a7-44b0-9787-de09a9c4359a','大德辛丑六月六日游洞霄和杜南谷','鄧牧','宋','宋诗','song-poetry','','[]','南谷仙翁游八極，千山萬山遠相揖。',64,'全唐诗/poet.song.246000.json','["南谷仙翁游八極，千山萬山遠相揖。", "翩然一笑玄蓋天，草木塵埃總湔滌。", "晉人伏虎老空巖，秦代隠仙遺有聲。", "幸喜仙翁能好客，羽衣談笑晚風清。"]'),
('0e12513d-df20-460e-9f9f-91a9d664df8c','寄友','鄧牧','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我在越，君在吳，馳書邀我游西湖。',156,'全唐诗/poet.song.246000.json','["我在越，君在吳，馳書邀我游西湖。", "我還吳，君適越，遥隔三江共明月。", "明月可望，佳人參差。", "笑言何時，寫我相思。", "知君去掃嚴陵墓，祇把清尊酹黄土。", "浮雲茫茫江水深，感慨空勞弔今古。", "孤山山下約陳實，聯騎須來踏春色。", "西湖千樹花正繁，莫待東風吹雪積。", "有酒如澠，有肉如陵。", "鼓趙瑟，彈秦箏，與君沈醉不用醒。", "人生行樂耳，何必千秋萬歲名。"]'),
('f10dc168-3474-476e-a62b-bd12289afa3b','漢陽郎官湖','鄧牧','宋','宋诗','song-poetry','','[]','仙翁薄暮醉酒歸，杖藜迷却高陽池。',252,'全唐诗/poet.song.246000.json','["仙翁薄暮醉酒歸，杖藜迷却高陽池。", "清風吹花綠陰倒，我笑謂是秋雲移。", "還乘貫月槎，夜過郎官湖。", "崢嶸星斗入江漢，蕩漾槎影如鯨魚。", "九華之真人，邀我倒玉壺，麒麟擘脯供行厨。", "依稀仙樂在空際，碧山四映寒蟾孤。", "舉酒酌寒蟾，明月下飲姮娥俱。", "霓裳拂雲錦，萬荷露瀉瓊瑶卮。", "麾幢晻靄羅煙空，乃有三皇所授之玉童。", "風前飄飄曳廣带，對立十二秋芙蓉。", "清香九曲銀河通，真人綠髪披春風。", "錦袍玉雪照天地，口說姓字安南公。", "是公多逸氣，略與古昔賢豪同。", "時能掃月色，延我石室煙蘿中。", "又言昔同張謂所游地，長歎一覆丹霞鍾。", "風吹仙樂度溪去，我亦醉卧香鑪峰。"]'),
('74f52990-ce76-41b3-b929-cf457836d2d3','輓趙秋曉  其一','陳庚','宋','宋诗','song-poetry','','[]','泮水題名記，靈光獨此翁。',48,'全唐诗/poet.song.246000.json','["泮水題名記，靈光獨此翁。", "褎衣雋曼倩，折角郭林宗。", "湖海襟期別，風濤患難同。", "斯人寧復得，些罷涕無從。"]'),
('672b2152-b3ff-40e0-9ab2-a16fcbacd773','輓趙秋曉  其二','陳庚','宋','宋诗','song-poetry','','[]','客至支筇出，俱云步履强。',48,'全唐诗/poet.song.246000.json','["客至支筇出，俱云步履强。", "禮猶尚筋力，病忍謂膏肓。", "此別終千古，相陪苦一霜。", "蕭蕭亭畔柳，回首重淒凉。"]'),
('130ee65e-a235-4d0e-b018-da78b878eeee','輓趙秋曉  其三','陳庚','宋','宋诗','song-poetry','','[]','取友慚何益，論昏不厭貧。',48,'全唐诗/poet.song.246000.json','["取友慚何益，論昏不厭貧。", "亦公自爲德，而我竟奚因。", "事巧緣何淺，言深死已瀕。", "枕邊呼別意，生死見情真。"]'),
('dcccb6a5-c671-4b1d-9843-fd8415ead2e0','謝友人惠犀皮胡瓶','陳庚','宋','宋诗','song-poetry','','[]','靈犀鱗甲鴟夷腹，塊土能奇詫善埏。',64,'全唐诗/poet.song.246000.json','["靈犀鱗甲鴟夷腹，塊土能奇詫善埏。", "器似虞陶知不窳，規同莊埴巧成圓。", "雕鎸尚喜兼文質，空洞祇堪容聖賢。", "於一器中求不器，願珍嘉惠比韋弦。"]'),
('130d1aa0-f360-4e5b-978c-781ba34e5c0b','冬至寓建陽作','胡一桂','宋','宋诗','song-poetry','','[]','繡日添漢宮，書雲紀晉觀。',84,'全唐诗/poet.song.246000.json','["繡日添漢宮，書雲紀晉觀。", "山家獨奚爲，剛腸占易彖。", "幽人意欣然，起坐視晴漢。", "大化回初陽，漫漫今已旦。", "川泳有遊魚，雲飛見翔雁。", "滯留本何心，永懷發孤歎。", "誠哉利攸往，觀辭思過半。"]'),
('cf73054d-c376-4b49-acd8-1edb7be2309d','至日建中次季真韻','胡一桂','宋','宋诗','song-poetry','','[]','盡日勞勞烟雨裏，此行誰識是歟非。',64,'全唐诗/poet.song.246000.json','["盡日勞勞烟雨裏，此行誰識是歟非。", "翩然芒屩相隨處，正見梅花欲放時。", "太極便堪窺易藴，黄鐘初可驗葭飛。", "天心子半無移改，細玩堯夫至日詩。"]'),
('7c563e85-1aba-4180-ba1a-2a1a7f6191fc','冬青行二首  其一','唐玨','宋','宋诗','song-poetry','','[]','馬箠問髐形，南面欲起語。',60,'全唐诗/poet.song.246000.json','["馬箠問髐形，南面欲起語。", "野麕尚屯束，何物敢盜取。", "餘花拾飄蕩，白日哀后土。", "六合忽怪事，蛻龍挂茅宇。", "老天鑒區區，千載護風雨。"]'),
('09b6b98f-c480-4dd7-bb6a-4426da6358a1','冬青行二首  其二','唐玨','宋','宋诗','song-poetry','','[]','冬青花，不可折，南風吹凉積香雪。',50,'全唐诗/poet.song.246000.json','["冬青花，不可折，南風吹凉積香雪。", "遥遥翠蓋萬年枝，上有鳳巢下龍穴。", "君不見犬之年羊之月，霹靂一聲天地裂。"]'),
('cb0082b3-3e2e-47a3-b5e9-a5cacdbe2a7c','存目','唐玨','宋','宋诗','song-poetry','','[]','詩題：夢中作四首首句：珠亡忽震蛟龍睡一抔自築珠丘土昭陵玉匣走天涯珠鳬玉雁又成埃。',40,'全唐诗/poet.song.246000.json','["詩題：夢中作四首首句：珠亡忽震蛟龍睡一抔自築珠丘土昭陵玉匣走天涯珠鳬玉雁又成埃。"]'),
('5166b19b-012e-49a4-97e8-dc63c92ece3c','送熊退齋歸武夷','蜀翁','宋','宋诗','song-poetry','','[]','君居建州溪，我住東浙尾。',240,'全唐诗/poet.song.246000.json','["君居建州溪，我住東浙尾。", "邂逅入壺山，于今幾寒暑。", "平生譚理道，涉獵頗自喜。", "考擊到精玄，我膚君骨髓。", "君學有根源，君文有規矩。", "寸步履平實，不知虛浮語。", "禮廢彝倫斁，聾盲數百載。", "紫陽當日心，誰復爲鼓舞。", "氣運未回天，人力不能起。", "終焉經久功，或慰奔馳苦。", "讀書要適用，行過言猶恥。", "架空累萬辭，先儒已坐此。", "觀君治教篇，農學相資倚。", "以茲行吾志，萬物當得所。", "奈何人理繆，痛哉時不與。", "君去將安之，波浪更風雨。", "武夷高且深，櫂歌聲未已。", "朝夕足夷猶，尚友朱夫子。", "他年見鰲峰，勢與此山擬。", "了却未完書，相逢定何許。"]'),
('96980e7d-dab9-4b3e-b071-37cf6e19c514','寄菊山','陳梅','宋','宋诗','song-poetry','','[]','老髪戴儒冠，黄金不愛官。',48,'全唐诗/poet.song.246000.json','["老髪戴儒冠，黄金不愛官。", "江湖雙脚健，天地寸心寬。", "山月曉猶白，松風夏亦寒。", "小詩訊猿鶴，聊以慰平安。"]'),
('23e05581-d365-4ef1-ac1d-e10bca4e800c','廣廕亭詩','陳士徽','宋','宋诗','song-poetry','','[]','唐翁靜者閉門飲水啜粥無知音，我能發爾一片冰清心。',292,'全唐诗/poet.song.246000.json','["唐翁靜者閉門飲水啜粥無知音，我能發爾一片冰清心。", "巨風吹天振海浪如屋，此翁林中眠正熟。", "中天渴烏吐火六合新開窯，此翁兩鬢秋颼颼。", "小兒爛羊瓜果盡青紫，此翁臨水洗雙耳。", "蜩蟾蛙蚓聒亂昕夕雷無聲，此翁宴坐觀黄庭。", "編茅斵室大如斗，蒼雪絲絲翳窗牖。", "忍饑學得西山夫，胸中有道癯不枯。", "木榔始花赤已實，百畝沉沉如櫛密。", "露結風高霜氣寒，潤如美竹馨如蘭。", "翁居巷南我巷北，况有薇郎能主客。", "書篚几杖皆清風，相看蔭我冰雪容。", "瓊州歲月不可度，此境中州亦稀遇。", "苦茗滿碗談興亡，日長歸來月滿堂。", "明朝一舸崖州去，世事茫茫隔烟霧。", "袖携毫楮覓扁題，鴻飛冥冥留爪泥。", "爲書廣廕扁翁室，淡墨欹輕醉中筆。", "乘醉更作廣廕詩，千載留與知音知。"]'),
('88bf0253-6830-4165-89b4-3d77b5ec086b','青溪主客歌','汪崇亮','宋','宋诗','song-poetry','','[]','野王手奏淮淝捷，門戶歸來有旌節。',96,'全唐诗/poet.song.246000.json','["野王手奏淮淝捷，門戶歸來有旌節。", "伸眉一笑紫髯秋，袖中猶挾柯亭月。", "山陰主人載雪舟，掀篷繫纜青溪頭。", "平生耳熱欠一識，若爲牽挽行雲留。", "一聲橫玉西風裏，蘆花不動鷗飛起。", "馬蹄依舊入青山，柳梢浸月天如水。"]'),
('eea205b6-4da1-4ec8-a0f5-6379e5b76563','句  其一','汪崇亮','宋','宋诗','song-poetry','','[]','溪鷺踏影立，風蟬曳聲過。',12,'全唐诗/poet.song.246000.json','["溪鷺踏影立，風蟬曳聲過。"]'),
('bf125cf0-482a-47c5-9633-2201dcd941d1','句  其二','汪崇亮','宋','宋诗','song-poetry','','[]','夢回酒醒不知處，月靜人稀方憶君。',16,'全唐诗/poet.song.246000.json','["夢回酒醒不知處，月靜人稀方憶君。"]'),
('76ecfe11-f392-441a-a368-4be823af1afe','句','俞演','宋','宋诗','song-poetry','','[]','殘燈吟夜雨，破榻卧秋山。',12,'全唐诗/poet.song.246000.json','["殘燈吟夜雨，破榻卧秋山。"]'),
('30e1a38d-38c2-482a-b813-53b0a87a4b90','太湖','王道士','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','三萬六千頃，浩蕩三州界。',48,'全唐诗/poet.song.246000.json','["三萬六千頃，浩蕩三州界。", "烟霧四無邊，往往出奇怪。", "洞庭柑已霜，震澤魚極介。", "豈無范蠡舟，我欲從公邁。"]'),
('03a88a58-3d23-499f-b0b2-875db7d32e54','于介翁別去一載偶會高湖謾成唐律以寫相思之意','王道士','宋','宋诗','song-poetry','','[]','高湖回首恰周期，別後青山幾度思。',64,'全唐诗/poet.song.246000.json','["高湖回首恰周期，別後青山幾度思。", "丹竈煙霞空入夢，夜窗風雨憶論詩。", "百年相會寧無約，九日來遊竟失期。", "去去但堅金石操，歲寒松柏有深知。"]'),
('ce2c6dca-0288-4fa7-9c09-502cfe66c626','美閻承旨','王道士','宋','宋诗','song-poetry','','[]','海底珊瑚明月璫，出爲國瑞固難量。',64,'全唐诗/poet.song.246000.json','["海底珊瑚明月璫，出爲國瑞固難量。", "文章能事間重譯，雨露深仁及遠方。", "六合八荒春浩蕩，百家諸子海蒼茫。", "淮王門下孫登客，還許升堂近耿光。"]'),
('d1a20d4f-eac1-475d-ad00-1e41693da2df','至道宮','葉林','宋','宋诗','song-poetry','','[]','猶存巨鑊記熙豐，翠藹春深古路通。',32,'全唐诗/poet.song.246000.json','["猶存巨鑊記熙豐，翠藹春深古路通。", "千百舂鋤一株樹，野田飛下雪花風。"]'),
('74bdcee2-7960-4bc4-bd78-4c2f85fcf0fc','賦洞霄宮隠居十年後','葉林','宋','宋诗','song-poetry','','[]','瓊館高居勢復完，煙重翠疊幾峰巒。',64,'全唐诗/poet.song.246000.json','["瓊館高居勢復完，煙重翠疊幾峰巒。", "山從舞鳳由來遠，洞隔投龍欲去難。", "處處有泉那用汲，巖巖維石宛如磐。", "品題今古知多少，閒把唐僧五字看。"]'),
('cf3ec4de-42b8-4f75-9b2b-bc37d1aa0ce5','石室洞','葉林','宋','宋诗','song-poetry','','[]','低垂石室洞，杖屨易躋攀。',48,'全唐诗/poet.song.246000.json','["低垂石室洞，杖屨易躋攀。", "有路穿雲窟，無門對月關。", "誰騎仙鹿去，我笑國蝸跧。", "若使今猶昨，清宵聞珮環。"]'),
('0bc37015-610b-48a0-99a9-b2d69bd6913d','登石室二首  其一','葉林','宋','宋诗','song-poetry','','[]','遠游貞白二仙家，今日追尋路不賒。',32,'全唐诗/poet.song.246000.json','["遠游貞白二仙家，今日追尋路不賒。", "七十二叢秋色裏，有人曾約去看花。"]'),
('c2c1d9bd-512f-4015-94f8-a24e0803f0fc','登石室二首  其二','葉林','宋','宋诗','song-poetry','','[]','石徑春深疊古苔，洞天無鑰爲誰開。',32,'全唐诗/poet.song.246000.json','["石徑春深疊古苔，洞天無鑰爲誰開。", "白雲本是無心物，風趁松花作雨來。"]'),
('6201f814-7e6c-4467-b7da-81c0abd713b3','呈住山介石','葉林','宋','宋诗','song-poetry','','[]','造物有青眼，名山無赧容。',48,'全唐诗/poet.song.246000.json','["造物有青眼，名山無赧容。", "聲名動猿鶴，道法伏菟龍。", "望氣從關尹，瞻雲自華封。", "懸知仙隠地，可以不迎逢。"]'),
('6e48f577-d6a7-46a0-bc19-7180119ae7e8','腰带水','張炎','宋','宋诗','song-poetry','','[]','犀繞魚懸事已非，水光猶自溼雲衣。',32,'全唐诗/poet.song.246000.json','["犀繞魚懸事已非，水光猶自溼雲衣。", "山中幾日渾無雨，一夜溪痕又減圍。"]'),
('0d1af688-8d88-48eb-b4cf-7b276dfe9260','戊寅臘望會友雙峨得薪字韻','鄭傳之','宋','宋诗','song-poetry','','[]','雙峨文會友，生意藹如春。',48,'全唐诗/poet.song.246000.json','["雙峨文會友，生意藹如春。", "風轉聞啼鳥，冰銷想躍鱗。", "焚香溫宿火，煮茗爇枯薪。", "一座惟吾老，欣然得句新。"]'),
('6a6e58c6-0c10-4212-9d0d-89f57f2b878d','吳季子墓','白珽','宋','宋诗','song-poetry','','[]','聖人如日月，下照無黨私。',168,'全唐诗/poet.song.246000.json','["聖人如日月，下照無黨私。", "藏珠與韞玉，所得自華滋。", "恭惟吳季子，夙稟明睿姿。", "近取子臧節，遠紹泰伯基。", "兩以大國讓，廉風起蠻夷。", "觀樂義已燭，挂劍心如飴。", "時方尚詐力，子獨恪且祇。", "時方事寇攘，子獨甘棄遺。", "孔子不到吳，聞風重齎咨。", "佳城介申浦，采地亦在茲。", "特書寄餘哀，豈不遐邇思。", "惋惋龍蛇翥，皎皎星日垂。", "禹世懷道義，取舍實繫之。", "寄言邦之人，無但峴首悲。"]'),
('224c4213-0a51-4db6-a2c6-a1c87306236e','題斬蛟橋','白珽','宋','宋诗','song-poetry','','[]','桓桓周將軍，英烈照千祀。',180,'全唐诗/poet.song.246000.json','["桓桓周將軍，英烈照千祀。", "少年知自艾，成人不惜死。", "射虎南山下，斫潜北橋底。", "騰拏三日夜，灑血四十里。", "激波爲嶽立，揮刃電亦駛。", "想當批鱗初，見義不見水。", "及其立人朝，矯矯中不倚。", "文學既英發，武事復霆起。", "殲兒善醜正，甘作忠義鬼。", "至今有生氣，耿耿耀青史。", "蘇公百世豪，氣味有相似。", "泊舟蛟川下，洗石題所以。", "平生疾惡意，十有二言裏。", "豐碑刻祠宇，詞翰晉二美。", "二美固足珍，吾取不在是。"]'),
('5f2278aa-7108-443b-a7e7-373f84d205cb','同陳太博諸公登六和塔','白珽','宋','宋诗','song-poetry','','[]','龍山古化城，浮屠峙其巔。',216,'全唐诗/poet.song.246000.json','["龍山古化城，浮屠峙其巔。", "開殿生妙香，金碧森貝筵。", "應真儼若生，倒飛青金蓮。", "頭陀紺林叢，導我丹梯緣。", "初猶藉佛日，閟境鯈已玄。", "回頭失誰何，叫嘯衣相牽。", "且復忍須臾，當見快意天。", "嬌兒詫先登，網戶相鈎連。", "炯若蟻在珠，九曲隨盤旋。", "爛爛滄海開，落落雲氣懸。", "羣峰可俯拾，背閲黄鵠騫。", "奇觀興懦夫，便欲凌飛仙。", "絕頂按坤維，始見南紀偏。", "神京渺何許，王氣須停躔。", "舟車集百蠻，島嶼通人烟。", "一爲帝王州，氣壓三大千。", "罡風灑毛髪，鐸語空蟬聯。", "紅紅杏園花，愧乏慈恩篇。"]'),
('83ea9d40-2c37-4061-a249-f2edf2a0f347','冷泉亭','白珽','宋','宋诗','song-poetry','','[]','靈山本清凈，一泉渟其中。',96,'全唐诗/poet.song.246000.json','["靈山本清凈，一泉渟其中。", "靈山孤飛來，此水將無同。", "山影壓不盡，照見天玲瓏。", "分明千尺冰，不獨疑寒蟲。", "京洛多風塵，到此一洗空。", "炎寒無二心，凜有操者風。", "泊然守空梵，萬劫豈終窮。", "驪山有溫泉，虛築華清宮。"]'),
('66e3a6ec-202f-4ca1-93b0-6b6093cd49a0','題松雪臨郭河陽溪山漁樂圖','白珽','宋','宋诗','song-poetry','','[]','遠山近山何歷歷，下有長溪橫一碧。',64,'全唐诗/poet.song.246000.json','["遠山近山何歷歷，下有長溪橫一碧。", "溪中亦有釣鰲手，此手不遮長安目。", "野橋烟樹接草廬，飛流如練懸空虛。", "截山白雲凝不去，要人寫作巖居圖。"]'),
('358bf795-4fc8-4126-9a36-3509c5b8b287','河南婦','白珽','宋','宋诗','song-poetry','','[]','從軍古云樂，獲罪禱應難。',48,'全唐诗/poet.song.246000.json','["從軍古云樂，獲罪禱應難。", "母望明珠復，夫求破鏡完。", "押衙逢義士，公主奉春官。", "爲報河南婦，天刑不可干。"]'),
('679ab00f-6bbe-499c-86d1-fdc5c2415c45','春日田園雜興','白珽','宋','宋诗','song-poetry','','[]','雨後散幽步，村村社鼓鳴。',48,'全唐诗/poet.song.246000.json','["雨後散幽步，村村社鼓鳴。", "陰晴雖不定，天地自分明。", "柳處風無力，蛙時水有聲。", "幾朝寒食近，吾事及躬耕。"]'),
('a94ed28a-2d21-4b8c-bcb7-cedef99a9b9d','山中懷友','白珽','宋','宋诗','song-poetry','','[]','幾年音問絕，此夕更關情。',48,'全唐诗/poet.song.246000.json','["幾年音問絕，此夕更關情。", "寒雨人孤坐，殘燈雁一聲。", "干戈猶故國，貧病自空城。", "惟有琴堪訴，愁深彈不成。"]'),
('4e2a2052-51c7-4848-beb0-fb887220d11c','清和','白珽','宋','宋诗','song-poetry','','[]','白苧漸相便，因知物候遷。',48,'全唐诗/poet.song.246000.json','["白苧漸相便，因知物候遷。", "空山一雨後，小檻綠陰前。", "鶑在留春思，人幽減晝眠。", "此時風日好，元不似梅天。"]'),
('c3efb145-c1dc-467e-80b0-2e95343c79b4','餘杭四月','白珽','宋','宋诗','song-poetry','','[]','四月餘杭道，一晴生意繁。',48,'全唐诗/poet.song.246000.json','["四月餘杭道，一晴生意繁。", "朱櫻青豆酒，綠草白鵝村。", "水滿船頭滑，風輕袖影翻。", "幾家蠶事動，寂寂晝關門。"]'),
('c6c93744-ba41-4b49-afad-5ed8c127c93d','遊宜興張公洞','白珽','宋','宋诗','song-poetry','','[]','天開福地據雄尊，果老張公幾代孫。',64,'全唐诗/poet.song.246000.json','["天開福地據雄尊，果老張公幾代孫。", "一竅通天纔直上，千崖轉石已平吞。", "山頭白鶴來無影，石上青騾去有痕。", "我欲放身如脫屣，仙凡一轍隔重閽。"]'),
('5b6efb2b-76de-4754-aaa0-3324a104d01a','凈慈禪寺','白珽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','奎額昭回龍屈盤，入門已覺厭塵寰。',64,'全唐诗/poet.song.246000.json','["奎額昭回龍屈盤，入門已覺厭塵寰。", "何當白髪三千丈，來寄清風五百間。", "帝子釜摇金瀲灩，家人卦剔翠孱顔。", "西湖日日船如織，半在南屏第一山。"]'),
('a0ac28c0-250a-4ad4-a6fd-f500d70ad008','湖樓玩雪','白珽','宋','宋诗','song-poetry','','[]','上湖十里捲簾中，幻出瑶華第一宮。',64,'全唐诗/poet.song.246000.json','["上湖十里捲簾中，幻出瑶華第一宮。", "山勢蹴天銀作浪，柳行撲地玉爲虹。", "漁蓑鶴氅同爲我，爵舌羊羔不負公。", "明日鳳池朝退蚤，一鞭曾約試吟驄。"]'),
('d3ec5c34-c0e6-4c89-aa23-4f36f33076d0','酒邊贈朱處士','白珽','宋','宋诗','song-poetry','','[]','烏葛唐巾白苧裘，掃庭終夕共淹留。',64,'全唐诗/poet.song.246000.json','["烏葛唐巾白苧裘，掃庭終夕共淹留。", "醉中談論心猶壯，老去歌歡淚亦流。", "對客呈詩如獻佛，課兒收橘當封侯。", "明年好理西風棹，重約三吳爛漫遊。"]'),
('46d103fd-0af3-4d6e-8dd6-f6f5ce3e09e7','遊天竺後山','白珽','宋','宋诗','song-poetry','','[]','山轉龍泓一徑深，嵐煙吹潤撲衣巾。',64,'全唐诗/poet.song.246000.json','["山轉龍泓一徑深，嵐煙吹潤撲衣巾。", "松蘿掩映似無路，猿鳥往來如有人。", "講石尚存天寶字，御梅嘗識建炎春。", "城中遮日空西望，自與長安隔兩塵。"]'),
('d464ae6c-d412-415a-9f1d-468522f5dc3c','竹陰','白珽','宋','宋诗','song-poetry','','[]','占斷人間瀟洒地，全身水墨畫篔簹。',64,'全唐诗/poet.song.246000.json','["占斷人間瀟洒地，全身水墨畫篔簹。", "非烟非霧一林碧，似雨似晴三徑凉。", "翠袖佳人黯空谷，白髭道士隠南塘。", "數竿醉日君須記，移向西窗補夕陽。"]'),
('2bf6da96-3b68-45ef-8d5e-d85c0a9bd4aa','題蘇東坡書楚頌並菩薩蠻滿庭芳詞卷後','白珽','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','南荒九死幸生還，種樹書成手自刪。',64,'全唐诗/poet.song.246000.json','["南荒九死幸生還，種樹書成手自刪。", "赤壁夢難同楚頌，洞庭樂不減商山。", "人生墮地少如意，老子對天無愧顔。", "千古菟裘有遺恨，斷珪殘璧自人間。"]'),
('ac42f87b-e5aa-4df2-8455-7e83f6e6f28a','續演雅十詩  其一','白珽','宋','宋诗','song-poetry','','[]','海青羽中虎，燕燕能制之。',24,'全唐诗/poet.song.246000.json','["海青羽中虎，燕燕能制之。", "小隙沈大舟，關尹不吾欺。"]'),
('579d0f60-9dca-49e6-9281-f156f4faf711','續演雅十詩  其二','白珽','宋','宋诗','song-poetry','','[]','草食押不蘆，雖死元不死。',24,'全唐诗/poet.song.246000.json','["草食押不蘆，雖死元不死。", "未見滌腸人，先聞棄簀子。"]'),
('9bf0104f-5a91-48e9-af2c-21bf748ce0e2','續演雅十詩  其三','白珽','宋','宋诗','song-poetry','','[]','誰令珠玉唾，出彼藜藿腸。',24,'全唐诗/poet.song.246000.json','["誰令珠玉唾，出彼藜藿腸。", "仁人不爲寶，良賈宜深藏。"]'),
('d9b17afa-0fd7-4cfa-9822-d34cc7a0e16c','續演雅十詩  其四','白珽','宋','宋诗','song-poetry','','[]','嬰啼聞木枝，羝乳見茅茹。',24,'全唐诗/poet.song.246000.json','["嬰啼聞木枝，羝乳見茅茹。", "何如百年身，反爾無根據。"]'),
('d329e5d3-9230-4db2-8bf8-85d038a1b93f','續演雅十詩  其五','白珽','宋','宋诗','song-poetry','','[]','西狩獲白麟，至死意不吐。',24,'全唐诗/poet.song.246000.json','["西狩獲白麟，至死意不吐。", "代北有角端，能通諸國語。"]'),
('aaba5658-6392-4c80-8887-7830f9ae084d','續演雅十詩  其六','白珽','宋','宋诗','song-poetry','','[]','纔脫海鶴啄，已登方物輿。',24,'全唐诗/poet.song.246000.json','["纔脫海鶴啄，已登方物輿。", "仰面勿啾啾，我長非僑如。"]'),
('4f237b22-a883-43e8-a00d-43541323566c','續演雅十詩  其七','白珽','宋','宋诗','song-poetry','','[]','羯尾大如斛，堅車載不起。',24,'全唐诗/poet.song.246000.json','["羯尾大如斛，堅車載不起。", "此以不掉滅，彼以不掉死。"]'),
('926039f0-8442-4f0c-b322-fada52052d36','續演雅十詩  其八','白珽','宋','宋诗','song-poetry','','[]','八珍殽龍鳳，此出龍鳳外。',24,'全唐诗/poet.song.246000.json','["八珍殽龍鳳，此出龍鳳外。", "荔枝配江䖴，徒誇有風味。"]'),
('fd7c3050-4c67-4fbe-803c-6753fa489937','續演雅十詩  其九','白珽','宋','宋诗','song-poetry','','[]','灤人薪巨松，童山八百里。',24,'全唐诗/poet.song.246000.json','["灤人薪巨松，童山八百里。", "世無奚超勇，惆悵渡易水。"]'),
('db5ad32c-5bec-4cf9-874e-655e09b0d556','續演雅十詩  其一○','白珽','宋','宋诗','song-poetry','','[]','兩駝侍雪立，終日饑不起。',24,'全唐诗/poet.song.246000.json','["兩駝侍雪立，終日饑不起。", "一覺沙日黄，肉屏那足擬。"]'),
('596284d1-5818-491e-a233-363aff6f36c7','積雪峰訪梁道士','白珽','宋','宋诗','song-poetry','','[]','驚羽穿林看細碎，健輿繞石聽欹斜。',32,'全唐诗/poet.song.246000.json','["驚羽穿林看細碎，健輿繞石聽欹斜。", "道人住近茅峰北，一簇樓臺五色霞。"]'),
('3ef62083-9169-448e-9628-b7e07eb1b354','湖居雜興八首  其一','白珽','宋','宋诗','song-poetry','','[]','御舟初出賞春霏，傳是諸王與后妃。',32,'全唐诗/poet.song.246000.json','["御舟初出賞春霏，傳是諸王與后妃。", "香霧漸深簾幙暗，日斜微見淡黄衣。"]'),
('e4d5dd58-093e-42d6-ac5a-9a6a2b932d55','湖居雜興八首  其二','白珽','宋','宋诗','song-poetry','','[]','脈脈吹香屋角梅，背風移燭小簾開。',32,'全唐诗/poet.song.246000.json','["脈脈吹香屋角梅，背風移燭小簾開。", "鳳城幾日元宵近，一片簫聲水上來。"]'),
('f1cb04de-5d94-4bcb-9e24-4c1571951d63','湖居雜興八首  其三','白珽','宋','宋诗','song-poetry','','[]','龍舟曉發斷橋西，別有輕舟兩兩隨。',32,'全唐诗/poet.song.246000.json','["龍舟曉發斷橋西，別有輕舟兩兩隨。", "春色可人晴較穩，酒家爭出柳梢旗。"]'),
('c9087bac-911f-4b6a-aec8-07a4ec72596e','湖居雜興八首  其四','白珽','宋','宋诗','song-poetry','','[]','相國平泉水竹居，吳山花石世間無。',32,'全唐诗/poet.song.246000.json','["相國平泉水竹居，吳山花石世間無。", "遊人馬上休回首，一半春風在裏湖。"]'),
('f588655e-5701-45bc-9f0c-8be146b6ac5f','湖居雜興八首  其五','白珽','宋','宋诗','song-poetry','','[]','雨後林塘夏亦秋，一葫蘆酒在船頭。',32,'全唐诗/poet.song.246000.json','["雨後林塘夏亦秋，一葫蘆酒在船頭。", "醉來深入荷花去，卧看青天飛白鷗。"]'),
('ad4651cc-638c-4e35-8fbb-20f43f97fbb7','湖居雜興八首  其六','白珽','宋','宋诗','song-poetry','','[]','三賢猶得仰高風，冠服雖殊氣味同。',32,'全唐诗/poet.song.246000.json','["三賢猶得仰高風，冠服雖殊氣味同。", "後五百年無繼者，桃花含笑夕陽中。"]'),
('adaf31d2-c286-47b0-baca-75419c1428c6','湖居雜興八首  其七','白珽','宋','宋诗','song-poetry','','[]','車魚人散水風腥，雨色凉分柳外晴。',32,'全唐诗/poet.song.246000.json','["車魚人散水風腥，雨色凉分柳外晴。", "回首夕陽都落盡，忽然東向數峰明。"]'),
('2e731ea3-d1d7-4b0b-84bb-e7ac930166c0','湖居雜興八首  其八','白珽','宋','宋诗','song-poetry','','[]','萬樹芙蓉兩蘂宮，秋風開遍水邊叢。',32,'全唐诗/poet.song.246000.json','["萬樹芙蓉兩蘂宮，秋風開遍水邊叢。", "白牆遮盡紅牆出，只見紅牆一半紅。"]'),
('18541fa0-dc17-42f1-8ce3-7faf5f40458a','翔泳堂酒邊','白珽','宋','宋诗','song-poetry','','[]','瓌辭度得雪兒歌，濃墨斜書碧玉柯。',32,'全唐诗/poet.song.246000.json','["瓌辭度得雪兒歌，濃墨斜書碧玉柯。", "醉折芙蓉薰酒盞，裏湖凉似外湖多。"]'),
('6ba08b25-d47b-4057-ab1a-f0e160a13696','題江貫道百牛圖','白珽','宋','宋诗','song-poetry','','[]','幾年散放桃林後，餘四百蹄猶可騎。',32,'全唐诗/poet.song.246000.json','["幾年散放桃林後，餘四百蹄猶可騎。", "攬鏡挂書多自在，能騎惟有一凝之。"]'),
('7e0716b2-d4c9-4b20-87d0-6e7f5678f365','題龔翠巖中山出遊圖','白珽','宋','宋诗','song-poetry','','[]','何處張弧鬼一車，中山曾見夜蒐圖。',32,'全唐诗/poet.song.246000.json','["何處張弧鬼一車，中山曾見夜蒐圖。", "紛紛眼底朱成碧，後乘鍾家有此姝。"]'),
('edc16d4d-3c1a-4fc2-b3ea-9b0085ab9fcd','玉清宮與趙達夫鮮于樞聯句二首','白珽','宋','宋诗','song-poetry','','[]','湖光漠漠水禽飛，堤柳斜斜带夕暉。',96,'全唐诗/poet.song.246000.json','["湖光漠漠水禽飛，堤柳斜斜带夕暉。", "二月江南好天氣，初陽臺上愜春衣。", "巾子峰頭艤釣船，初陽臺上坐鳴絃。", "出雲高樹明殘日，過雨蒼苔泣細泉。", "絕俗誰能繼高躅，凌雲我欲學飛仙。", "還家正恐鄉人間，化鶴歸來知幾年。"]'),
('544f152b-ca9d-4745-a0cc-5e531a8f14b8','靈隠寺暮歸','白珽','宋','宋诗','song-poetry','','[]','山色晚蒼蒼，山門下夕陽。',48,'全唐诗/poet.song.246000.json','["山色晚蒼蒼，山門下夕陽。", "栴林飄槲葉，新月到禪床。", "徑出千峰秀，亭迴一澗長。", "淹留不可及，露濕薜衣裳。"]'),
('5406e8bd-edf4-4940-b12b-94c800dc5cf7','宿上天竺','白珽','宋','宋诗','song-poetry','','[]','名山倦游歷，挂起手中藤。',48,'全唐诗/poet.song.246000.json','["名山倦游歷，挂起手中藤。", "佛國三生石，天巖百歲僧。", "定回松院磬，吟苦雪龕燈。", "愧我心猶雜，何因問二乘。"]'),
('509b6b7e-2580-4354-8ecf-74859506f04d','西湖訪古','白珽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','隠約湖山一點青，秋風歸去阻雲程。',32,'全唐诗/poet.song.246000.json','["隠約湖山一點青，秋風歸去阻雲程。", "貝宮珠闕無尋處，夜夜凌波哭月明。"]'),
('0036299a-d855-4cc8-9b2f-9ef0b50f84fa','山居懷林處士','白珽','宋','宋诗','song-poetry','','[]','昔有林處士，結廬鄰峰巔。',132,'全唐诗/poet.song.246000.json','["昔有林處士，結廬鄰峰巔。", "年年不入城，梅花有佳聯。", "童鶴三數口，負郭十畝田。", "弟姪列朝裾，咸平好時年。", "人品既已高，奉養常充然。", "嗟我何爲者，日用買山錢。", "愛詩不能佳，未了區中緣。", "空有一寸心，羨殺處士賢。", "飽看貴人面，不若饑看天。", "搥床呼伯雅，且此相周旋。", "有田足幾時，卓哉坡翁言。"]'),
('301e598b-c8c5-447f-901c-7d1b2112b858','題鄭子真畫四季詩意  其一','白珽','宋','宋诗','song-poetry','','[]','紅杏綠楊，永晝野服。',30,'全唐诗/poet.song.246000.json','["紅杏綠楊，永晝野服。", "柴門散仙，莫道無人。", "知處東風，都在吟箋。"]'),
('e553c30f-4f9f-4fe9-b69d-24230cc3c556','題鄭子真畫四季詩意  其二','白珽','宋','宋诗','song-poetry','','[]','蓮葉吹香，澹澹扁舟。',30,'全唐诗/poet.song.246000.json','["蓮葉吹香，澹澹扁舟。", "撐港斜斜，驚散一行。", "白鷺西風，捲起梨花。"]'),
('a3439bc9-fbff-46c1-9cfd-1e535e842d83','贈張知府周卿','白珽','宋','宋诗','song-poetry','','[]','人品中原說此翁，雄文直氣耿心胸。',64,'全唐诗/poet.song.246000.json','["人品中原說此翁，雄文直氣耿心胸。", "幾年天上張公子，今日雲間陸士龍。", "來暮已聞歌五袴，平反何翅祿千鍾。", "相從愧落諸公後，拭目西巖第一峰。"]'),
('cbb1145e-35c6-48b3-ad54-40788c8b0307','贈青龍任月山','白珽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','傾蓋相逢意已親，風流儒雅邁同倫。',64,'全唐诗/poet.song.246000.json','["傾蓋相逢意已親，風流儒雅邁同倫。", "曾來東閣觀奇士，又向西湖見偉人。", "放棹小溪梅皪皪，敲棋深院燭燐燐。", "懸知後夜相懷切，帆落胥山月一輪。"]'),
('1686bd10-05e9-439d-a96a-e620dd52d534','題洞霄宮藥圃','白珽','宋','宋诗','song-poetry','','[]','仙翁曾播植，瓊圃尚敷榮。',48,'全唐诗/poet.song.246000.json','["仙翁曾播植，瓊圃尚敷榮。", "春日祥光滿，秋風瑞實成。", "黄精宜益壽，萱草足忘情。", "候採靈芝服，還應羽翼生。"]'),
('5a2ae691-754d-4a2e-b5a4-ff162f0d7c73','蛾眉亭','白珽','宋','宋诗','song-poetry','','[]','秦赭鑿填石，不受鞭箠考。',192,'全唐诗/poet.song.246000.json','["秦赭鑿填石，不受鞭箠考。", "零落楚江滸，相峙矗三島。", "穿松得細徑，據一陵二小。", "奔流浩浩來，五色爛華藻。", "至寶地不惜，絕境天所造。", "誰言兩蛾黛，功奪京兆巧。", "終朝對顰蹙，似爲今古惱。", "然犀磯沉沉，跨鯨月皎皎。", "絲綸三千丈，蒙衝百萬櫂。", "天風吹過夢，多憂只空老。", "今者吾與子，所愜在幽討。", "供帳莫匆匆，槃觴從草草。", "雅琴鼓一再，領此風日好。", "臨崖發清嘯，倚樹或顛倒。", "禮存玉帛外，縱弛或一道。", "興極不知歸，白鷗破晴昊。"]'),
('5d9cbf8a-c749-4b7f-a966-d9d76855680c','李翰林墓','白珽','宋','宋诗','song-poetry','','[]','出城得佳山，兩峰特奇詭。',120,'全唐诗/poet.song.246000.json','["出城得佳山，兩峰特奇詭。", "一如植躬圭，一峰拱而侍。", "我見猶愛之，而况謫仙子。", "孤墳在其下，政爾直一死。", "謫仙真仙人，出處見諸史。", "豈敢傲吾君，辛苦植唐祀。", "嗟予偘偘者，塵土正如此。", "停車不忍發，載拜顙有泚。", "仰止青山高，清風與終始。", "孰謂千載人，不在天地裏。"]'),
('00b44ec4-67a9-4230-a023-bb1e242ba23b','題如鏡凈講師房','白珽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','娛老林房世路賒，塵埃飛不到袈裟。',64,'全唐诗/poet.song.246000.json','["娛老林房世路賒，塵埃飛不到袈裟。", "西湖草木雖同土，北寺烟霞自一家。", "靜敞白間翻貝葉，閒輸赤仄養椒花。", "鑑光炯炯輝今古，身後何須用五車。"]'),
('db3abde7-e1de-453c-bf63-37c62983bd3c','春日重過如鏡上人房','白珽','宋','宋诗','song-poetry','','[]','憶昔敲門賦瑞筠，鹿園佳話又重新。',64,'全唐诗/poet.song.246000.json','["憶昔敲門賦瑞筠，鹿園佳話又重新。", "屋頭能拓三三徑，林下知非陸陸人。", "鑿沼何須晉康樂，種蓀還憶楚靈均。", "老師鍊得心如鏡，更把高臺比月輪。"]'),
('92de3a7a-57bc-4a82-b963-04cafd252699','題惠山','白珽','宋','宋诗','song-poetry','','[]','名山名剎大佳處，紺殿翠宇開雲霞。',64,'全唐诗/poet.song.246000.json','["名山名剎大佳處，紺殿翠宇開雲霞。", "陸羽廼事已千載，九龍諸峰元一家。", "雨前茶有如此水，月裏樹豈尋常花。", "奇奇怪怪心語口，無根拄杖任橫斜。"]'),
('c43df040-4a57-45b4-a020-3145137d15f0','題碧桃折枝','白珽','宋','宋诗','song-poetry','','[]','玄都千樹欲無枝，全得春風爛漫吹。',32,'全唐诗/poet.song.246000.json','["玄都千樹欲無枝，全得春風爛漫吹。", "曉露未晞紅郁郁，仙源長在日遲遲。"]'),
('f9a08f56-591c-4c0e-978a-e59c87b556ab','弔林處士墓','白珽','宋','宋诗','song-poetry','','["\u897f\u6e56"]','千古西湖見一賢，斷碑猶在草芊芊。',64,'全唐诗/poet.song.246000.json','["千古西湖見一賢，斷碑猶在草芊芊。", "人間豈少題梅者，石上誰來酹菊泉。", "陳柏墓門疑是宅，唐衣廟貌望如仙。", "可憐遼鶴無消息，寂寞春風二百年。"]'),
('95896226-f12d-4b3f-80dd-b88c34b6dd15','擊蛇笏','白珽','宋','宋诗','song-poetry','','[]','孔明廟前柏，手版賊其枝。',168,'全唐诗/poet.song.246000.json','["孔明廟前柏，手版賊其枝。", "枯秭無生氣，衆目炫一時。", "何如孔公笏，鐵面含霜姿。", "虺蛇何足道，正氣屢奸欺。", "祥符慶曆間，豈無纖人斯。", "聞之膽爲落，不在彼在茲。", "聖學億萬年，聖源浩無涯。", "八傳得巨源，憤學求似之。", "遺經與遺物，保護如嬰兒。", "萬里去復遠，見者咸齎咨。", "况此一尺槐，千載孔林思。", "非無原壤杖，非無少正鈹。", "用舍各有時，小大各有施。", "疇能起段公，共賦甘棠詩。"]'),
('74402246-ad47-410f-ab84-32e0789528be','寄天香庵恬上人','白珽','宋','宋诗','song-poetry','','[]','門掩天香竹樹叢，了無塵翳此心同。',64,'全唐诗/poet.song.246000.json','["門掩天香竹樹叢，了無塵翳此心同。", "東林社散圖空在，南國山多夢不通。", "白草秋閒支遁馬，黄沙春斷子卿鴻。", "思君記得逢君處，一片歸雲海樹空。"]'),
('6cbe0241-3e4c-40e8-bf50-819b75b7bbbc','岳武穆精忠廟','白珽','宋','宋诗','song-poetry','','[]','國勢已如此，孤忠天地知。',48,'全唐诗/poet.song.246000.json','["國勢已如此，孤忠天地知。", "死生同父子，姦宄繫安危。", "偃月無封檜，栖霞有謚碑。", "中原遺老在，歲歲夢王師。"]'),
('c452bccd-8f90-4783-879e-dfef1cc9268b','三月八日過西馬塍','白珽','宋','宋诗','song-poetry','','[]','散策好春日，湖西古馬塍。',48,'全唐诗/poet.song.246000.json','["散策好春日，湖西古馬塍。", "陰晴雖不定，天地自分明。", "柳處風無力，蛙時水有聲。", "園家分半席，問得御花名。"]'),
('90abeb51-33f6-48a6-8eaf-9dae40b4f774','過東寺','白珽','宋','宋诗','song-poetry','','[]','倚空樓閣競翬飛，鐵鳳金鈴一望齊。',32,'全唐诗/poet.song.246000.json','["倚空樓閣競翬飛，鐵鳳金鈴一望齊。", "多少流民無片瓦，江南四月雨凄凄。"]'),
('d7da23da-583b-4fa8-b880-da920acb1782','止征婦哭','白珽','宋','宋诗','song-poetry','','[]','戰國曾聞挾兩戈，病中軍不渡交河。',32,'全唐诗/poet.song.246000.json','["戰國曾聞挾兩戈，病中軍不渡交河。", "一身同爲明庭死，死敵强于死病多。"]'),
('a7a18235-8c3e-465a-a92f-979606cbc3c0','題王大令保母帖','白珽','宋','宋诗','song-poetry','','[]','大令書法美少年，玉函金籥隨飛烟。',160,'全唐诗/poet.song.246000.json','["大令書法美少年，玉函金籥隨飛烟。", "纍纍一百又五字，豈意近出黄閍磚。", "字奇文古兩超絕，保母從茲傾衆帖。", "誰將瓦合嘲玉碎，一片孤衷本相接。", "快劍橫斫鐵山摧，戲龍猛蹴銀河欹。", "方庭無月天地黑，仰視別有星離離。", "浪言貞石志千載，不及永和漥硯在。", "白石已仙千里死，千百人中幾人愛。", "蘭亭信美如捕風，貴耳賤目人響從。", "三日嘔血饑搥胸，葉公畫龍懼真龍。"]'),
('91c76f75-35f1-4a24-9b14-b6b0e1dba39a','宋鐃歌鼓吹曲  其一','謝翱','宋','宋诗','song-poetry','','[]','日離海，青曈曨。',58,'全唐诗/poet.song.246000.json','["日離海，青曈曨。", "沃以積水，涵蒼穹。", "神光隠，豹霧空。", "氣呼吸，爲蛇龍。", "赤雲衣，紫霓從。", "吹白衆宿，歌大風。", "天吳遁，清海宮。"]'),
('c95d1d23-26b9-4c62-8e47-bb26922d81df','宋鐃歌鼓吹曲  其二','謝翱','宋','宋诗','song-poetry','','[]','天馬黄，産異方。',104,'全唐诗/poet.song.246000.json','["天馬黄，産異方。", "龍爲馬，白照夜。", "氣汗雲，聲篲野。", "備法衣，引宸駕。", "騰天垠，倏變化。", "閏之餘，劘以霸。", "閲八姓，瞬代謝。", "驅祥靈，入罟擭。", "皇上帝，監于下。", "誓無譁，出既禡。", "市日中，不易賈。", "坐明堂，朝諸夏。", "賚萬方，錫純嘏。"]'),
('79393746-8907-4bf0-baaf-63e3dbf173b8','宋鐃歌鼓吹曲  其三','謝翱','宋','宋诗','song-poetry','','[]','黎之野，彌蒼莽。',117,'全唐诗/poet.song.246000.json','["黎之野，彌蒼莽。", "迤壺關，屬上黨。", "有雄矯健，曰餘宿將。", "于故之思，泣示厥像。", "倚孽狐，勢方張。", "辨臣獻議，勸下太行。", "趨懷孟虎牢，計之上。", "爭洛邑，以東鄉。", "王師奄至，扼其吭。", "帝授方略，中厥狀。", "獸窮駭突，死卒以煬。", "脅從已逮，孥肆放。", "凱歌回，皇威暢。"]'),
('8e8e1638-72c3-4ff4-b5b1-53ff9cb80e7e','宋鐃歌鼓吹曲  其四','謝翱','宋','宋诗','song-poetry','','[]','上臨墉，戈耀日。',109,'全唐诗/poet.song.246000.json','["上臨墉，戈耀日。", "韎韋指顧，流電疾。", "罪止其魁，不及卒。", "其魁則頑，曰予虢自出。", "坐于轅門，斧以率歸。", "子往諭，泣股栗。", "語中其肝，至畢述。", "侍不及屏，沮回遹鞠。", "投于燎，甘所即。", "皇仁閔下，焉止蹕。", "貔貅徹竈，歸數實。", "獲其棘矢，納世室。"]'),
('19c5b0a4-12b0-405d-9c8d-2e3862f30013','宋鐃歌鼓吹曲  其五','謝翱','宋','宋诗','song-poetry','','[]','軍澧南，潰飛鳥。',97,'全唐诗/poet.song.246000.json','["軍澧南，潰飛鳥。", "鷹隼北來，龍蛇夭矯。", "帝有初命，奉致討。", "臨於荆，妖孽既掃。", "胡驅而孕雉，入蒼莽以保。", "王旅長驅，颯振槁。", "以仁易暴，戒擊剽。", "惟荆衡及郴，士如林，磔其節蟊。", "春葩秋陰，我有造于南。", "式敷德音。"]'),
('9135f622-527e-4f6a-a1c0-3473c118f0bb','宋鐃歌鼓吹曲  其六','謝翱','宋','宋诗','song-poetry','','[]','鄰之震，震于戶。',89,'全唐诗/poet.song.246000.json','["鄰之震，震于戶。", "戒登陴，徹守御。", "神威掩至，不及拒。", "沿楚以南，菁茅宿莽。", "獻于王吏，奉厥土。", "天子有詔，侯西楚。", "自南北東，皆我疆。", "龍旗虎節，拜降王。", "秦戈鞏甲，期韜藏。", "冕旒當中，垂衣裳。"]'),
('9d6f884c-3b3d-441f-bf73-45004d5d22e1','宋鐃歌鼓吹曲  其七','謝翱','宋','宋诗','song-poetry','','[]','母思悲，母于歸。',81,'全唐诗/poet.song.246000.json','["母思悲，母于歸。", "母聞帝語，妾歸無所。", "妾生并土，蜀野芒芒，奄失其疆。", "初帝謂母，子昶來，小者侯，大者王。", "有痍其肌，載粟於創。", "畢有下土，方歸母于鄉。", "天不女奪，朕言不忘。"]'),
('6b3d410c-6b2a-4da9-ad2a-dcd7bde80cb3','宋鐃歌鼓吹曲  其八','謝翱','宋','宋诗','song-poetry','','[]','象之奔斯，惟迹蹶蹶。',82,'全唐诗/poet.song.246000.json','["象之奔斯，惟迹蹶蹶。", "魚麗駕空，雲鳥潰。", "南草浮浮，順於貔貅。", "焚其帑，實棄厥陬。", "皇風播，平𥊧瞀。", "星辰起，皆北走。", "唐季以來，逆雛來咮。", "嶺海肅清，無留後。", "于汴獻囚，凱歌奏。"]'),
('a59cdc3b-6b56-4d05-8d66-4cba94cd274b','宋鐃歌鼓吹曲  其九','謝翱','宋','宋诗','song-poetry','','[]','帝命將臣，誓師于征。',121,'全唐诗/poet.song.246000.json','["帝命將臣，誓師于征。", "伯牙于庭，曰無劉我人。", "曲阿惟唐，以及豫章。", "孽于南國，楚粵是疆。", "我師孔武，聿禽其王。", "始怒臯臯，將臣不懌。", "曰如上命，即起予疾。", "弓韜於衣，刃以不血。", "收其石程，焚其侈淫。", "視于丁寧，筈羽不飲。", "取其鎛磬，以獻于京。", "于廟告成，垓埏既平。"]'),
('a3e78020-b6c1-47d5-8358-08f244c87f36','宋鐃歌鼓吹曲  其一○','謝翱','宋','宋诗','song-poetry','','[]','版圖歸，歸職方。',85,'全唐诗/poet.song.246000.json','["版圖歸，歸職方。", "昔服跗注，備戎行。", "帝錫之斾，龍鳥章。", "酬獻命與胥，今上及秦王。", "外臣拜稽首，笑頷帝色康。", "畢同軌，來於梁。", "曄靈奕奕，敷重光。", "願止劍履，覲带裳。", "四海臣妾，配虞唐。"]'),
('4834bbb0-cde6-48ad-b6fe-ae1faadb557a','宋鐃歌鼓吹曲  其一一','謝翱','宋','宋诗','song-poetry','','[]','清源無諸邦，力弱臣秣陵。',96,'全唐诗/poet.song.246000.json','["清源無諸邦，力弱臣秣陵。", "間道遣進表，九門望日旌。", "願齒鄒與郳，自達天子庭。", "四鄰彫霸業，國除洗天兵。", "皇靈暢遐外，蜑俗邇聲明。", "歸其所隸州，乞身奉朝請。", "帝命得陪祀，湯沐在王城。", "從茲附庸畢，歌以頌河清。"]'),
('9e8f89e6-ceb9-4509-b2ef-d9fbc3460ad6','宋鐃歌鼓吹曲  其一二','謝翱','宋','宋诗','song-poetry','','[]','上之回，舞干戚。',118,'全唐诗/poet.song.246000.json','["上之回，舞干戚。", "鳴鸞在鑣，士飽力。", "桴鼓轟騰，罕山北。", "餘刃恢恢，軍容肅穆。", "王畿主辰，參後服神。", "繼聖伐功，卒扼以偏師，斷北狄。", "矢菆鳴房，蝟集的。", "質子援絕，親銜璧。", "并俗嚬嚬，附于化，以安得。", "其屈産，歸帝閑。", "四夷君長，來稱藩。", "籥節夷樂，示子孫。"]'),
('24e55164-60e0-4810-95e1-6cbe1a37f2c3','宋騎吹曲 親征曲第一','謝翱','宋','宋诗','song-poetry','','[]','雲屯列竈驅貔貅，殿前殺馬祭蚩尤。',64,'全唐诗/poet.song.246000.json','["雲屯列竈驅貔貅，殿前殺馬祭蚩尤。", "勾陳蒼蒼太白濕，賊帳夢驚繞營日。", "軍呼萬歲摧太行，華留東抹流電光。", "重華繼堯坐垂拱，并土再駕無葛疆。"]'),
('d8a2824d-d3b7-49a5-9d47-b559df3a9f30','宋騎吹曲 回鑾曲第二 其一','謝翱','宋','宋诗','song-poetry','','[]','徂暑黎陽車駕歸，掃清氛翳兵更衣。',48,'全唐诗/poet.song.246000.json','["徂暑黎陽車駕歸，掃清氛翳兵更衣。", "江都朔雲車駕出，凱歌消冰供尚食。", "都人引領望翠華，征人一月俱還家。"]'),
('0c45c5ea-cb27-4baf-b81f-45b1858e3acc','宋騎吹曲 回鑾曲第二 其二','謝翱','宋','宋诗','song-poetry','','[]','長堤夜幸士素飽，孤城沈竈無飛鳥。',32,'全唐诗/poet.song.246000.json','["長堤夜幸士素飽，孤城沈竈無飛鳥。", "從征鹵簿拜上恩，太常朝上回鑾表。"]'),
('5587ba47-8d67-4276-b96e-283ccd2f22b5','宋騎吹曲 回鑾曲第二 其三','謝翱','宋','宋诗','song-poetry','','[]','都人望氣歸瑶闕，星掃茸頭落參伐。',32,'全唐诗/poet.song.246000.json','["都人望氣歸瑶闕，星掃茸頭落參伐。", "西人冉冉留紫雲，六飛擁日歌回軍。"]'),
('8f2f9efc-e94e-4037-b8dc-b32938b4cddb','宋騎吹曲 遣將曲第三 其一','謝翱','宋','宋诗','song-poetry','','[]','天門雷動開風雲，內前盡給羽林軍。',80,'全唐诗/poet.song.246000.json','["天門雷動開風雲，內前盡給羽林軍。", "聖人神武授方略，斬將搴旗各駿奔。", "王師所過如時雨，洗濯焦枯嚮荆楚。", "重宣德意吊遺黎，素服軍前釋俘虜。", "全家到闕拜上恩，詔書爲築先臣墓。"]'),
('e08a7e3c-1991-40de-af91-b9248c560bc6','宋騎吹曲 遣將曲第三 其二','謝翱','宋','宋诗','song-poetry','','[]','神風流霆驅偃草，天兵夜下西南道。',80,'全唐诗/poet.song.246000.json','["神風流霆驅偃草，天兵夜下西南道。", "虎賁長戟來鳳州，歸峽銜枚疾如掃。", "廟謨萬里諗諸將，山川曲折圖形狀。", "天同鬼授契若符，坐減罘罳虜供帳。", "歸來論功授節鎮，鐃鼓殿前歌破陣。"]'),
('4d9f8599-462c-448b-8d9d-73b3c97e790f','宋騎吹曲 歸朝曲第四 其一','謝翱','宋','宋诗','song-poetry','','[]','荆南萬里朝天道，巫女雲荒産芳草。',80,'全唐诗/poet.song.246000.json','["荆南萬里朝天道，巫女雲荒産芳草。", "錦韉道賜带盤鵰，方物南來進龍腦。", "願陪郊祀依日光，供張歸朝親奉表。", "勳階邑食及隸人，移鎮徐戎作家廟。", "人生富貴侯與王，四海爲家皆故鄉。"]'),
('c6ca5964-2f0d-4ca4-82f2-6fe9ab5d121f','宋騎吹曲 歸朝曲第四 其二','謝翱','宋','宋诗','song-poetry','','[]','勾吳月令牽牛中，翟茀乘風來閟宮。',80,'全唐诗/poet.song.246000.json','["勾吳月令牽牛中，翟茀乘風來閟宮。", "隨王劍履朝上殿，黄門夜趣長春宴。", "昭容引班入內朝，龍衮當中開雉扇。", "宴罷朝辭生局促，詔賜離宮作湯沐。", "先王烝嘗澤有差，上恩許歌陌上花。"]'),
('377d2e56-8eb9-4daa-8f24-e6a432d0f3d2','宋騎吹曲 諭歸朝曲第五','謝翱','宋','宋诗','song-poetry','','[]','淮南草濕網蟲露，家在先朝父尚主。',64,'全唐诗/poet.song.246000.json','["淮南草濕網蟲露，家在先朝父尚主。", "真人御極四海歸，偃蹇不朝稱節度。", "夜持鐵券爲爾賜，上恩特遣儀鑾使。", "神離魄奪取族夷，功臣效命錫龍旂。"]'),
('32b95161-eefb-4a60-bc4d-268b8d08ed25','宋騎吹曲 李侍中妾歌第六','謝翱','宋','宋诗','song-poetry','','[]','李筠愛將唯儋珪，美人姓劉筠侍兒。',80,'全唐诗/poet.song.246000.json','["李筠愛將唯儋珪，美人姓劉筠侍兒。", "城危搶撥不得力，雨損鉛華帳下啼。", "擁髻前言馬有幾，猶說閨中那問此。", "赤龍從東乘日車，火繞城門內蛇死。", "英雄際會風雲奔，婦人思報羅裳恩。"]'),
('e6248b07-96c0-42a3-a48e-1bb388e40afc','宋騎吹曲 孟蜀李夫人詞第七','謝翱','宋','宋诗','song-poetry','','[]','春荒曲薄蠶叢土，屈狄歸朝辭廟主。',80,'全唐诗/poet.song.246000.json','["春荒曲薄蠶叢土，屈狄歸朝辭廟主。", "官家呼母恩許歸，劍閣并門無處所。", "故衣升屋棺四繞，出門哭子汴州道。", "回腸酹酒三致辭，巴蜀如歸化啼鳥。", "老身不食追爾魂，鹵簿臨門拜上恩。"]'),
('eaa8bf78-96be-4f5c-b05b-a5d65d2752e0','宋騎吹曲 南唐奉使曲第八','謝翱','宋','宋诗','song-poetry','','[]','孤城圍中拜右史，侍書猶對重瞳子。',80,'全唐诗/poet.song.246000.json','["孤城圍中拜右史，侍書猶對重瞳子。", "請行忼慨期緩師，奉命日馳三百里。", "河流遡風車北首，便殿蒙恩引天袖。", "臣肝有血不濺衣，寸舌欲存建王後。", "奇胸如江湧崔嵬，慟哭不得天顔回。"]'),
('514648c6-3de1-4882-aff6-17d74aeadfec','宋騎吹曲 伎女洗藍曲第九','謝翱','宋','宋诗','song-poetry','','[]','後庭朱黄作衣裏，伎女帳帷青曳地。',64,'全唐诗/poet.song.246000.json','["後庭朱黄作衣裏，伎女帳帷青曳地。", "碧綠夜挂寒不收，緣此洗藍渟露水。", "外間學染因得名，不省歸朝爲國氏。", "他年寄生産鴟尾，空憶宮中鳥銜子。"]'),
('d6502901-4bdf-4027-8d99-a97905693315','宋騎吹曲 邸吏謁故主曲第十','謝翱','宋','宋诗','song-poetry','','[]','嶺南使鶴日教戰，巫女才人謔相見。',96,'全唐诗/poet.song.246000.json','["嶺南使鶴日教戰，巫女才人謔相見。", "南橈欲載遠遊冠，衛士盜船去不還。", "夢見隨俘上江邱，道謁凄凉唯故吏。", "自言置邸本先王，方物入朝緣此至。", "聞言含咽涕灑江，况乃園人舊姓龐。", "淚辭嶺海無歸處，蒙恩祇向江陵住。"]'),
('3bc07a3f-ed6a-4229-926c-9cced8a4385c','芳草怨','謝翱','宋','宋诗','song-poetry','','[]','湘雲離離沉曉月，疏麻夏死白水發。',96,'全唐诗/poet.song.246000.json','["湘雲離離沉曉月，疏麻夏死白水發。", "傳芭楚女辭帳中，夜逐霓旌南過越。", "荆岑越嶠殊百草，恨結柔絲香不老。", "紅英搗鹽實斧創，青子滿地枝如掃。", "刺桐樹朽猩猩在，佩雜芳蕤散秋海。", "鄉來青鳳食花去，瞻望靈均涕零雨。"]'),
('3bdc0847-3018-4e4a-b6c2-3c0e99c51b05','春江曲','謝翱','宋','宋诗','song-poetry','','[]','妾身生長臨江邊，幼嫁酒家學數錢。',80,'全唐诗/poet.song.246000.json','["妾身生長臨江邊，幼嫁酒家學數錢。", "自從夫婿去爲賈，別妾初下武昌船。", "涔陽歸雁不寄影，巂州書到已三年。", "別時夢指水爲誓，惟有海鳬見妾泪。", "愁拋錦字下中流，却見海鳬淚如水。"]'),
('69526186-336a-4ad1-824b-8941adb70348','子夜吳歌','謝翱','宋','宋诗','song-poetry','','[]','玄髪照秋水，茱萸香未歇。',24,'全唐诗/poet.song.246000.json','["玄髪照秋水，茱萸香未歇。", "風吹夜合花，露濕衣上月。"]'),
('2a28a6f6-f53c-4e6a-8514-131614cbba98','烏栖曲擬張司業','謝翱','宋','宋诗','song-poetry','','[]','吳宮草深四五月，破楚門開烏啼歇。',80,'全唐诗/poet.song.246000.json','["吳宮草深四五月，破楚門開烏啼歇。", "美人軍裝多在船，歸來把弓墮弓弦。", "越羅如粟越王獻，宮中養蠶不作線。", "轆轤出屋井水淺，梔樹花萎子如繭。", "烏栖烏啼宮燭秋，越女入宮吳女愁。"]'),
('c6bba29d-9915-46b2-9ef7-99273758848b','廢居行','謝翱','宋','宋诗','song-poetry','','[]','海濤翻空秋草短，白蛇入窠啖雀卵。',64,'全唐诗/poet.song.246000.json','["海濤翻空秋草短，白蛇入窠啖雀卵。", "經年廢屋無居人，孕婦夜向船中産。", "歸來多雨臼生魚，穴蟲祝子滿戶樞。", "鄰家置屋供官役，買得沂王園令宅。"]'),
('4aa2dd43-e994-4248-9b11-eb537a95fcb7','古釵嘆','謝翱','宋','宋诗','song-poetry','','[]','刑徒鬼火去飄忽，息婦堆前殯齊發。',112,'全唐诗/poet.song.246000.json','["刑徒鬼火去飄忽，息婦堆前殯齊發。", "白烟淚濕樵叟來，拾得慈獻陵中髪。", "青長七尺光照地，髪下宛轉金釵二。", "持歸薰沐置高堂，包裹恐爲神所將。", "妻兒朝拜復莫拜，冉冉卧病不得瘥。", "省知天物厭凡庸，夜送白龍潭水中。", "扣頭却顧祈免死，永入幽宮伴龍子。"]'),
('2d38810a-c0cf-4efb-8bec-8c41e7d6f941','雙桐生空井','謝翱','宋','宋诗','song-poetry','','[]','風飄白露井梧落，葉上丸丸綴靈藥。',32,'全唐诗/poet.song.246000.json','["風飄白露井梧落，葉上丸丸綴靈藥。", "琴枝連理鳳鳴晨，轆轤雙轉銀缾索。"]'),
('a85b8ac0-43ff-4517-815f-23f4fe18107a','飛來雙白鶴','謝翱','宋','宋诗','song-poetry','','[]','飛來縹緲立在門，噣銜竹花臆欲言。',48,'全唐诗/poet.song.246000.json','["飛來縹緲立在門，噣銜竹花臆欲言。", "雄雌來去眼如霧，客已彷彿知其人。", "笙簫忽遠不知處，知在雲窗與綠戶。"]'),
('2115f897-2712-4441-8177-5321588417f4','山中曲擬張司業','謝翱','宋','宋诗','song-poetry','','[]','夕煙沉，曙煙起。',67,'全唐诗/poet.song.246000.json','["夕煙沉，曙煙起。", "野爨濕茫茫，空竿弄塵水。", "栟櫚倚西南雲，生葉團團如車輪。", "桑弓蓬矢半刀筆，去者送盡無來人。", "捫蘿慟哭衫袖冷，白首空回掃山影。"]'),
('58b2734a-f0a2-4276-8803-a72cc8d5c629','遠游篇寄府教景熙','謝翱','宋','宋诗','song-poetry','','[]','朝遊扶桑根，不折拂日枝。',72,'全唐诗/poet.song.246000.json','["朝遊扶桑根，不折拂日枝。", "莫食楚萍實，掬海見虹霓。", "黄鵠別我影，目盡漢水湄。", "况復銜其子，風露何當歸。", "飄蕭軟桂叢，零落紫苔衣。", "夢魂知爾處，落羽在瑶池。"]'),
('e4395cf7-1ad8-4f51-9300-105fd3485f5d','峨眉老人別子歌','謝翱','宋','宋诗','song-poetry','','[]','峨眉有老人，奉命過嵩少。',72,'全唐诗/poet.song.246000.json','["峨眉有老人，奉命過嵩少。", "天風吹西翼，冉冉明夕照。", "濕塵紛墮天，髪白更待報。", "有子爲異物，不得入家廟。", "慟哭東南雲，相望滄海嶠。", "青鳥年年來，寄書久不到。"]'),
('e183aa70-55c4-4c99-aa0a-166ebea84f6e','瓊花引','謝翱','宋','宋诗','song-poetry','','[]','后土祠前車馬道，天人種花無瑶草。',96,'全唐诗/poet.song.246000.json','["后土祠前車馬道，天人種花無瑶草。", "英雲蕊珠欲上天，夜半黄門催進表。", "酒香浮春露泥泥，二十四橋色如洗。", "陰風吹雪月墮地，幾人不得揚州死。", "孤貞抱一不再識，夜歸閬風曉無蹟。", "蒼苔染根烟雨泣，歲久游魂化爲碧。"]'),
('adbffded-6957-4950-95ca-bbe9f14902d6','短歌行','謝翱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','秦淮沒日如沒鶻，白波摇空濕弦月。',96,'全唐诗/poet.song.246000.json','["秦淮沒日如沒鶻，白波摇空濕弦月。", "舟人倚櫂商聲發，洞庭脫木如脫髪。", "寒螀哀啼衆芳歇，晨梳青林望吳越。", "吳歈越吟浪花舞，秋槎濕劍歸無所。", "愁生酒醒聞山鷄，石鏡飛花汗如雨。", "起招如意擊樹枝，爲君悲歌君淚垂。"]'),
('7c90f11f-0ee7-480c-9c38-1f7bc85f0d6b','秋日擬塞上曲','謝翱','宋','宋诗','song-poetry','','[]','落日墩堭北，妖星太白西。',64,'全唐诗/poet.song.246000.json','["落日墩堭北，妖星太白西。", "凉風吹沙磧，帳下玉人啼。", "吹沙復吹草，嘶馬未知道。", "醉後聞塔鈴，胡天忽如掃。", "野駝尋水向月行，露下胡兒食秋棗。"]'),
('0de91a41-b569-42f6-ae01-d8b87287f031','故園秋日曲四首  其一','謝翱','宋','宋诗','song-poetry','','[]','空園久閉無人住，城烏應入巢其樹。',32,'全唐诗/poet.song.246000.json','["空園久閉無人住，城烏應入巢其樹。", "食盡滿園綠荔枝，引雛飛去人始知。"]'),
('11dc21fb-da30-4c5b-a2de-5aaf77a835ee','故園秋日曲四首  其二','謝翱','宋','宋诗','song-poetry','','[]','茅茨竹外烟火青，杉鷄啁哳向田鳴。',32,'全唐诗/poet.song.246000.json','["茅茨竹外烟火青，杉鷄啁哳向田鳴。", "家家紅鹽殷新杵，綠樹裹創子如雨。"]'),
('cafaa64c-7372-4b5f-a656-a09df9c4907a','故園秋日曲四首  其三','謝翱','宋','宋诗','song-poetry','','[]','龍蛇已去荒窟宅，翻藕人人下劍池。',32,'全唐诗/poet.song.246000.json','["龍蛇已去荒窟宅，翻藕人人下劍池。", "岸池藕盡無浮葉，惟有青青榕樹枝。"]'),
('4c948b0d-faf3-40b3-a109-e55e6409c9b5','故園秋日曲四首  其四','謝翱','宋','宋诗','song-poetry','','[]','粵王山下霧如雨，吹入羅襟楚女啼。',32,'全唐诗/poet.song.246000.json','["粵王山下霧如雨，吹入羅襟楚女啼。", "身逐千艘落南去，惟有檣烏飛向西。"]'),
('75b4a601-1a27-4fca-bdfe-01175f2171ab','咄咄復咄咄','謝翱','宋','宋诗','song-poetry','','[]','咄咄復咄咄，野風吹雲起草垡。',62,'全唐诗/poet.song.246000.json','["咄咄復咄咄，野風吹雲起草垡。", "竹塵陰陰不見山，鷄飛上樹海沒鶻。", "人間舊事新白頭，淮南小兒未識愁。", "淮南老翁叫無力，瓦盆盛水看日食。"]'),
('ee80229d-ad80-4a91-8078-c540e246ff84','桂花引','謝翱','宋','宋诗','song-poetry','','[]','風生河漢吹鳴璫，桂宮神斧伐遠揚。',48,'全唐诗/poet.song.246000.json','["風生河漢吹鳴璫，桂宮神斧伐遠揚。", "西游真人得奇曲，九門不鎖天雨霜。", "人間青烟濕塵鞚，藥臼嵯峨壓天夢。"]'),
('b87301f5-9e87-4847-bb06-84ed314dc84e','賦得建業水','謝翱','宋','宋诗','song-poetry','','[]','建業水，秋風動揚子。',114,'全唐诗/poet.song.246000.json','["建業水，秋風動揚子。", "魚龍夜落星斗南，潮沒潮生蒼鶻起。", "他年冠蓋物具美，風吹小船入城市。", "潮去不來風日死，白浪黄塵烟霧裏。", "中有長魚食鱣鮪，解后食魚何處是。", "西上國門望武昌，風雨徙魚來漢陽。", "武昌魚勞聚寒槮，太白入月魚腦減，武昌城頭鼓紞紞。"]'),
('4fb2cb29-4e40-4a1a-b4c7-3a5060baf93a','賦得北府酒','謝翱','宋','宋诗','song-poetry','','[]','北府酒，吹濕宮城柳。',90,'全唐诗/poet.song.246000.json','["北府酒，吹濕宮城柳。", "柳枝著地春垂垂，祇管人間新別離。", "離情欲斷江水語，女兒連臂歌白紵。", "淮南神仙來酒坊，甲馬獵獵羽林郎。", "百年風物烟塵蒼，老兵對月猶舉觴。", "青帘淚濕女牆下，曾識行軍舊司馬。"]'),
('dd21e254-17ef-40cc-ad34-0d5751dbd26d','楚女謠','謝翱','宋','宋诗','song-poetry','','[]','楚山蕭蕭吹紺髪，楚女采蓮歌夜發。',80,'全唐诗/poet.song.246000.json','["楚山蕭蕭吹紺髪，楚女采蓮歌夜發。", "年年種菂遲成藕，水深拔根絲在手。", "懸房學繭秋雨多，化爲魂夢巢蜂窠。", "前花作實采已盡，後花尚蕊船未過。", "昨昔浮萍隨漲水，濕紫寒青裹蓮蕊。"]'),
('4cf0fbb6-f003-4191-9f7b-23e2b427a55c','後瓊花引','謝翱','宋','宋诗','song-poetry','','[]','揚州城門夜塞雪，揚州城中哭明月。',80,'全唐诗/poet.song.246000.json','["揚州城門夜塞雪，揚州城中哭明月。", "墮枝濕雲故鬼語，西來陰風無健鶻。", "神娥愬空衆芳歇，一夕蒼苔變華髪。", "宮花窣簾塵掩襪，玉華無因進吳越。", "灕灕淮水山央央，誰其死者李與姜。"]'),
('08d01d57-bcea-4512-881e-a099dc46ec9e','邳州哭','謝翱','宋','宋诗','song-poetry','','[]','邳州哭，井水竭，去年哭母瘴海熱。',56,'全唐诗/poet.song.246000.json','["邳州哭，井水竭，去年哭母瘴海熱。", "今年此日來邳州，母死未禫子爲囚。", "邳州土濕淚長在，化爲蒼苔色不改，雨洗遊魂歸瘴海。"]'),
('9d2edb08-2e47-47d2-bfbd-320d60e0924c','秋風海上曲','謝翱','宋','宋诗','song-poetry','','[]','秋風吹水龍上天，龍女抱珠海底眠。',96,'全唐诗/poet.song.246000.json','["秋風吹水龍上天，龍女抱珠海底眠。", "水花生雲起如葑，神龍下宿藕絲孔。", "巨鼇贔屭鼉鼓隨，赤魚鱗鬣陳旍旗。", "海人見此失操綱，歸對妻兒月下紡。", "自言移家來磧中，十載秋風潮不上。", "老夫一人語門前，見此已是開皇年。"]'),
('0ed673cf-7ec4-422d-92d6-012ed632d010','明河篇','謝翱','宋','宋诗','song-poetry','','[]','牽牛夜入明河道，淚滴相思作秋草。',64,'全唐诗/poet.song.246000.json','["牽牛夜入明河道，淚滴相思作秋草。", "婺女城頭翫月明，星君冢上無啼鳥。", "天寒露凈沾衣巾，明河倏化爲白雲。", "雲飛蜿蜿秋在水，石壓槎頭海烟起。"]'),
('f840c46f-7a9f-420c-a77a-3745bdfa1298','射鳩行','謝翱','宋','宋诗','song-poetry','','[]','少年操弩挾兩矢，朝射青鳩暮射雉。',83,'全唐诗/poet.song.246000.json','["少年操弩挾兩矢，朝射青鳩暮射雉。", "人言雊雉蛇所化，欲食躊躇筯不下。", "街頭得錢爭買鳩，網林抉藪無時休。", "老父勸兒食且止，燕安有毒况珍美。", "爾不見鳩食半夏鳴爾屋，爾毋食鳩有藥毒。"]'),
('e4935de3-5a05-46c4-8865-cc1f0b1ff1f2','虞美人草詞','謝翱','宋','宋诗','song-poetry','','[]','髑髏起語鴟叫嘯，山精夜啼楚王廟。',96,'全唐诗/poet.song.246000.json','["髑髏起語鴟叫嘯，山精夜啼楚王廟。", "渡淮風雨八千人，叱咤向天成白道。", "身經百戰轉危亡，很籍悲歌出漢堡。", "夜帳天寒抱玉泣，血變草青烟曉濕。", "他年辟仇春草生，吳中草死無妾名。", "自從爲草生西楚，得到吳中猶楚舞。"]'),
('a495a93b-8542-4275-982a-ec7142870d5b','劉寄奴草詞','謝翱','宋','宋诗','song-poetry','','[]','榛中小草夏蔚薈，葉如牡艾花如毳。',96,'全唐诗/poet.song.246000.json','["榛中小草夏蔚薈，葉如牡艾花如毳。", "少年防塞得命生，出鏃肉中無粟起。", "向來神姦見白晝，濕竹烟青聞杵臼。", "英雄奮臂徵此時，唾落虛空散林藪。", "漢家白蛇入本紀，况是天王舊支子。", "豈知苗裔在民伍，蛇鬼猶呼帝小字。"]'),
('854a9df3-c517-4b0c-a2a4-cbade183d171','雨中怨','謝翱','宋','宋诗','song-poetry','','[]','妾在江南家楚東，憶君月落雨聲空。',32,'全唐诗/poet.song.246000.json','["妾在江南家楚東，憶君月落雨聲空。", "夜來入夢君無語，落月同看雨不同。"]'),
('2ed470c8-d602-45f7-9d0b-c0964cb378d0','白紵歌','謝翱','宋','宋诗','song-poetry','','[]','江頭蓬沓走吳女，浣水爲花朝浣紵。',64,'全唐诗/poet.song.246000.json','["江頭蓬沓走吳女，浣水爲花朝浣紵。", "晝隨睛網曬日中，夜覆井闌飄白露。", "織成素雪裁稱身，夫爲吳王戍柏舉。", "田家歲績供布縷，獨夜詎如妾愁苦。"]'),
('b7aedc93-e54f-4463-9771-f982f5a97253','陌上桑','謝翱','宋','宋诗','song-poetry','','[]','旭日曈曨颺拂羽，落葚空條生曉霧。',80,'全唐诗/poet.song.246000.json','["旭日曈曨颺拂羽，落葚空條生曉霧。", "人生顔色逐春妍，夏葉餵蠶少絲縷。", "蘭膏照繭未登簇，露濕頭梳惟水沐。", "却憐鄰女學鍊真，藥爐七過煮桑薪。", "縱逢蕭史上天去，甕盆生苔愁殺人。"]'),
('4d45aa2d-0469-453f-8483-5f24e8d7b843','折楊柳','謝翱','宋','宋诗','song-poetry','','[]','月時折柳江頭別，春去來看柳上月。',64,'全唐诗/poet.song.246000.json','["月時折柳江頭別，春去來看柳上月。", "翠翎小鳥巢短枝，巢老重重編敗髪。", "人生貧賤多別離，巢中髪密妾髪稀。", "人生富貴能幾時，年年柳色青綠垂。"]'),
('0a75f3bd-e4ac-496a-b30c-9487251e537a','廢瑟詞','謝翱','宋','宋诗','song-poetry','','[]','發埋空山販繒客，草中惟棄秦時瑟。',68,'全唐诗/poet.song.246000.json','["發埋空山販繒客，草中惟棄秦時瑟。", "樵夫拾置貽樂工，朱徽作絃如墨色。", "自從漢曲入鐃歌，清廟無人傳不得。", "至今崔嵬聲已死，越{廣/丘}春蟲聞呪子。"]'),
('2562890a-fccb-4ca5-9572-c95ffabb5130','飛仙引遊沃州水簾谷作','謝翱','宋','宋诗','song-poetry','','[]','赤城後門桃花尾，溼浸蘼蕪洗蒼耳。',96,'全唐诗/poet.song.246000.json','["赤城後門桃花尾，溼浸蘼蕪洗蒼耳。", "小支菩提海上來，天風吹下谷簾水。", "斜珠界左轉復右，華蓋縣肝三葉紫。", "內間肉芝承乳流，鬼母僊姝臨洗胃。", "蒼龜守關朝太微，色阻讒神誣奏事。", "海桑男子在謫籍，驅鹿行車閏年至。"]'),
('bff20492-6883-4f8b-84f5-265e713b9c3b','樊夫人上昇詞','謝翱','宋','宋诗','song-poetry','','[]','石蠔粘窗秋見海，山鷄夜啼弄毛彩。',64,'全唐诗/poet.song.246000.json','["石蠔粘窗秋見海，山鷄夜啼弄毛彩。", "王孫吹笙導夫人，青髪凌風素霞在。", "雨塵離地白浩浩，河西種星榆樹老。", "海桑童童日出歸，衣濕上池洗頭草。"]'),
('88623fe8-615d-421d-835d-690f1270f956','俠客吳歌立秋日海上作','謝翱','宋','宋诗','song-poetry','','[]','潮動秋風吹牡荆，離歌入夜斗西傾。',32,'全唐诗/poet.song.246000.json','["潮動秋風吹牡荆，離歌入夜斗西傾。", "佽飛廟下蛇含草，青拭吳鈎入匣鳴。"]'),
('a0f89293-ff11-41c8-8519-06d66dfa8fa8','島上曲二首  其一','謝翱','宋','宋诗','song-poetry','','[]','皮带墨鱗身卉衣，晚隨鬼渡水燈微。',32,'全唐诗/poet.song.246000.json','["皮带墨鱗身卉衣，晚隨鬼渡水燈微。", "石門犬吠聞人語，知在海南種蛤歸。"]'),
('1c1eac0a-d6bb-4b6c-9a82-4cc1394206ce','島上曲二首  其二','謝翱','宋','宋诗','song-poetry','','[]','夫招賈客歲經遼，自到城中賣織綃。',32,'全唐诗/poet.song.246000.json','["夫招賈客歲經遼，自到城中賣織綃。", "却買鉛華采珠母，檳榔露下月中調。"]'),
('2a16057a-d7ad-43ad-b1a0-b72dc9cea07b','落梅詞','謝翱','宋','宋诗','song-poetry','','[]','北風花糝枝，春風花糝衣。',72,'全唐诗/poet.song.246000.json','["北風花糝枝，春風花糝衣。", "青鳥夢中見，畏來花下飛。", "豈是得春遲，因緣別春早。", "夜濕灞陵苔，半在古馳道。", "入瓦雪冥冥，離樹香草草。", "那無返魂術，不忍見春老。"]'),
('b4811ddc-6df8-4246-a459-9832702f1279','望蓬萊','謝翱','宋','宋诗','song-poetry','','[]','青枝啼鳥波延延，方士指海談神仙。',96,'全唐诗/poet.song.246000.json','["青枝啼鳥波延延，方士指海談神仙。", "五雲垂天光屬夜，老父相傳說車駕。", "千官此地佩宛宛，舟發黄門止供頓。", "繞檣赤日護龍旗，西北驛書馳羽箭。", "百年塵空滄海晚，月落無人度灞滻。", "鷄鳴白石爛如銀，蓬萊不見夷州遠。"]'),
('df35e7c6-420f-4671-81aa-61462ee3d525','結客行','謝翱','宋','宋诗','song-poetry','','[]','結客衛京師，棄家南斗陲。',84,'全唐诗/poet.song.246000.json','["結客衛京師，棄家南斗陲。", "相看各意氣，欲取遼陽歸。", "事左脫身去，豈爲無所爲。", "家藏楚王子，手執五陵兒。", "泣奉先主令，白旗曏天揮。", "鞭屍讎必報，函首捷終馳。", "力盡志不遂，以死謝漸離。"]'),
('516bd257-3484-4421-9d1e-dfb7b5010486','古別離','謝翱','宋','宋诗','song-poetry','','[]','仙人別母母哭啼，遺以神藥乃醉之。',80,'全唐诗/poet.song.246000.json','["仙人別母母哭啼，遺以神藥乃醉之。", "醒來哭定記兒語，食此庭前雙橘樹。", "葉能禦饑病能愈，豈似當時逐兒去。", "鄰翁有女立我前，取刀剖腹爾勿憐。", "但爾嫁夫能治田，生子不願生神仙。"]'),
('42951c4b-c7e4-4ba7-8d96-0f11998ed9f8','花卿冢行','謝翱','宋','宋诗','song-poetry','','[]','濕雲模糊埋秋空，雨青沙白丹陵東。',72,'全唐诗/poet.song.246000.json','["濕雲模糊埋秋空，雨青沙白丹陵東。", "莓苔陰陰草茸茸，云是花卿古來冢。", "花卿舊事人所知，花卿古冢知者誰。", "精靈未歸白日西，廟鴉啄肉枝上啼，綿州柘黄魂正飛。"]'),
('c327a16e-7e13-44d9-897d-c11251bcb08d','和靖墓','謝翱','宋','宋诗','song-poetry','','[]','山中處士白麻履，死後無書獻天子。',96,'全唐诗/poet.song.246000.json','["山中處士白麻履，死後無書獻天子。", "青童玄鶴晝上天，夜下玉棺葬湖水。", "湖隄四合葑如髪，芳樹玲瓏倚春雪。", "百年鳳舞雲霧空，玉椀人間出句越。", "宮嵐塔雨恍如失，飛網繞湖冠聚鷸。", "琳宇焚芝秋寂歷，斗下無人祠太乙。"]'),
('b7c18754-ebfc-499e-9a32-3a271915ad57','蓮葉舟','謝翱','宋','宋诗','song-poetry','','[]','濕雲冉冉依芳芷，楚女神絃迎帝子。',96,'全唐诗/poet.song.246000.json','["濕雲冉冉依芳芷，楚女神絃迎帝子。", "天人種蓮露染根，一片碧花秋墮水。", "笙簫聞聲影如夢，浮花漠漠船來重。", "神蛟蛻腸江水湄，化爲五色光陸離。", "中有玉人跨蛟舞，藕根斷絲罥人衣。", "碧瞳秋髪眠清夜，按肌不粟清露下。"]'),
('18fb1f87-be16-4fd7-815c-2fc395f4153e','玉井水','謝翱','宋','宋诗','song-poetry','','[]','玉華翳日神封井，液泠秋根洗雲影。',80,'全唐诗/poet.song.246000.json','["玉華翳日神封井，液泠秋根洗雲影。", "年年天女下來觀，露濕風吹太華頂。", "冰枝脫葉墜欲舞，青鳥伺枝忽銜去。", "夜深井氣白吐虹，井中龍子如守宮。", "凡人不敢飲此水，往往夢寐游其中。"]'),
('ab706086-672e-4a38-93ec-95604573be21','送人歸烏傷','謝翱','宋','宋诗','song-poetry','','[]','湖邊老屋牆壓籬，饑鴉啄雪枝上啼。',88,'全唐诗/poet.song.246000.json','["湖邊老屋牆壓籬，饑鴉啄雪枝上啼。", "湖中葑田産菰米，菖蒲花開照湖水。", "蒺藜老翁呼不起，曾入東宮教皇子。", "文雅風流俱掃地，瓦磚擲人老兵醉。", "後園小坊近市廛，借人樗蒲無稅錢，君歸故里何所憐。"]'),
('29ec2796-9e57-430a-886d-6fe810b18eb4','覓紫芝','謝翱','宋','宋诗','song-poetry','','[]','少微昏見觜觹中，山深夜氣光流虹。',80,'全唐诗/poet.song.246000.json','["少微昏見觜觹中，山深夜氣光流虹。", "青芝獨産林下石，染根濕雲如紫漆。", "天門夢斷路初回，山鬼守根不敢食。", "銀泥徹鎖守者疲，老翁持呪取夜歸。", "明當食之聞鬼哭，對爾洗腸還入腹。"]'),
('fa89840d-df3a-4a8b-a928-525051df016e','雨後海棠','謝翱','宋','宋诗','song-poetry','','[]','春光摇摇一萬里，野粉殘英空蜀水。',96,'全唐诗/poet.song.246000.json','["春光摇摇一萬里，野粉殘英空蜀水。", "天人愁濕紅錦窠，萬里移根泪如洗。", "蒼苔裹枝雪墮地，雨中聞有西南使。", "化爲黄鵠凌空青，開時銜花落銜子。", "綠章青簡下蓬萊，滯魄游魂恨未已。", "至今鸚鵡啼猩紅，不隨明月葬空中。"]'),
('3363bd80-5d81-4c63-9a70-d030dcf54007','登廣靈寺塔望南高峰','謝翱','宋','宋诗','song-poetry','','[]','城池風烟杯渡僧，廣靈孤塔懸晝燈。',96,'全唐诗/poet.song.246000.json','["城池風烟杯渡僧，廣靈孤塔懸晝燈。", "塔燈上齊南高雲，南高峰巔祠歙神。", "靈旗蕭蕭卷清雨，結喉巫陽能楚語。", "回望人烟塔峰北，惟有空城臨水滸。", "赤蛇不神江海翻，藪澤狐狸作巴舞。", "當年介弟階防禦，玉鸞青鞭上天去。"]'),
('2f06fc51-d66e-406c-b375-ea7f6e4cfccd','雪度','謝翱','宋','宋诗','song-poetry','','[]','千山萬山雪崔嵬，欲流不流水洄洄。',56,'全唐诗/poet.song.246000.json','["千山萬山雪崔嵬，欲流不流水洄洄。", "蟄熊出穴戍草短，客行心急夢歸來。", "南園桑柘未生葉，南溪渡頭不可涉，朝種木蘭拔爲檝。"]'),
('0765c61b-4fb6-40b0-a238-6f6f1d0b69ab','閲方史君登行狀','謝翱','宋','宋诗','song-poetry','','[]','九江黥王所理州，衰年仗箠作諸侯。',80,'全唐诗/poet.song.246000.json','["九江黥王所理州，衰年仗箠作諸侯。", "唐人舊隠衣冠盡，歸闖宮潮不得覲。", "天吳舞罷塵土飛，廿載腥雲寄空殯。", "當年電隙豈所問，生死身名惟轉瞬。", "睦人共說方饒州，番人作廟祠唐震。"]'),
('6ad3220e-2049-4c48-9fdc-785028a1f21a','食薺歌送別方安道','謝翱','宋','宋诗','song-poetry','','[]','山中薺發燒餘地，與君爲客同食薺。',64,'全唐诗/poet.song.246000.json','["山中薺發燒餘地，與君爲客同食薺。", "薺長故君收燼餘，君歸食薺如食荼。", "我家甌越草應出，土濕烟青歸不得。", "相逢舉酒復爲別，對君盤中不忍食。"]'),
('1ecd3720-9303-4f4d-8e47-206d9f4f15fb','夜宿南明縣齋','謝翱','宋','宋诗','song-poetry','','[]','朝陰扣舷清剡曲，暝投天姥峰前宿。',80,'全唐诗/poet.song.246000.json','["朝陰扣舷清剡曲，暝投天姥峰前宿。", "桂蟲食葉露濕身，影落莓苔雲矗矗。", "天風吹枝斷末殊，夢尋杳靄來絳車。", "下車者誰藏姓氏，夜嚮瓊臺讀諸子。", "覺來隠隠聲在耳，月白西南望爲水。"]'),
('847ee5e1-62fe-4dc5-bc30-1ccc27a73b17','書畫梅花水仙卷','謝翱','宋','宋诗','song-poetry','','[]','風吹襪露明微照，芳雲弱植仙姝廟。',64,'全唐诗/poet.song.246000.json','["風吹襪露明微照，芳雲弱植仙姝廟。", "髻鬟零亂在枕函，月裏羅浮夢中到。", "鮫綃拂塵蟬翼隔，窗霧凝寒唯影入。", "曉來坐對殘空標，翠翎不見額黄濕。"]'),
('c9e08f8e-e5ea-43c5-9fd1-276341664619','冬青樹引別王潜','謝翱','宋','宋诗','song-poetry','','[]','冬青樹，山南陲，九日靈禽居上枝。',88,'全唐诗/poet.song.246000.json','["冬青樹，山南陲，九日靈禽居上枝。", "知君種年星在尾，根到九泉雜龍髓。", "恒星晝霣夜不見，七度山南與鬼戰。", "願君此心無所移，此樹終有開花時。", "山南金粟見離離，白衣人拜樹下起，靈禽啄粟枝上飛。"]'),
('2dac2a17-e440-4959-b9c5-fa93bd2e4199','小元祐歌寄劉君鼎','謝翱','宋','宋诗','song-poetry','','[]','前甲子，小元祐，句章祲黑權臣死。',112,'全唐诗/poet.song.246000.json','["前甲子，小元祐，句章祲黑權臣死。", "端平天子初改紀，襲芳泰陵種蘭芷。", "當秋淮甸枯草黄，彎弧北向射天狼。", "狐南星光天狗墮，入蔡生擒完顔王。", "是年南海無波浪，月濕珠胎君以降。", "只今六十空白頭，獨騎麒麟補春秋。", "天回星周美惡復，人世更傳蔡州錄。"]'),
('ac621dab-7080-4dc2-a8ca-f8e1701b4bab','句章見月食','謝翱','宋','宋诗','song-poetry','','[]','縠州見月如魚口，沬聚痕消暗窗牖。',128,'全唐诗/poet.song.246000.json','["縠州見月如魚口，沬聚痕消暗窗牖。", "鄞城見月如破臼，棄藥含垢掛南斗。", "龍蛇伏氣諸腦空，水中睡失群陰母。", "其間海禽獨夜啼，黑雲赴海同奔犀。", "市人識母不識父，擊柝摧扉救月死。", "况值蕤賓月十五，干神附甲支在子。", "孤子哀吟離楚尾，泪落荒江吊南紀。", "猶憶秦淮哭日年，不敢仰視看盆水。"]'),
('e3148d2f-b506-4377-8646-eda4e6411201','避暑城西觀吳道子畫老君像','謝翱','宋','宋诗','song-poetry','','[]','濕烟掛龍天海頭，角城溽暑如炎州。',80,'全唐诗/poet.song.246000.json','["濕烟掛龍天海頭，角城溽暑如炎州。", "白氛翳景失樓閣，蓬萊縹緲不可求。", "解衣揮麈子城下，地湧青蓮鄰古社。", "卷簾看畫人猶龍，矯首見龍還見畫。", "碧幢髪雪垂過耳，弄筆者誰吳氏子。"]'),
('3aa0c439-5841-41ce-a42e-a9668779896d','趙安天北遊求詩安天韶王孫作詩送之','謝翱','宋','宋诗','song-poetry','','[]','海雲抱漚海水熱，道路征人裹冰雪。',96,'全唐诗/poet.song.246000.json','["海雲抱漚海水熱，道路征人裹冰雪。", "憐君獨作萬里遊，雨把蓮莖手中別。", "蓮莖刺多蓮葉濕，翻爲君衣覆爲笠。", "汴南淮北多故人，馬上相逢泪相揖。", "故園萋萋長草根，遲君歸來洗雨痕。", "青鞭碧影角湖曲，芳夢猶到韶王孫。"]'),
('54397e4a-4444-45c9-bb43-bd6ba7d9a8dc','逃暑崇法寺','謝翱','宋','宋诗','song-poetry','','[]','城南古寺凉生處，草色遥連孝子墓。',64,'全唐诗/poet.song.246000.json','["城南古寺凉生處，草色遥連孝子墓。", "棋局雨生苔鮮文，袈裟晴挂芭蕉樹。", "自昔闍黎修白業，會公唯與舒王椄。", "只今塵土影堂空，石上猶鎸麻紙帖。"]'),
('fefdadcd-f32b-467d-8e22-a237491741af','鄞女墓','謝翱','宋','宋诗','song-poetry','','[]','網草新垂月中露，青禽夜宿菱塘陼。',80,'全唐诗/poet.song.246000.json','["網草新垂月中露，青禽夜宿菱塘陼。", "寺西幽修雲覆土，知葬舒王下殤女。", "百年光塵事事新，皇子夫人墓作鄰。", "民間厭勝祈新鬼，穉鬼久隨風雨陳。", "去來似爾勿復道，白下鍾山夢中老。"]'),
('9c4bcba3-a566-4ab3-bdd6-16d7b875aa39','寶幢山尋黄提刑震舊避地處','謝翱','宋','宋诗','song-poetry','','[]','甬東寺裏逢陳若，雙袖龍鍾行带索。',112,'全唐诗/poet.song.246000.json','["甬東寺裏逢陳若，雙袖龍鍾行带索。", "問知黄公舊避逃，寶幢山下坐叢薄。", "日惟一食禱先靈，不願拾得不死藥。", "仰天呼號得正終，一往不復至城郭。", "公初著書女立旁，公死母亡家濩落。", "子爲戶曹取公女，欲敘因由無與語。", "得來與子行林莽，月落山空識其處。"]'),
('5c034fea-8e00-4f81-b6e6-b1ac63e42c5f','城西廢園','謝翱','宋','宋诗','song-poetry','','[]','水門夾西雨連越，鄴瓦耕殘莎草茁。',96,'全唐诗/poet.song.246000.json','["水門夾西雨連越，鄴瓦耕殘莎草茁。", "誰知當日夫容園，濕路迷城暗車轍。", "夫容青根聯戚里，美人對博蓬山裏。", "潮痕欲上紅露晞，知是日高梳洗起。", "園南禁絕人行道，中有民間舊宿草。", "廢園起垡鳴竊脂，寒食始應通祭掃。"]'),
('d75f724c-b5de-49ab-a84b-411291b4771a','五言近體二首  其一','謝翱','宋','宋诗','song-poetry','','[]','南雁去來盡，音書不可憑。',48,'全唐诗/poet.song.246000.json','["南雁去來盡，音書不可憑。", "應過蠻嶺瘴，聞拊楚臣膺。", "滄海沈秦璧，愁雲起舜陵。", "可堪夢魂在，回首舊孤稜。"]'),
('615570e9-b287-44bd-b193-fabee610e4d2','五言近體二首  其二','謝翱','宋','宋诗','song-poetry','','[]','月離孤嶂雨，尋夢下山川。',48,'全唐诗/poet.song.246000.json','["月離孤嶂雨，尋夢下山川。", "野冢埋鸚鵡，殘碑哭杜鵑。", "妓收中使客，民買內醫田。", "到此聞鄰笛，離情重惘然。"]'),
('8aefa57e-18ec-47a3-85c3-5d1e8ced6de5','中秋憶山中人','謝翱','宋','宋诗','song-poetry','','[]','茲夕發清嘯，爲君楚舞終。',84,'全唐诗/poet.song.246000.json','["茲夕發清嘯，爲君楚舞終。", "西風五陵夢，凉露九霄中。", "野邏烟常起，溪流榜不通。", "天陰無乳兔，林盡見飛鴻。", "濕濕雲垂髪，丸丸樹偃弓。", "劍歌玄武莫，塵語白鷗空。", "祇有淮南泪，應沾青桂叢。"]'),
('0424a11a-bfeb-455c-9119-e4184c9f5cce','仙華山招隠','謝翱','宋','宋诗','song-poetry','','[]','軒后悲蒼劍，神娥下玉簫。',96,'全唐诗/poet.song.246000.json','["軒后悲蒼劍，神娥下玉簫。", "攀髯初失夢，遺蛻尚凌歊。", "碧墮升棺影，青分産柱苗。", "山精依鹿竹，天雨濕雞翹。", "有約成孤憤，無人重久要。", "豢龍因姓氏，使鶴語軒軺。", "冉冉將終老，冥冥不可招。", "無書寄青雀，有恨在中條。"]'),
('eb38943d-92d4-418b-8fc0-1148738893d7','答烟蘿隠者','謝翱','宋','宋诗','song-poetry','','[]','月落烟霧動，遥知夜不眠。',48,'全唐诗/poet.song.246000.json','["月落烟霧動，遥知夜不眠。", "紫苔生水底，白髪坐巖前。", "野鶴下窺影，山人疑問年。", "微吟度小刦，勞贈遠遊篇。"]'),
('5fb0a3d9-df49-45d9-8fae-ce29eccfba0e','送人還蜀','謝翱','宋','宋诗','song-poetry','','[]','白髪夢鄉國，君歸路不迷。',48,'全唐诗/poet.song.246000.json','["白髪夢鄉國，君歸路不迷。", "洑槎秋見草，荒棧夜聞雞。", "月過秦凉北，星深河漢西。", "何因到却返，吳語話分携。"]'),
('9e5a3bd1-04b3-4cf5-bf77-334b696ea46f','憶梁禮部臯','謝翱','宋','宋诗','song-poetry','','[]','閒庭芳桂叢，相憶曙雲空。',48,'全唐诗/poet.song.246000.json','["閒庭芳桂叢，相憶曙雲空。", "文字能娛老，莓苔此興同。", "青山明月下，家口少微東。", "歲晚西莊路，柴門語自工。"]'),
('7860303d-12aa-4f66-a5c0-57497a272e56','拜玄英先生畫像','謝翱','宋','宋诗','song-poetry','','[]','來此得公真，塵埃避隠淪。',48,'全唐诗/poet.song.246000.json','["來此得公真，塵埃避隠淪。", "水生溪榜夕，苔卧野衣春。", "雨冢侵吳甸，荒祠侑漢人。", "微吟值衰世，爲爾獨傷神。"]'),
('0edc7c67-8e92-4ebb-9f74-e03a67aa41f5','哭正節徐先生','謝翱','宋','宋诗','song-poetry','','[]','凄凉携子女，冠佩赴重陰。',48,'全唐诗/poet.song.246000.json','["凄凉携子女，冠佩赴重陰。", "塌井千年事，青天此夜深。", "哀辭山石刻，卹典海舟沈。", "里族南薰夢，東都直至今。"]'),
('e0db6df0-67da-44eb-826c-979ed80d7358','送汪十','謝翱','宋','宋诗','song-poetry','','[]','多年隠賣漿，此去結山房。',48,'全唐诗/poet.song.246000.json','["多年隠賣漿，此去結山房。", "掃菌侵花落，種松如草長。", "老期秋欲至，貧味水初嘗。", "歲晚逢樵獵，音書定不忘。"]'),
('211f8c39-52db-4b62-8bbf-7f49325cf5ed','槿樹','謝翱','宋','宋诗','song-poetry','','[]','白犬吠行人，西風杵臼新。',48,'全唐诗/poet.song.246000.json','["白犬吠行人，西風杵臼新。", "洗香澄宿水，曝髪向秋鄰。", "野草依溝盡，宮花入帽頻。", "人家小門徑，憐爾獨相親。"]'),
('0a708b14-aa23-4a2e-b6ff-fd349082db2a','悼南上人','謝翱','宋','宋诗','song-poetry','','[]','翻紅卷未終，聞打寂時鍾。',48,'全唐诗/poet.song.246000.json','["翻紅卷未終，聞打寂時鍾。", "盡說他身在，唯應外國逢。", "錫聲歸後夜，琴意滿諸峰。", "憶昨安禪處，湖雲起白龍。"]'),
('8e3e5902-f6e1-4eaf-b1c7-0d343f78d5ec','元日讀老子望瀑作','謝翱','宋','宋诗','song-poetry','','[]','空山無轍迹，懸水下分洪。',48,'全唐诗/poet.song.246000.json','["空山無轍迹，懸水下分洪。", "醉醒聽猶在，寒暄色不同。", "異書天姥秘，靈物乳池空。", "祇憶殘年雨，先流到海中。"]'),
('f258bb09-10ce-4723-8948-05dac06cbdf3','雨中觀海棠','謝翱','宋','宋诗','song-poetry','','[]','風吹簾網動，對爾惜芳菲。',48,'全唐诗/poet.song.246000.json','["風吹簾網動，對爾惜芳菲。", "蜀雨何人在，吳宮祇燕歸。", "燭消春粉盡，淚濕野香微。", "抱蘤殘青子，鳥銜隨處飛。"]'),
('f6b11c6d-f473-43db-99b6-52ff6c449481','哭所知','謝翱','宋','宋诗','song-poetry','','[]','總戎臨百粵，花鳥瘴江村。',48,'全唐诗/poet.song.246000.json','["總戎臨百粵，花鳥瘴江村。", "落日失滄海，寒風上薊門。", "雨青餘化血，林黑見歸魂。", "欲哭山陽笛，鄰人亦不存。"]'),
('8cc03e14-8299-47ff-83cc-78a239492565','寄題何氏綠綺樓','謝翱','宋','宋诗','song-poetry','','[]','北岸有高樓，其南多藥樹。',84,'全唐诗/poet.song.246000.json','["北岸有高樓，其南多藥樹。", "仙人晝采之，遺佩鄉江渚。", "化爲綠綺琴，軫徽微已具。", "有客來南方，振衣坐其處。", "風吹朱鳥巢，欲落鳴至曙。", "山分地肺雲，水流天目雨。", "別去重所思，別時不能去。"]'),
('42f090d7-af9d-429d-bb65-bc46b2b2b176','夏日遊玉几山中','謝翱','宋','宋诗','song-poetry','','[]','曳舟來山中，出郭稅吾駕。',111,'全唐诗/poet.song.246000.json','["曳舟來山中，出郭稅吾駕。", "獨{艹暴}忻衆勝，晨發乃及夜。", "豈無城中山，愛此足幽野。", "橫陳玉几峰，隠護碧殿瓦。", "并州古男子，禮塔於此舍。", "而我飲冰人，猶爲內熱者。", "擬携桃枝笙，舒卷得餉暇。", "明席織海草，因之一枕藉。", "冷風吹雪空，相與坐其下。"]'),
('c0e3a449-9dc0-4664-b5ce-fa7e4deaea04','雨飲玲瓏巖下','謝翱','宋','宋诗','song-poetry','','[]','垂雲起嶔嵌，衣被松與桂。',96,'全唐诗/poet.song.246000.json','["垂雲起嶔嵌，衣被松與桂。", "夜含星斗光，隠若金石氣。", "雨來輒阻之，不得撫蒼翠。", "下有桑門子，飲用陶匏器。", "盆中蓄海石，左顧如牡礪。", "疑此磧上來，不知幾年歲。", "桑門却問客，所居何姓氏。", "回指南海峰，蒼茫倘一至。"]'),
('a7ca8f7d-5788-4162-a0a4-14f6d9b2a5e6','翠鎖亭避雨','謝翱','宋','宋诗','song-poetry','','[]','客有遊山衣，著久如薜荔。',96,'全唐诗/poet.song.246000.json','["客有遊山衣，著久如薜荔。", "行行萬翠亭，忽作風雨憩。", "仰面無所臯，梁間有題字。", "問此何人書，婉娩有弱氣。", "云昔魏王妃，學書似李衛。", "乘雲到此山，洒墨在空翠。", "塵風吹土花，倏忽景物異。", "疑此夢與仙，不類人間世。"]'),
('9c9130ac-52a8-4b68-92a8-1a7e35a3cf9c','過舒臨海故宅','謝翱','宋','宋诗','song-poetry','','[]','破壁濕海蘚，水退日氣蒸。',156,'全唐诗/poet.song.246000.json','["破壁濕海蘚，水退日氣蒸。", "云是舒公宅，其孫艾且仁。", "昔公初作尉，視事即斬人。", "上書稱臣亶，待罪滄海濱。", "天子有詔至，汝亶可治民。", "爾時荆文公，上方邑之鄞。", "聞此輒異之，久會公秉鈞。", "謂此非狂狷，引用至中丞。", "立朝思蹇諤，庶以報君親。", "蘇公下詔獄，讒者用事新。", "於此與有力，豈爲重其身。", "晴風吹海雨，山川尚橫陳。", "俛仰勿太息，徒爲驚爾鄰。"]'),
('227976ab-87e6-47f9-bf28-95bd58c7d2c2','鐵蛇嶺長耳僧','謝翱','宋','宋诗','song-poetry','','[]','嶺上有神僧，風吹豎兩耳。',72,'全唐诗/poet.song.246000.json','["嶺上有神僧，風吹豎兩耳。", "云昔垂至肩，手提忽然起。", "遊方得至術，來此制蛇虺。", "衣縫獨繭絲，裂縫蛇盡死。", "至今山下草，食之蠱可已。", "客去勿復言，海隅多幻詭。"]'),
('1460378e-992d-4617-b2f5-1a3c5e9f1982','觀水','謝翱','宋','宋诗','song-poetry','','[]','積陰生壑雨，野水學江流。',108,'全唐诗/poet.song.246000.json','["積陰生壑雨，野水學江流。", "對屋見燈火，相望南渡頭。", "浮槎到高樹，白黿起滄洲。", "變怪若不測，神功安能尤。", "稍退見涯涘，及來痕沫收。", "崩疇出白石，隠隠如博投。", "水楊洗荒根，素髪生古愁。", "見此倏若化，故流還膠舟。", "荒源不可詰，欲盡山雲求。"]'),
('2a2b226e-c9b4-4a6d-9ac2-b00ccc6ab917','聽雨','謝翱','宋','宋诗','song-poetry','','[]','山厨壓炊烟，野雨起薄莫。',84,'全唐诗/poet.song.246000.json','["山厨壓炊烟，野雨起薄莫。", "孤客卧空牀，不識門前路。", "回風已若休，入壑忽如赴。", "荒林啼鬼車，往往不見處。", "鄰翁起厭勝，呪作禹餘步。", "聽雨雜呪聲，起歌助其語。", "呪靜雨亦止，還眠向窗曙。"]'),
('c7f8d988-b524-4414-8c43-c93f4c8773f9','寄所知','謝翱','宋','宋诗','song-poetry','','[]','何處識君面，青天雲霧裾。',48,'全唐诗/poet.song.246000.json','["何處識君面，青天雲霧裾。", "携琴上衡霍，玄髪向風梳。", "別去看流水，三年此躇躊。", "偶同海鳥夢，爲致空中書。"]'),
('610674b0-3220-49b4-97c9-1b842c471e0d','池上萍','謝翱','宋','宋诗','song-poetry','','[]','浮萍隨漲水，上到荷葉端。',84,'全唐诗/poet.song.246000.json','["浮萍隨漲水，上到荷葉端。", "水退不得下，猶粘花萼間。", "花殷青已見，葉翠枯始斑。", "何如根在水，根蔕相團團。", "人生慕高遠，風雲事躋攀。", "絕髯尚號叫，化爲鶴與猿。", "幸未及枯槁，萬里吾當還。"]'),
('79c56d7f-c3b5-4297-9c34-5fdbd554d27e','十日菊','謝翱','宋','宋诗','song-poetry','','[]','今日非昨日，尚覺秋英好。',72,'全唐诗/poet.song.246000.json','["今日非昨日，尚覺秋英好。", "明日異今日，秋英詎云早。", "所以惜芳人，采擷常貴少。", "而彼千載士，憐爾獨皎皎。", "晞霜敷朝榮，零露抱夕槁。", "千載且復然，一夕寧恨老。"]'),
('c3106b81-f708-45c3-b6ac-47c841ded05e','佽飛廟迎神引','謝翱','宋','宋诗','song-poetry','','[]','劍歌兮擊筑，茭青兮蓼綠，夕濟甬兮沉玉。',79,'全唐诗/poet.song.246000.json','["劍歌兮擊筑，茭青兮蓼綠，夕濟甬兮沉玉。", "步巫兮禹孫，葺神藩兮楚軍，神之乘兮海雲。", "噀芳兮越咒，斬將兮神祐。", "秋零露兮爲醑，春集鴉兮神語。", "風蕭蕭兮滿旗，雲之車兮來思。"]'),
('d8753cae-4fdf-4ab4-b067-de70ad062995','鴻門斾','謝翱','宋','宋诗','song-poetry','','[]','天雲屬地汗流宇，杯影龍蛇分漢楚。',80,'全唐诗/poet.song.246000.json','["天雲屬地汗流宇，杯影龍蛇分漢楚。", "楚人起舞本爲楚，中有楚人爲漢舞。", "鸊鵜淬光雌不語，楚國孤臣泣俘虜。", "他年疽背怒發此，硭碭雲歸作風雨。", "君看楚舞如楚何，楚舞未終聞楚歌。"]'),
('f095a0d1-1077-4925-9d65-7c5eb6ebbe38','贈寫照唐子良','謝翱','宋','宋诗','song-poetry','','[]','吳中衆史今代畫，不獨畫人兼畫馬。',160,'全唐诗/poet.song.246000.json','["吳中衆史今代畫，不獨畫人兼畫馬。", "唐生家住金華雲，對予獨肯畫古人。", "夕陽西下東流水，紛紛古人呼不起。", "東都留守吳中豪，王府勳僚舊俊髦。", "當時氣薄陰山日，勾陳蒼蒼太白高。", "百年水竭海塵土，誰見凌烟拂蛛罔。", "霜髯磔磔開清新，彷彿猶带黄河冰。", "忽疑稍會怒色止，或可從傍窺諫紙。", "唐生見我淚如洗，頗憶古人今不死。", "俟我氣定神始閒，命筆更起唐衣冠。"]'),
('dd0b7f0d-6dd4-4265-bc8a-19bacea8ec33','種葵蒲萄下','謝翱','宋','宋诗','song-poetry','','[]','茙葵花種蒲萄下，年年葉長見花謝。',80,'全唐诗/poet.song.246000.json','["茙葵花種蒲萄下，年年葉長見花謝。", "蒲萄漸密花漸遲，開時及見蒲萄垂。", "微風摇曳架上枝，陰雲凝碧行琉璃。", "天人下飲蒲萄露，花神夜泣向天訴。", "謝爾蒲萄數尺陰，不如寸草同此心。"]'),
('25750d39-d437-4f0e-8b2d-d7becba07e91','送殘暑','謝翱','宋','宋诗','song-poetry','','[]','向已送殘春，當茲送殘暑。',72,'全唐诗/poet.song.246000.json','["向已送殘春，當茲送殘暑。", "離尊雖不同，時節會有去。", "平生苦汗塵，欲避無處所。", "驪駒出商音，畏不將風雨。", "却憶別花時，紅塵挽衣履。", "回首漢諸陵，落日無窮樹。"]'),
('4abab057-85fb-4f4f-88a9-83b2f70be557','有洗舊誥綾作青色鬻將以爲緣以紺繒易得之作手卷賦小樂章求好事書其後','謝翱','宋','宋诗','song-poetry','','[]','吳宮輦路傷行客，繭冰壓雲凝碧色。',128,'全唐诗/poet.song.246000.json','["吳宮輦路傷行客，繭冰壓雲凝碧色。", "門前新掃染家鄰，借人鋪設殘衣帛。", "宮花翦綾連院號，覆取翻看成一道。", "織紋宛轉勑字新，知是初誰六尺誥。", "城霞失彩宮蘚病，中與海圖上衣領。", "改顔倖售緣所遭，褪藥玄香洗藍影。", "青綢易得淚承睫，擊筑楚歌無故業。", "歌殘求書好事人，異代倘傳誥綾帖。"]'),
('01a003b3-63cf-4755-9251-470e452e0847','廣惜往日','謝翱','宋','宋诗','song-poetry','','[]','漢有臣兮龔勝卒，噤不食兮十四日。',80,'全唐诗/poet.song.246000.json','["漢有臣兮龔勝卒，噤不食兮十四日。", "今忍饑兮我復渴，道間關兮踰半月。", "幸求死兮得死，苟不得兮無術。", "鳳笙兮龍笛，燕群仙兮日將夕。", "風吹衣兮珮蕭瑟，駿龍兮寥天，行成兮緣畢。"]'),
('d5993dd0-11ab-453f-b327-e043095536d4','雪中方四隠君訪宿有詩憶鹿田風雨舊遊奉和併呈吳六贊府','謝翱','宋','宋诗','song-poetry','','[]','金華人北山，空響出靜竚。',216,'全唐诗/poet.song.246000.json','["金華人北山，空響出靜竚。", "鹿田在其顛，肺石來風雨。", "有客六七人，昔遊至其處。", "唯我愁不眠，起坐蹴君語。", "謂此定何聲，百感生離緒。", "玩非琴與瑟，復異砧將杵。", "醉者呼不應，愁者自爲苦。", "空欞怯孤衾，展轉如巢樹。", "濕歌散餘悲，以足拊柱礎。", "爾來又七年，欲至困羈旅。", "傳聞老桑門，已復蟬蛻去。", "入山惡少年，巾鉢空其聚。", "乃知人世間，何者爲客主。", "而我同懷人，忽復異處所。", "夢中遥相望，各抱不售賈。", "有客不同遊，亦是同懷者。", "地主况有期，輿馬不待假。", "倘規宿山中，畸人不應舍。"]'),
('56ff4b23-fe62-4a25-b149-cffdc256cd46','九日','謝翱','宋','宋诗','song-poetry','','[]','秋風颯以至，今日重陽日。',228,'全唐诗/poet.song.246000.json','["秋風颯以至，今日重陽日。", "眼明對南山，尚想陶彭澤。", "向來建威幕，頗見有此客。", "驅車不小留，駕言公田秫。", "一朝又棄去，此意誰能識。", "寄奴趣殊禮，風旨來自北。", "只今王江州，建國功第一。", "故是何珉孫，舉動良足惜。", "飲愧望柴桑，稍以自湔滌。", "殷勤白衣餉，猶恐不我即。", "中路候藍輿，要致已甚迫。", "葛巾赤兩脚，頹然向林宅。", "此翁本坦蕩，焉能苦違物。", "雖然可計取，中實未易屈。", "華軒又何羨，自載返蓬蓽。", "終身書甲子，往往義形色。", "如使磷與緇，安得爲玉雪。", "籬邊菊弄黄，粲粲正堪摘。", "我方持空觴，千載高風激。"]'),
('5775d954-fab7-4be5-9f4f-435f468b2e49','送袁太初歸剡原袁來杭宿傳法寺寺在德壽宮北今行路及園即宮舊址','謝翱','宋','宋诗','song-poetry','','[]','大雷山下鄞江口，石濕落星海涵斗。',211,'全唐诗/poet.song.246000.json','["大雷山下鄞江口，石濕落星海涵斗。", "莓苔瑣窗居鬼神，散髪天衣夜行酒。", "百年綺語墮凡塵，劉公不還謝公走。", "祇今零落三秋霜，猶說先朝人物藪。", "道逢袁家美年少，欲挽吳潮歸兩袖。", "自言學出戴君門，又說舒君忘年友。", "舒君白頭爪塵垢，戴君業成衣露肘。", "君來何處覓知音，吊古凄凉無老叟。", "出門擇語歸計餐，顧忌慚皇無不有。", "不如歸食空江槎，初生淡菜如珠母。", "風帆送客來夷洲，白帢青衫談不朽。", "君不見君今宿寺多鄞僧，耆舊能言幾人在。", "隔牆食柏秋麝過，廢石坡陁舊南內。"]'),
('6277e29c-d268-429d-b989-6ddf636438f7','雜言送鄭主簿炎之官昌化','謝翱','宋','宋诗','song-poetry','','[]','劉先生，名肩吾，閩中詞賦天下無。',318,'全唐诗/poet.song.246000.json','["劉先生，名肩吾，閩中詞賦天下無。", "當年戰藝誇顔色，進士出身兩回得。", "盧公里人正在朝，相見相逢九官宅。", "余時猶弱起慨忼，謂此未足榮其鄉。", "丈夫事業在簡冊，要令姓字留耿光。", "繼聞鄭君年最少，人物氣象尤堂堂。", "白鹿山南介公後，禽蛟兩祭獅子王。", "夢魂欲見無由據，側荔芭蕉春復暮。", "時移乃爾來霅間，因作廣文求主簿。", "顧予多病澀語言，面垢毛焦著麻布。", "山中乞食城中歸，徵詩送贈非所宜。", "已聞之戍嚮昌化，此地人傳多畏怕。", "龍居嗜燕烟入巢，病甲垂櫩腥雨下。", "又聞山鬼吹燈夜，來向人家避官舍。", "君持何術徑往居此無百憂，便將天雷斧柄塞鬼穴。", "巫山鐵鏁沈龍湫，祇足自亂不得休。", "豈知從心致禱動幽隠，使龍無嗜鬼無愁，不知君能致此不。", "龍不須酹以酒，鬼不須祭以肉。", "秋旗卷雨曉案烟，時向縣齋望天目。"]'),
('699d55ba-310d-4aae-a475-b0b45c0e2d75','避暑池上擬古','謝翱','宋','宋诗','song-poetry','','[]','遊子渺天末，晨光東南馳。',96,'全唐诗/poet.song.246000.json','["遊子渺天末，晨光東南馳。", "良時不易晤，胡爲徒來茲。", "叢柏結夏塔，輕蒲生夕颸。", "空有齊紈扇，團團手中持。", "持此欲永久，但感顔髪衰。", "愛爾雲中鳥，浴彼道上池。", "餘翎委弱藻，飛去猶淪漪。", "極目送不返，將以窮所思。"]'),
('8db2e310-3641-46b7-b855-38beef9b8b3c','擬古二首  其一','謝翱','宋','宋诗','song-poetry','','[]','翔鱗化海鳬，不化腦中石。',96,'全唐诗/poet.song.246000.json','["翔鱗化海鳬，不化腦中石。", "人生棄井邑，寄處終爲客。", "常懷墳墓思，永夜良跼蹐。", "秋風吹蓬顆，絫絫如布奕。", "上爲考與曾，下爲叔與伯。", "豈無故鬼悲，翻念遠行役。", "服藥得神仙，去後唯留迹。", "忽夢南遊雲，相逐孤飛翮。"]'),
('72ad1f11-0299-4927-8502-1b8cd20437aa','擬古二首  其二','謝翱','宋','宋诗','song-poetry','','[]','嶠南毒草花，離離北潭址。',60,'全唐诗/poet.song.246000.json','["嶠南毒草花，離離北潭址。", "洗花潭洞中，水黑魚盡起。", "豈無建溪芽，投之以方匕。", "南山有雨來，百毒化爲水。", "臨流招故人，洗髪弄清泚。"]'),
('77110407-45e3-4688-a9ab-790bf5f65c8b','九日前子善來會山中','謝翱','宋','宋诗','song-poetry','','[]','朝尋寒露枝，莫摘不盈把。',84,'全唐诗/poet.song.246000.json','["朝尋寒露枝，莫摘不盈把。", "風吹西南雲，幽情誰與寫。", "有客來縉州，遺我古盞斝。", "中有鴛鴦文，色如銅雀瓦。", "浮以鬰金蕤，蒼蘚藉其下。", "此物寧足感，聊用助歌者。", "但懷郢曲悲，豈計所知寡。"]'),
('63720374-3976-49fb-b790-de3ce6fe24d0','九日集葆山寺得載字','謝翱','宋','宋诗','song-poetry','','[]','貧居懶出門，未到輒復悔。',72,'全唐诗/poet.song.246000.json','["貧居懶出門，未到輒復悔。", "偶尋秋夕英，顧見石璀璀。", "手斸松根苓，下有墳千載。", "青山如葆羽，無人禁樵採。", "狂歌呼麯生，悲往興故在。", "未卜遇浮丘，猶堪居畏壘。"]'),
('fd27490d-a8e6-491c-a83f-fe4fbbf5449c','九日禺中登沃洲放鶴峰南望天台諸山','謝翱','宋','宋诗','song-poetry','','[]','鏡面小蓬島，入剡脫我驂。',120,'全唐诗/poet.song.246000.json','["鏡面小蓬島，入剡脫我驂。", "舍櫂來沃洲，下嶺見精藍。", "修眉浮天姥，天台在其南。", "良遊愛九日，巾墮髪不櫛。", "醉浮秋夕英，饑食决明實。", "遠尋竺僧迹，俛仰千載陳。", "狂呼許元度，王謝十八人。", "彷彿川谷應，草木皆冥冥。", "便欲即之語，又疑物所馮。", "閉目游泰初，寥廓以爲鄰。"]'),
('265dff31-21bd-4af5-bb7c-dd6f05a4e247','五日山中','謝翱','宋','宋诗','song-poetry','','[]','東鄰拔蒲根，南鄰燒艾葉。',96,'全唐诗/poet.song.246000.json','["東鄰拔蒲根，南鄰燒艾葉。", "艾葉出青烟，蒲根香勝雪。", "乾坤生燐火，陰碧期月光。", "烟隨艾葉散，進此菖蒲觴。", "蒲觴益齒髪，齒白髪如漆。", "餘飲不盡器，置之五七日。", "五日化爲丹，七日化爲碧。", "一服一千年，令人生羽翼。"]'),
('f2f380a4-ec23-4bbf-a884-5d83e60225b2','寄題山陰徐氏林亭三首 見南亭','謝翱','宋','宋诗','song-poetry','','[]','青林見危構，南山覆其陲。',96,'全唐诗/poet.song.246000.json','["青林見危構，南山覆其陲。", "林居何爲此，所愛烟霧姿。", "上有鷓鴣鳥，來從溟海湄。", "飛止不他鄉，畏與宿願違。", "違此頃刻間，萬死莫贖之。", "而憂中夜露，辛苦濕毛衣。", "毛衣豈願濕，即濕非所辭。", "莓苔與薏苡，含弄寄相思。"]'),
('6fb5e9a4-935f-41ad-a3d5-e92635446fa1','寄題山陰徐氏林亭三首 山陰茅宇','謝翱','宋','宋诗','song-poetry','','[]','山陰久淒凉，復爾見茅宇。',84,'全唐诗/poet.song.246000.json','["山陰久淒凉，復爾見茅宇。", "客來愛其人，問此於誰語。", "自云邇先塋，玩構亦廬處。", "朝光凌爽氣，初巖亙修渚。", "平居狷介心，祇以自爲苦。", "日夕驅其奴，名之同所惡。", "驅汝汝不辭，我懷良可悲。"]'),
('aab2b63e-9c1c-4047-b94c-b18fe44591d4','寄題山陰徐氏林亭三首 小華陽亭','謝翱','宋','宋诗','song-poetry','','[]','句越山中長木蓮，華陽仙女此餐烟。',32,'全唐诗/poet.song.246000.json','["句越山中長木蓮，華陽仙女此餐烟。", "松花飄落無尋處，都在徐君劍樹邊。"]'),
('fcb46b34-c0c2-41da-8d1f-894c0ba2a801','九日黎明發新昌望天姥峰','謝翱','宋','宋诗','song-poetry','','[]','南明剡東山，虧蔽草與萊。',108,'全唐诗/poet.song.246000.json','["南明剡東山，虧蔽草與萊。", "前岡接遠阜，樹石如苔莓。", "西南見天姥，旭旭雲日開。", "下有采藥徑，仙人招我來。", "手持白菊花，泛以青螺杯。", "傾杯化靈藥，蕤芳入客懷。", "俛視浮爨居，白氣爲塵埃。", "凉風吹脫巾，一往不願回。", "便投此策竹，騎龍下天台。"]'),
('be64abf1-d8e9-4895-8db2-1edae74b512e','五日觀瀟湘圖','謝翱','宋','宋诗','song-poetry','','[]','五日泣江蘺，騷人沉佩褋。',96,'全唐诗/poet.song.246000.json','["五日泣江蘺，騷人沉佩褋。", "年深吊古客，滿門垂艾葉。", "既垂青艾葉，復競畫舟檝。", "明時內閣子，供奉進瑶帖。", "豈復懷沅湘，歷舜愬往牒。", "江流物色改，看畫淚承睫。", "彷彿舊居人，指點失故業。", "三戶空鳥啼，九疑列如堞。"]'),
('1a902fc8-551c-47ca-b7f3-221bb1837770','玉麈尾','謝翱','宋','宋诗','song-poetry','','[]','客持麈尾柄，色奪環與玦。',96,'全唐诗/poet.song.246000.json','["客持麈尾柄，色奪環與玦。", "塵心隨影袪，一片若行雪。", "神獸潜空山，何年探靈穴。", "忽失落人手，遂爲談者悅。", "陰崖起白氣，篆古踰軒頡。", "一拂沉蘚文，再拂字不滅。", "三拂蛟螭騰，世眼不能別。", "投爾陰崖顛，驚怪吐其舌。"]'),
('2f827d60-d483-4133-a860-12e32d7aa88b','鐵如意','謝翱','宋','宋诗','song-poetry','','[]','仙客五六人，月下鬬婆娑。',96,'全唐诗/poet.song.246000.json','["仙客五六人，月下鬬婆娑。", "散影若雲霧，遺音杳江河。", "其一起楚舞，一起作楚歌。", "雙執鐵如意，擊碎珊瑚柯。", "一人奪執之，睨者一人過。", "更舞又一人，相向屢傞傞。", "一人獨撫掌，身挂青薜蘿。", "夜長天籟絕，宛轉愁奈何。"]'),
('ffefd20f-987f-4a6c-bbf6-414dec2d6395','謝子靜寄端午藥煎','謝翱','宋','宋诗','song-poetry','','[]','麩桃弄朝烟，含蟲鍊百杵。',72,'全唐诗/poet.song.246000.json','["麩桃弄朝烟，含蟲鍊百杵。", "山人入藥籙，搗日月逢午。", "甘酸雜衆味，能生玉池乳。", "頗憶越吟人，性靜無所苦。", "中年白髪生，寄以潤肺腑。", "爲謝山中人，願結山中侶。"]'),
('f8bd216a-6241-4a81-8698-986ecb68f23f','因北遊者寄峨眉家先生先生曾宰建之浦城故末章及之二首  其一','謝翱','宋','宋诗','song-poetry','','[]','靈關高縹緲，縹緲出曾城。',84,'全唐诗/poet.song.246000.json','["靈關高縹緲，縹緲出曾城。", "其上盤紫雲，倏忽牛馬形。", "交青不栖樹，浴彼清泠泓。", "唯有孤鸑鷟，銜命此山靈。", "迎風遡寥廓，杳杳西北征。", "羽毛中道折，六月霜霰零。", "回首靈關雲，淚下如懸纓。"]'),
('38820acf-673e-4b4e-99f2-787101a6b024','因北遊者寄峨眉家先生先生曾宰建之浦城故末章及之二首  其二','謝翱','宋','宋诗','song-poetry','','[]','江淹所治縣，粵王曾種樹。',60,'全唐诗/poet.song.246000.json','["江淹所治縣，粵王曾種樹。", "山人雨後來，空臺唯宿莽。", "故人出端平，子孫今不武。", "寥寥南峰寺，枯禪尚靈雨。", "猶記桐鄉祠，影前及僧語。"]'),
('55254d6e-8e95-4e06-a5ba-cc1fa8fe50b3','寄東白許元發','謝翱','宋','宋诗','song-poetry','','[]','昔我來南方，采藥與君遇。',96,'全唐诗/poet.song.246000.json','["昔我來南方，采藥與君遇。", "仙核墮寒蕪，水花明遠渚。", "雲空參語外，露下離立處。", "別來荒烟中，五閲寒與暑。", "寒暑豈異初，肌髪不如故。", "聞處人道變，未得世病愈。", "驅車望東白，此情那可遡。", "倘及乘青蜺，爲君拂塵羽。"]'),
('3136d76b-3676-4bf4-968d-d4bd348b8383','秋暑飲僧舍分韻得界字','謝翱','宋','宋诗','song-poetry','','[]','夜露摇井梧，明河涵左界。',96,'全唐诗/poet.song.246000.json','["夜露摇井梧，明河涵左界。", "酣眠知何益，筋力久已懈。", "餘氛薄中餐，幅巾無所挂。", "欲去豈不能，有興輒中敗。", "浮醅濟瓜茗，陰鼎漉薑芥。", "忽醉此山中，解衣如脫械。", "凉颸掃地生，塵暑焚香邁。", "空巢見落毛，石髪卷如蠆。"]'),
('617629ff-4fab-487b-83c5-67988f871daf','擬古寄何大卿六首  其一','謝翱','宋','宋诗','song-poetry','','[]','空山産桐梓，擬作膝上琴。',60,'全唐诗/poet.song.246000.json','["空山産桐梓，擬作膝上琴。", "琴成不他飾，種漆江之潯。", "獨無徽將軫，何以發商音。", "但得獨繭蠶，飼之扶桑陰。", "烹魚腹有膠，不患海水深。"]'),
('fe3f1fc7-ec35-43e6-8307-d4a610dd8abc','擬古寄何大卿六首  其二','謝翱','宋','宋诗','song-poetry','','[]','雄雌雙碧雞，所食琪樹蘤。',48,'全唐诗/poet.song.246000.json','["雄雌雙碧雞，所食琪樹蘤。", "來棲藥洞中，當春怕乳子。", "其雌秋別時，守此唯雄耳。", "可憐銜子歸，萬里渡海水。"]'),
('8f31afeb-c718-4026-a30d-fb9430cba18b','擬古寄何大卿六首  其三','謝翱','宋','宋诗','song-poetry','','[]','世傳賣藥翁，出市恒騎虎。',60,'全唐诗/poet.song.246000.json','["世傳賣藥翁，出市恒騎虎。", "朅來空山中，恨不輒與語。", "長嘯歸無家，獨指梧桐樹。", "既指梧桐樹，復采梧桐子。", "持以贈所思，浩歌聊復爾。"]'),
('f6f0ffaf-ec94-4520-9b9d-d3b220432b20','擬古寄何大卿六首  其四','謝翱','宋','宋诗','song-poetry','','[]','石間道人影，見者恒髣彿。',48,'全唐诗/poet.song.246000.json','["石間道人影，見者恒髣彿。", "浮雲過列仙，與語呼之出。", "身亦竟不出，影亦竟不沒。", "含涕謝仙人，天地此終畢。"]'),
('b1ad4b34-5c16-41be-9af6-84bd2b5aaa9e','擬古寄何大卿六首  其五','謝翱','宋','宋诗','song-poetry','','[]','流來山中花，紺碧三百里。',72,'全唐诗/poet.song.246000.json','["流來山中花，紺碧三百里。", "漪漪歙硯雲，含風入秋水。", "五芝與八石，往往産其沚。", "豈獨秘靈文，亦復隠奇士。", "不見施家郎，詩詞獨清泚。", "一朝控白鸞，吹笙洗塵滓。"]'),
('ac274cf6-0937-42cb-babd-70bd031527cb','擬古寄何大卿六首  其六','謝翱','宋','宋诗','song-poetry','','[]','山人食木實，竹實以飼鳳。',60,'全唐诗/poet.song.246000.json','["山人食木實，竹實以飼鳳。", "聞此來空烟，三載脫塵鞚。", "不見玉笙音，唯聞溪鳥弄。", "西臺憶故人，野祭忽如夢。", "仰視浮雲馳，不覺哭之慟。"]'),
('dfdc47c2-520f-4dbf-ba08-50beb286de55','巖居效賈島','謝翱','宋','宋诗','song-poetry','','[]','巖巖百尺屋，山鬼寂四壁。',96,'全唐诗/poet.song.246000.json','["巖巖百尺屋，山鬼寂四壁。", "獨抱震餘桐，橫此風中石。", "夢見一道者，手持青瓦礫。", "謂此有至音，世人不能識。", "粟塵起嵯峨，滄海寄一滴。", "語罷失其處，覺來空嘆息。", "攝衣起楚歌，斷弦如裂帛。", "懸藤月露深，蛟龍舞其側。"]'),
('8b28ae49-fbdc-418d-9073-3f80bda707f1','萍間穉荷效王司馬體','謝翱','宋','宋诗','song-poetry','','[]','初萍半含絮，頃刻開數畝。',72,'全唐诗/poet.song.246000.json','["初萍半含絮，頃刻開數畝。", "荷生浮其間，風雨足解后。", "百年游子心，欲作千歲久。", "昔爲浮萍根，今爲穉荷藕。", "荷高刺已生，魚遊觸其首。", "離離荷下萍，吹向白魚口。"]'),
('69cc3c9f-9ee3-4aa2-b8e7-36b29e098fbf','效孟郊體七首  其一','謝翱','宋','宋诗','song-poetry','','[]','手持菖蒲葉，洗根澗水湄。',48,'全唐诗/poet.song.246000.json','["手持菖蒲葉，洗根澗水湄。", "雲生巖下石，影落莓苔枝。", "忽起逐雲影，覆以身上衣。", "菖蒲不相待，逐水流下溪。"]'),
('d2ba2b7b-cd35-4b96-b5bc-8399263920e5','效孟郊體七首  其二','謝翱','宋','宋诗','song-poetry','','[]','移參窗北地，經歲日不至。',48,'全唐诗/poet.song.246000.json','["移參窗北地，經歲日不至。", "悠悠荒郊雲，背植足陰氣。", "新雨養陳根，乃復佐藥餌。", "天涯葵藿心，憐爾獨種參。"]'),
('0353221d-d7c2-4b04-8ccb-a7a942adeb6d','效孟郊體七首  其三','謝翱','宋','宋诗','song-poetry','','[]','閒庭生柏影，荇藻交行路。',48,'全唐诗/poet.song.246000.json','["閒庭生柏影，荇藻交行路。", "忽忽如有人，起視不見處。", "牽牛秋正中，海白夜疑曙。", "野風吹空巢，波濤在孤樹。"]'),
('61d3d39c-eb86-4164-ab22-af8932430fcd','效孟郊體七首  其四','謝翱','宋','宋诗','song-poetry','','[]','落葉昔日雨，地上僅可數。',84,'全唐诗/poet.song.246000.json','["落葉昔日雨，地上僅可數。", "今雨落葉處，可數還在樹。", "不愁繞樹飛，愁有空枝垂。", "天涯風雨心，雜佩光陸離。", "感此畢宇宙，涕零無所之。", "寒花飄夕暉，美人啼秋衣。", "不染根與髪，良藥空爾爲。"]'),
('b7ba60a5-94e2-442b-ba16-bc41b38100a5','效孟郊體七首  其五','謝翱','宋','宋诗','song-poetry','','[]','越禽惜羽毛，不向惡木棲。',48,'全唐诗/poet.song.246000.json','["越禽惜羽毛，不向惡木棲。", "木奴重踰淮，愛爾巢其枝。", "巢枝不食實，中有二老棋。", "乳子月明中，夢繞東南飛。"]'),
('4781c2b1-1dd3-4f6a-bbc4-88e59ba867f5','效孟郊體七首  其六','謝翱','宋','宋诗','song-poetry','','[]','弱柏不受雪，零亂蒼烟根。',72,'全唐诗/poet.song.246000.json','["弱柏不受雪，零亂蒼烟根。", "尚餘粲粲珠，點綴枝葉繁。", "小榻如僧床，下有莓苔痕。", "對此莓苔痕，三年不敢言。", "莓苔儻可食，嚥雪待朝暾。", "豈無柏樹子，不食種在盆。"]'),
('a0fa35a1-b5a6-41d5-8bef-8f988355c1dc','效孟郊體七首  其七','謝翱','宋','宋诗','song-poetry','','[]','閨中玻黎盆，貯水看落月。',60,'全唐诗/poet.song.246000.json','["閨中玻黎盆，貯水看落月。", "看月復看日，日月從此出。", "愛此日與月，傾寫入妾懷。", "疑此一掬水，中涵濟與淮。", "淚落水中影，見妾頭上釵。"]'),
('111c33bf-fb94-4538-b7b9-d5de8f9f0414','二月十日','謝翱','宋','宋诗','song-poetry','','[]','山居少四鄰，櫧葉半爲薪。',48,'全唐诗/poet.song.246000.json','["山居少四鄰，櫧葉半爲薪。", "野色生遥念，空江滯此身。", "風濤春憶越，親舊晚游秦。", "獨擬尋雞犬，雲蘿挂葛巾。"]'),
('e4c47e62-981f-4820-88b5-1cd9c3ff815c','九日韶卿子善有約不至子靜亦歸桐廬與景雲飲瀑下作','謝翱','宋','宋诗','song-poetry','','[]','揉藍染釣緡，欲老此江濱。',48,'全唐诗/poet.song.246000.json','["揉藍染釣緡，欲老此江濱。", "九日寒泉水，他年白髪身。", "鄰州曾約客，別業未歸人。", "嗅菊知吾事，那能更問津。"]'),
('d1350754-dfe2-4535-bda6-2ed2f7e94e0b','呈王尚書應麟','謝翱','宋','宋诗','song-poetry','','[]','寒風吹鬢影，客淚濕衣塵。',48,'全唐诗/poet.song.246000.json','["寒風吹鬢影，客淚濕衣塵。", "千里見積水，滿城無故人。", "船歌甌雪盡，劍舞越花薪。", "獨憶絲綸老，相從話所親。"]'),
('06ccc657-a371-4eeb-8c9f-978cbfc4ef19','山陰道中呈鄭正樸翁','謝翱','宋','宋诗','song-poetry','','[]','楊柳遠天色，野風來水涯。',48,'全唐诗/poet.song.246000.json','["楊柳遠天色，野風來水涯。", "異鄉同夢客，今雨故人家。", "越樹夜啼鳥，禹陵冬落花。", "悠悠江海意，爲爾鬢先華。"]'),
('d9505f90-97c8-4df1-ab6a-f4336e7b8322','送毛耳翁之湘南','謝翱','宋','宋诗','song-poetry','','[]','湘草碧於水，王孫尚此留。',48,'全唐诗/poet.song.246000.json','["湘草碧於水，王孫尚此留。", "一身行萬里，雙鬢集諸愁。", "月落嶽雲曙，龍逃海雨秋。", "可能無事業，相見竟悠悠。"]'),
('711c979b-4735-4763-8444-00083dbd7ed5','寒食姑蘇道中','謝翱','宋','宋诗','song-poetry','','[]','頻年感烟草，荒塚幾人耕。',48,'全唐诗/poet.song.246000.json','["頻年感烟草，荒塚幾人耕。", "吳楚逢寒食，山村見獨行。", "天陰月不死，江晚汐徐生。", "到海征帆影，悠悠識此情。"]'),
('21eb064f-86a5-439c-b6aa-5935b19c90c3','別子靜却送之霅','謝翱','宋','宋诗','song-poetry','','[]','獨往知吾事，語離何所求。',48,'全唐诗/poet.song.246000.json','["獨往知吾事，語離何所求。", "故家無別業，殘夢下扁舟。", "積葉吳宮冷，吟猿顧渚秋。", "那能不相待，羈旅負清遊。"]'),
('f6f94ee3-7582-4ec8-9ba6-7c0286c24613','哭肯齋李先生','謝翱','宋','宋诗','song-poetry','','[]','落日夢江海，呼天野水涯。',48,'全唐诗/poet.song.246000.json','["落日夢江海，呼天野水涯。", "百年唯此死，孤劍託全家。", "血染楚花碧，魂歸蜀日斜。", "能令感恩者，狼籍慰荒遐。"]'),
('c570446e-0168-4d6d-81af-740e6f28a882','八詠樓','謝翱','宋','宋诗','song-poetry','','[]','江山此愁絕，寒角夢中吹。',48,'全唐诗/poet.song.246000.json','["江山此愁絕，寒角夢中吹。", "飛鳥過帆影，遊塵空戟枝。", "水交明月動，槎洑故州移。", "已薄齊梁士，猶吟沈約詩。"]'),
('138dc9c9-e009-4790-a505-2a3d254434fb','至日憶山中客','謝翱','宋','宋诗','song-poetry','','[]','山村雲物外，至朔閏年愁。',48,'全唐诗/poet.song.246000.json','["山村雲物外，至朔閏年愁。", "獨客語茅屋，樵人共白頭。", "驛花殘楚水，烽火到交州。", "欲隠裂裳帛，春來重結裘。"]'),
('cb7fffe8-df89-4877-9948-29f05c3d26de','懷峨眉家先生','謝翱','宋','宋诗','song-poetry','','[]','露下濕百草，病思生積愁。',48,'全唐诗/poet.song.246000.json','["露下濕百草，病思生積愁。", "窟泉春洗屐，氈雪莫過樓。", "魂夢來巴峽，衣冠老代州。", "平生仗忠信，心自與身仇。"]'),
('90b3b0bd-8c5f-4566-9030-e7691918eff8','哭廣信謝公','謝翱','宋','宋诗','song-poetry','','[]','自爾逃名姓，終喪哭水濱。',48,'全唐诗/poet.song.246000.json','["自爾逃名姓，終喪哭水濱。", "海僧疑見貌，山鬼舊爲鄰。", "客死留衣物，囊空出告身。", "他年越鄉值，賣卜有斯人。"]'),
('dc129127-af00-482f-b146-7250e061c4de','雨夜呈韶卿','謝翱','宋','宋诗','song-poetry','','[]','相看隴水雲，一夕幾回分。',48,'全唐诗/poet.song.246000.json','["相看隴水雲，一夕幾回分。", "預恐今宵雨，他年獨自聞。", "野花同楚越，江靄雜朝曛。", "不得鋤芝朮，逢樵却寄君。"]'),
('2eb507ad-0dd3-4790-9c87-9a4c2b801e52','莫春感興','謝翱','宋','宋诗','song-poetry','','[]','天涯芳草夢，此意未應泯。',48,'全唐诗/poet.song.246000.json','["天涯芳草夢，此意未應泯。", "獨對風烟老，虛爲江海人。", "漁樵分落日，櫻笋過殘春。", "舉世無知己，他生應逐臣。"]'),
('7344e313-cf11-4f31-93a4-d6714800e358','秋日憶過秦國公主園','謝翱','宋','宋诗','song-poetry','','[]','野影林檉盡，山昏瓦塔齊。',48,'全唐诗/poet.song.246000.json','["野影林檉盡，山昏瓦塔齊。", "凉宵風雨過，一雁西南啼。", "嵐霧洗巾帨，井泉生蒺藜。", "傷心拂塵麈，衣淚濕空綈。"]'),
('66fdf670-c6b7-4210-8118-eb4d53018760','送道士歸赤松','謝翱','宋','宋诗','song-poetry','','[]','閒身可得仙，諸妄覺他年。',48,'全唐诗/poet.song.246000.json','["閒身可得仙，諸妄覺他年。", "夜氣浮秋井，陰花冷碧田。", "禮星逢鶴下，呪食待人眠。", "叩齒通懸解，祠堂山影邊。"]'),
('e4ed63e0-7182-4c8a-b2be-c55f7bf4cce7','送僧之天台','謝翱','宋','宋诗','song-poetry','','[]','石橋南北路，師到動經旬。',48,'全唐诗/poet.song.246000.json','["石橋南北路，師到動經旬。", "尊者定中影，凡人回去身。", "戴經支錫重，作禮納巾頻。", "杯海歸何日，長眉問四鄰。"]'),
('5d8a1d58-fbf3-4d0a-bf3c-24da2b1ef674','雪水','謝翱','宋','宋诗','song-poetry','','[]','寒英漲碧沉，浴鵠冷難禁。',48,'全唐诗/poet.song.246000.json','["寒英漲碧沉，浴鵠冷難禁。", "太白消秦日，中𤃩接蜀陰。", "頻湯清洗瘴，入茗味如參。", "人世淄澠口，應疑別未深。"]'),
('69a89c0b-f131-4953-ae22-8d150c06d786','用韻酬友人憶寄','謝翱','宋','宋诗','song-poetry','','[]','麻衣拂市塵，外事不干貧。',48,'全唐诗/poet.song.246000.json','["麻衣拂市塵，外事不干貧。", "野氣生寒井，天陰壓莫春。", "閑身分楚鞠，白髪作吳人。", "已斸蘼蕪徑，青鞋憶寄頻。"]'),
('9bb42961-f5f1-49f9-920e-6bcc3ec5471f','鼓子花','謝翱','宋','宋诗','song-poetry','','[]','塵濕西風淚，溝西影見君。',48,'全唐诗/poet.song.246000.json','["塵濕西風淚，溝西影見君。", "碧衣羞遠日，天夢冷秋雲。", "蔓引山精徑，籬依楚女墳。", "海邊逢賣藥，采實故應分。"]'),
('5414f61c-ce38-4382-9fab-4a109af018b4','山寺送翁景芳歸覲','謝翱','宋','宋诗','song-poetry','','[]','弱雲竹水湄，葉影碧離離。',48,'全唐诗/poet.song.246000.json','["弱雲竹水湄，葉影碧離離。", "野別如秋夢，他宵獨爾思。", "林殘西域果，鍾動下方棋。", "可得朝還莫，相看長在茲。"]');
